INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('colombia_armed_groups_peace','Armed groups and the peace process','Bewaffnete Gruppen und der Friedensprozess','Negotiations with guerrilla groups and drug cartels under the "total peace" policy, and the armed and narcotics economy they operate in.','Verhandlungen mit Guerillagruppen und Drogenkartellen im Rahmen der Politik des "totalen Friedens" sowie die bewaffnete Ökonomie und Drogenwirtschaft, in der sie agieren.',ARRAY['AMERICAS-ANDEAN'],true,NULL,'The "total peace" policy opened parallel negotiations with the ELN, FARC dissident factions and the Gulf Clan. A tribunal charged former FARC members with war crimes, and the largest cartel suspended talks after the understanding reached between the Colombian and US presidents. Coca cultivation and gold trafficking fund several of the groups involved.','Die Politik des "totalen Friedens" eröffnete parallele Verhandlungen mit der ELN, FARC-Dissidentengruppen und dem Clan del Golfo. Ein Tribunal klagte frühere FARC-Mitglieder wegen Kriegsverbrechen an, und das größte Kartell setzte die Gespräche aus, nachdem sich der kolumbianische und der US-Präsident verständigt hatten. Kokaanbau und Goldschmuggel finanzieren mehrere der beteiligten Gruppen.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('colombia_political_transition','Presidential transition and institutional contest','Präsidentschaftswechsel und institutioneller Streit','The Colombian presidential succession, the contested result and the institutional disputes around it.','Die kolumbianische Präsidentschaftsnachfolge, das umstrittene Ergebnis und die damit verbundenen institutionellen Auseinandersetzungen.',ARRAY['AMERICAS-ANDEAN'],true,NULL,'The presidential race concluded in a narrow runoff win for Abelardo de la Espriella over Iván Cepeda. The US president publicly endorsed the winner before the vote, and the outgoing president alleged foreign interference in the result. The losing camp pursued a legal challenge. Coverage divides between readings of the outcome as a security mandate and as a risk to institutional norms.','Das Präsidentschaftsrennen endete mit einem knappen Stichwahlsieg von Abelardo de la Espriella über Iván Cepeda. Der US-Präsident hatte den Sieger vor der Wahl öffentlich unterstützt, und der scheidende Präsident behauptete ausländische Einflussnahme auf das Ergebnis. Das unterlegene Lager ging juristisch dagegen vor. Die Berichterstattung teilt sich in Deutungen des Ausgangs als Sicherheitsmandat und als Risiko für institutionelle Normen.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('colombia_theater','Colombia','Kolumbien','Colombia''s external alignment, its contested presidential transition, and the negotiations with armed groups and drug cartels.','Kolumbiens außenpolitische Ausrichtung, der umstrittene Präsidentschaftswechsel und die Verhandlungen mit bewaffneten Gruppen und Drogenkartellen.',ARRAY['AMERICAS-ANDEAN'],true,NULL,'Relations with Washington moved from a threatened military operation and a formal Colombian complaint to a White House meeting within weeks, and the resulting understanding disrupted the government''s negotiations with armed groups. A presidential election then produced a winner endorsed by the US president, while the outgoing president alleged foreign interference in the vote. Colombia has no centroid of its own and is covered under AMERICAS-ANDEAN.','Die Beziehungen zu Washington entwickelten sich binnen Wochen von einer angedrohten Militäroperation und einer förmlichen kolumbianischen Beschwerde hin zu einem Treffen im Weißen Haus; die daraus folgende Verständigung störte die Verhandlungen der Regierung mit bewaffneten Gruppen. Eine Präsidentschaftswahl brachte anschließend einen vom US-Präsidenten unterstützten Sieger hervor, während der scheidende Präsident ausländische Einflussnahme auf die Wahl behauptete. Kolumbien hat keinen eigenen Zentroid und wird unter AMERICAS-ANDEAN geführt.','theater',ARRAY['colombia_us_alignment','colombia_political_transition','colombia_armed_groups_peace'],'{}','regional','{"type": "Point", "coordinates": [-74.1, 4.7]}'::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('colombia_us_alignment','Alignment with Washington','Ausrichtung gegenüber Washington','Colombia''s relations with the United States, spanning coercive measures, tariffs, sanctions designations and negotiated rapprochement.','Kolumbiens Beziehungen zu den Vereinigten Staaten, von Zwangsmaßnahmen, Zöllen und Sanktionslistungen bis zur ausgehandelten Annäherung.',ARRAY['AMERICAS-ANDEAN'],true,NULL,'In January the US president threatened a military operation against Colombia following a raid in Venezuela; Bogotá lodged a formal complaint. Within weeks the two presidents met at the White House. The episode combined tariff threats, visa measures and sanctions designations with a rapid diplomatic reversal, and the resulting understanding carried directly into Colombia''s talks with armed groups.','Im Januar drohte der US-Präsident nach einem Einsatz in Venezuela mit einer Militäroperation gegen Kolumbien; Bogotá legte förmlich Beschwerde ein. Wenige Wochen später trafen sich beide Präsidenten im Weißen Haus. Die Episode verband Zolldrohungen, Visamaßnahmen und Sanktionslistungen mit einer raschen diplomatischen Kehrtwende; die daraus folgende Verständigung wirkte unmittelbar auf Kolumbiens Gespräche mit bewaffneten Gruppen.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('cuba_embargo_sanctions','US sanctions and blockade instruments','US-Sanktions- und Blockadeinstrumente','US economic and legal instruments applied to Cuba: the embargo and its executive orders, sanctions designations of Cuban state and military-run enterprises, secondary sanctions reaching foreign shippers and hotel operators, expropriation and compensation claims, and criminal charges against Cuban officials.','Wirtschaftliche und juristische Instrumente der USA gegenüber Kuba: das Embargo und seine Dekrete, Sanktionslistungen kubanischer Staats- und Militärunternehmen, Sekundärsanktionen gegen ausländische Reedereien und Hotelbetreiber, Enteignungs- und Entschädigungsklagen sowie Strafverfahren gegen kubanische Amtsträger.',ARRAY['AMERICAS-CUBA'],true,102,'The instrument set widened during this window from the long-standing embargo to an executive order targeting fuel supply, designations of the military conglomerate GAESA and the Moa nickel operation, withdrawal by foreign shipping and hotel groups under threat of secondary sanctions, a Supreme Court opening for expropriation claims, and an indictment of a former Cuban president.','Das Instrumentarium weitete sich in diesem Zeitraum vom langjährigen Embargo aus: ein Dekret gegen die Treibstoffversorgung, Listungen des Militärkonglomerats GAESA und des Nickelbetriebs Moa, Rückzug ausländischer Reederei- und Hotelgruppen unter Androhung von Sekundärsanktionen, eine Öffnung des Supreme Court für Enteignungsklagen und eine Anklage gegen einen früheren kubanischen Präsidenten.','atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-CUBA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('cuba_energy_collapse','Energy and humanitarian collapse','Energie- und humanitärer Zusammenbruch','The failure of Cuba''s electricity supply and the shortages that follow from it: national and regional blackouts, exhaustion of fuel reserves, rationing, and the effects on hospitals, food, water, sanitation and transport.','Der Zusammenbruch der kubanischen Stromversorgung und die daraus folgenden Engpässe: landesweite und regionale Stromausfälle, erschöpfte Treibstoffreserven, Rationierung sowie die Auswirkungen auf Kliniken, Nahrung, Wasser, Abfallentsorgung und Verkehr.',ARRAY['AMERICAS-CUBA'],true,105,'Cuba''s grid failed repeatedly during this window, at times island-wide, after the government reported its fuel reserves exhausted. Reporting covers rationing plans, closed hotels and suspended flights, uncollected refuse in Havana, hospital supply failures, and United Nations warnings of humanitarian collapse. Whether the cause is the US fuel blockade or long-term under-investment is itself contested.','Kubas Stromnetz fiel in diesem Zeitraum wiederholt aus, zeitweise landesweit, nachdem die Regierung ihre Treibstoffreserven für erschöpft erklärt hatte. Berichtet wird über Rationierungspläne, geschlossene Hotels und gestrichene Flüge, nicht abgeholten Müll in Havanna, Versorgungsausfälle in Kliniken und Warnungen der Vereinten Nationen vor einem humanitären Zusammenbruch. Ob die Ursache die US-Treibstoffblockade oder jahrzehntelange Unterinvestition ist, ist selbst umstritten.','atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-CUBA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('cuba_external_lifelines','External lifelines and patron competition','Äußere Rettungsleinen und Patronenkonkurrenz','External supply to Cuba and the competition around it: oil and fuel cargoes, food and medical shipments, credit and aid from Russia, China, Venezuela, Mexico, Canada and European states, and US pressure on third countries to withhold them.','Versorgung Kubas von außen und der Wettbewerb darum: Öl- und Treibstoffladungen, Nahrungsmittel- und Medizinlieferungen, Kredite und Hilfe aus Russland, China, Venezuela, Mexiko, Kanada und europäischen Staaten sowie US-Druck auf Drittstaaten, sie zurückzuhalten.',ARRAY['AMERICAS-CUBA'],true,106,'Russian tankers, a Chinese rice shipment, Mexican humanitarian cargoes and a suspended Pemex crude contract all feature in this window, alongside US measures aimed at the third parties supplying them. Shipping movements, diversions and arrivals were reported closely enough to function as a running indicator of the island''s position.','Russische Tanker, eine chinesische Reislieferung, mexikanische Hilfsfrachten und ein ausgesetzter Pemex-Rohölvertrag prägen diesen Zeitraum, daneben US-Maßnahmen gegen die liefernden Drittparteien. Schiffsbewegungen, Kursänderungen und Ankünfte wurden so genau verfolgt, dass sie als laufender Indikator für die Lage der Insel dienten.','atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-CUBA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('cuba_migration_exodus','Migration and refugee pressures',NULL,NULL,NULL,ARRAY['AMERICAS-CUBA','AMERICAS-USA'],false,103,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('cuba_military_coercion','Military coercion and regime-change threat','Militärische Nötigung und Drohung eines Regimewechsels','The military dimension of US pressure on Cuba: naval and air deployments in the Caribbean, reconnaissance activity, the Guantánamo Bay base and contacts across it, US debate over authorisation for the use of force, and armed incidents around the island.','Die militärische Dimension des US-Drucks auf Kuba: Marine- und Luftverlegungen in der Karibik, Aufklärungstätigkeit, der Stützpunkt Guantánamo Bay und die Kontakte über ihn hinweg, die US-Debatte über eine Ermächtigung zum Einsatz von Gewalt sowie bewaffnete Zwischenfälle rund um die Insel.',ARRAY['AMERICAS-CUBA'],true,107,'This window covers a carrier deployment to the Caribbean, increased surveillance flights off the Cuban coast, a rare meeting between the US Southern Command chief and Cuban officers at the edge of Guantánamo Bay, a Defense Secretary visit to the base, Senate votes on war powers, and a fatal exchange involving an armed group on a US-registered speedboat.','Dieser Zeitraum umfasst die Verlegung eines Flugzeugträgers in die Karibik, verstärkte Aufklärungsflüge vor der kubanischen Küste, ein seltenes Treffen des Chefs des US-Südkommandos mit kubanischen Offizieren am Rand von Guantánamo Bay, einen Besuch des Verteidigungsministers auf dem Stützpunkt, Senatsabstimmungen über Kriegsvollmachten sowie einen tödlichen Zwischenfall mit einer bewaffneten Gruppe auf einem in den USA registrierten Schnellboot.','atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-CUBA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('cuba_regime_survival','Regime legitimacy and internal control','Legitimität des Regimes und innere Kontrolle','The Cuban government''s internal position: the Communist Party and state leadership, succession, treatment of dissent and political prisoners, protest and policing, and the scope and pace of economic reform.','Die innere Lage der kubanischen Regierung: die Kommunistische Partei und die Staatsführung, die Nachfolge, der Umgang mit Dissens und politischen Gefangenen, Proteste und Polizeieinsätze sowie Umfang und Tempo der Wirtschaftsreformen.',ARRAY['AMERICAS-CUBA'],true,104,'During this window the government announced its largest economic reform package since 1959, released more than two thousand prisoners, and faced rare street protests over blackouts that ended in arrests. Reporting also covers speculation about who follows the current leadership and the position of the private sector.','In diesem Zeitraum kündigte die Regierung ihr größtes Wirtschaftsreformpaket seit 1959 an, entließ mehr als zweitausend Gefangene und sah sich seltenen Straßenprotesten gegen Stromausfälle gegenüber, die mit Verhaftungen endeten. Berichtet wird auch über Spekulationen zur Nachfolge der Führung und über die Lage des Privatsektors.','atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-CUBA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('cuba_theater','Cuba under maximum pressure','Kuba unter Maximaldruck','The confrontation between the United States and Cuba, comprising the US sanctions and blockade instruments applied to the island, the energy and humanitarian crisis on it, the outside states supplying it, the threat of US military action, and the Cuban government''s internal position.','Die Konfrontation zwischen den Vereinigten Staaten und Kuba: die US-Sanktions- und Blockadeinstrumente gegen die Insel, die dortige Energie- und humanitäre Krise, die Staaten, die sie beliefern, die Drohung mit US-Militäraktionen und die innere Lage der kubanischen Regierung.',ARRAY['AMERICAS-CUBA','AMERICAS-USA'],true,NULL,'Coverage in this window is dominated by a US campaign to cut off Cuba''s fuel imports, the island-wide power failures and shortages that followed, and the resulting contest over supply between Washington and Havana''s outside partners. Alongside it run an escalating US military signal in the Caribbean and a legal campaign against the Cuban leadership.','Die Berichterstattung in diesem Zeitraum wird von einer US-Kampagne zur Unterbindung kubanischer Treibstoffimporte bestimmt, von den darauf folgenden landesweiten Stromausfällen und Engpässen sowie vom Ringen um Nachschub zwischen Washington und Havannas äußeren Partnern. Daneben laufen ein eskalierendes US-Militärsignal in der Karibik und ein juristisches Vorgehen gegen die kubanische Führung.','theater',ARRAY['cuba_embargo_sanctions','cuba_energy_collapse','cuba_external_lifelines','cuba_military_coercion','cuba_regime_survival'],'{}','regional','{"type": "Point", "coordinates": [-82.4, 23.1]}'::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('drc_intervention_forces','MONUSCO, AU and regional military deployments',NULL,NULL,NULL,ARRAY['AFRICA-DRC','AFRICA-RWANDA','AFRICA-UGANDA','AFRICA-BURUNDI'],false,85,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('drc_minerals_competition','Cobalt and coltan extraction and supply competition','Kobalt- und Coltanabbau und Wettbewerb um Lieferketten','The Democratic Republic of the Congo holds the world''s largest cobalt reserves and a significant share of its coltan, tantalum and copper. Chinese companies built much of the existing refining and processing base; American-backed buyers have more recently acquired producers and sought stakes tied to a minerals arrangement with Kinshasa. Some of the deposits concerned lie in territory held by armed groups, and the state has used export controls to influence prices.','Die Demokratische Republik Kongo verfügt über die weltweit größten Kobaltreserven sowie über bedeutende Anteile an Coltan, Tantal und Kupfer. Chinesische Unternehmen bauten einen Großteil der bestehenden Raffinerie- und Verarbeitungsbasis auf; zuletzt erwarben US-gestützte Käufer Produzenten und strebten Beteiligungen im Rahmen einer Rohstoffvereinbarung mit Kinshasa an. Ein Teil der betroffenen Vorkommen liegt in Gebieten bewaffneter Gruppen, und der Staat nutzte Exportkontrollen, um Preise zu beeinflussen.',ARRAY['AFRICA-DRC'],true,84,'Two strands run together and are not separable in coverage: the contest between American and Chinese buyers for Congolese assets, and the human and environmental record of the extraction itself.','Zwei Stränge laufen zusammen und sind in der Berichterstattung nicht zu trennen: der Wettbewerb amerikanischer und chinesischer Käufer um kongolesische Werte und die menschliche und ökologische Bilanz der Förderung selbst.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('drc_peace_process','Mediation and sanctions over eastern Congo','Vermittlung und Sanktionen im Ostkongo-Konflikt','Efforts to end the fighting in eastern Congo run through several external tracks at once: agreements associated with Washington, talks in Doha and Switzerland, a signed ceasefire-monitoring mechanism, and the United Nations mission that is being reconfigured to support it. Alongside them runs an enforcement track of financial designations and travel restrictions aimed at Rwandan military figures and at Congolese political figures accused of supporting the rebellion.','Die Bemühungen, die Kämpfe im Osten Kongos zu beenden, laufen über mehrere externe Stränge zugleich: mit Washington verbundene Vereinbarungen, Gespräche in Doha und in der Schweiz, ein unterzeichneter Mechanismus zur Waffenstillstandsüberwachung und die Mission der Vereinten Nationen, die darauf ausgerichtet wird. Daneben verläuft ein Durchsetzungsstrang aus Finanzlistungen und Reisebeschränkungen gegen ruandische Militärs und gegen kongolesische Politiker, denen Unterstützung des Aufstands vorgeworfen wird.',ARRAY['AFRICA-DRC'],true,83,'The largest single cluster here is the designation of the Rwandan army and of former president Joseph Kabila; the accords themselves generate far less coverage than the sanctions used to enforce them.','Das größte einzelne Cluster ist die Listung der ruandischen Armee und des früheren Präsidenten Joseph Kabila; die Abkommen selbst erzeugen deutlich weniger Berichterstattung als die Sanktionen zu ihrer Durchsetzung.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('eastern_congo_armed_groups','Armed group proliferation and territorial control',NULL,NULL,NULL,ARRAY['AFRICA-DRC','AFRICA-RWANDA','AFRICA-UGANDA','AFRICA-BURUNDI'],false,82,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,NULL)
