INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('ethiopia_amhara_conflict','Amhara insurgency and border tensions',NULL,NULL,NULL,ARRAY['AFRICA-ETHIOPIA','AFRICA-ERITREA','NON-STATE-OROMIA-LIBERATION-FRONT'],false,75,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('ethiopia_regional_confrontation','Ethiopia''s confrontation with its neighbours','Äthiopiens Konfrontation mit seinen Nachbarn','Ethiopia faces simultaneous disputes on several fronts: the unravelling of the Pretoria settlement that ended the Tigray war, accusations of Eritrean troop movements across the northern border, a long-running disagreement with Egypt over control of the Nile dam, and Addis Ababa''s stated pursuit of sovereign access to the sea.','Äthiopien steht gleichzeitig an mehreren Fronten in Konflikten: dem Zerfall des Abkommens von Pretoria, das den Tigray-Krieg beendete, Vorwürfen eritreischer Truppenbewegungen über die Nordgrenze, einer langjährigen Auseinandersetzung mit Ägypten über die Kontrolle des Nilstaudamms und dem erklärten Streben Addis Abebas nach einem souveränen Zugang zum Meer.',ARRAY['AFRICA-HORN','MIDEAST-EGYPT'],true,75,'Tigray and Eritrea are one fused story in the 2026 record, not two; the Egyptian dimension has shifted from water alone to regional alignment.','Tigray und Eritrea sind im Material von 2026 eine zusammenhängende Geschichte, nicht zwei; die ägyptische Dimension hat sich vom reinen Wasserstreit zur regionalen Bündnispolitik verlagert.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('ethiopia_somaliland_access','Ethiopian sea access and Red Sea port competition',NULL,NULL,NULL,ARRAY['AFRICA-ETHIOPIA','AFRICA-SOMALIA','MIDEAST-EGYPT','AFRICA-DJIBOUTI','AFRICA-ERITREA'],false,77,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('great_lakes_theater','Eastern Congo conflict and mineral competition','Konflikt in Ostkongo und Konkurrenz um Rohstoffe','The eastern provinces of the Democratic Republic of the Congo have been contested for three decades by armed groups, the Congolese state and neighbouring governments. The current phase combines the M23 insurgency and its disputed external backing, an externally brokered mediation and sanctions track, and competition over the cobalt, coltan and copper deposits that sit in and around the same territory. The United States, China, Rwanda, Uganda, Burundi and the United Nations mission are all engaged.','Die östlichen Provinzen der Demokratischen Republik Kongo sind seit drei Jahrzehnten zwischen bewaffneten Gruppen, dem kongolesischen Staat und den Nachbarregierungen umkämpft. Die gegenwärtige Phase verbindet den M23-Aufstand und dessen umstrittene Unterstützung von außen, einen extern vermittelten Verhandlungs- und Sanktionsstrang sowie den Wettbewerb um die Kobalt-, Coltan- und Kupfervorkommen, die in und um dasselbe Gebiet liegen. Die Vereinigten Staaten, China, Ruanda, Uganda, Burundi und die Mission der Vereinten Nationen sind daran beteiligt.',ARRAY['AFRICA-DRC','AMERICAS-USA'],true,23,'Coverage in the first half of 2026 divides sharply: the M23 war de-escalated through the period while the mediation and sanctions track kept producing, and an Ebola outbreak came to dominate Congolese coverage overall without being part of this dispute.','Die Berichterstattung im ersten Halbjahr 2026 teilt sich deutlich: Der M23-Krieg deeskalierte im Verlauf, während der Vermittlungs- und Sanktionsstrang weiter Nachrichten produzierte; zugleich beherrschte ein Ebola-Ausbruch die Kongo-Berichterstattung insgesamt, ohne Teil dieses Konflikts zu sein.','theater',ARRAY['m23_conflict','drc_peace_process','drc_minerals_competition'],ARRAY['katanga_copper_belt','bisie_tin_mine'],'regional','{"type": "Point", "coordinates": [29.2, -1.68]}'::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('horn_africa_theater','Horn of Africa realignment','Neuordnung am Horn von Afrika','The Horn of Africa is being reordered by overlapping disputes: the contested international status of Somaliland, an unresolved confrontation between Ethiopia and its northern and downstream neighbours, and the uneven reconstruction of the Somali state. Outside powers -- Israel, Turkey, Egypt, the Gulf states, the United States and China -- are all party to at least one of them.','Das Horn von Afrika wird durch mehrere ineinandergreifende Konflikte neu geordnet: den umstrittenen völkerrechtlichen Status Somalilands, eine ungelöste Konfrontation zwischen Äthiopien und seinen nördlichen wie flussabwärts gelegenen Nachbarn und den ungleichmäßigen Wiederaufbau des somalischen Staates. Auswärtige Mächte -- Israel, die Türkei, Ägypten, die Golfstaaten, die USA und China -- sind an mindestens einem davon beteiligt.',ARRAY['AFRICA-HORN','MIDEAST-ISRAEL','MIDEAST-EGYPT','MIDEAST-TURKEY','AMERICAS-USA'],true,21,'Coverage in 2026 is dominated by the recognition of Somaliland and the reaction to it, with a renewed war risk in northern Ethiopia and a fragile Somali state as the two other persistent strands.','Die Berichterstattung des Jahres 2026 wird von der Anerkennung Somalilands und den Reaktionen darauf bestimmt; das erneute Kriegsrisiko im Norden Äthiopiens und ein fragiler somalischer Staat sind die beiden weiteren durchgehenden Stränge.','theater',ARRAY['somaliland_recognition_contest','ethiopia_regional_confrontation','somalia_state_security'],ARRAY['bab_el_mandeb','gerd_dam'],'regional','{"type": "Point", "coordinates": [45.3, 2.05]}'::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('latam_eu_market_access','EU-Mercosur market access','EU-Mercosur-Marktzugang','Ratification and implementation of the trade agreement between the European Union and Mercosur, including quota allocation, import standards and related EFTA talks.','Ratifizierung und Umsetzung des Handelsabkommens zwischen der Europäischen Union und dem Mercosur, einschließlich Quotenverteilung, Einfuhrstandards und damit verbundener EFTA-Gespräche.',ARRAY['AMERICAS-BRAZIL','AMERICAS-SOUTHERNCONE','AMERICAS-ANDEAN'],true,3,'The agreement concluded between the two blocs requires ratification across European institutions and member states. France, Poland and Switzerland have registered formal opposition, Poland has filed a challenge at the EU Court of Justice, and the European Union has restricted certain Brazilian meat imports. Uruguay and Argentina have ratified. The EU deforestation regulation applies to several covered commodities.','Das zwischen den beiden Blöcken geschlossene Abkommen bedarf der Ratifizierung durch die europäischen Institutionen und Mitgliedstaaten. Frankreich, Polen und die Schweiz haben förmlichen Widerstand angemeldet, Polen hat Klage beim Gerichtshof der EU eingereicht, und die Europäische Union hat bestimmte brasilianische Fleischeinfuhren beschränkt. Uruguay und Argentinien haben ratifiziert. Die EU-Entwaldungsverordnung gilt für mehrere erfasste Rohstoffe.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('latam_hemispheric_theater','External powers in Latin America','Externe Mächte in Lateinamerika','Competition among external powers -- the United States, China and the European Union -- for trade terms, resource access, infrastructure contracts and control of strategic ports across Latin America.','Wettbewerb externer Mächte -- der Vereinigten Staaten, Chinas und der Europäischen Union -- um Handelsbedingungen, Rohstoffzugang, Infrastrukturaufträge und die Kontrolle strategischer Häfen in ganz Lateinamerika.',ARRAY['AMERICAS-BRAZIL','AMERICAS-SOUTHERNCONE','AMERICAS-ANDEAN','AMERICAS-CENTRAL','AMERICAS-USA','ASIA-CHINA','ASIA-HONGKONG','NON-STATE-EU'],true,NULL,'Brazil, the Southern Cone and the Andean states are courted and pressured by three external blocs at once. The European Union negotiates market access through the Mercosur agreement, the United States applies tariffs and sanctions, and China finances ports, rail and mineral supply. Scope is South America; Mexico, Central America and the Caribbean are covered by their own theaters.','Brasilien, der Südkegel und die Andenstaaten werden zugleich von drei externen Blöcken umworben und unter Druck gesetzt. Die Europäische Union verhandelt über das Mercosur-Abkommen den Marktzugang, die Vereinigten Staaten setzen Zölle und Sanktionen ein, und China finanziert Häfen, Bahnstrecken und Mineralienlieferungen. Der Zuschnitt umfasst Südamerika; Mexiko, Mittelamerika und die Karibik werden von eigenen Schauplätzen abgedeckt.','theater',ARRAY['latam_resource_access','latam_us_trade_pressure','latam_eu_market_access','latam_port_infrastructure_control'],ARRAY['atacama_lithium_triangle','salar_de_uyuni_lithium','chilean_copper_belt','southern_peru_copper_belt','panama_canal','colon_port'],'regional','{"type": "Point", "coordinates": [-47.9, -15.8]}'::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('latam_lithium_minerals','Lithium and strategic minerals competition',NULL,NULL,NULL,ARRAY['ASIA-CHINA','AMERICAS-USA','AMERICAS-SOUTHERNCONE','AMERICAS-ANDEAN'],false,107,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('latam_port_infrastructure_control','Control of strategic port infrastructure','Kontrolle strategischer Hafeninfrastruktur','Contests over who operates strategically sensitive port and canal infrastructure in the Americas -- concession cancellations, court-ordered operator changes, and the commercial and maritime retaliation that follows.','Auseinandersetzungen darüber, wer strategisch sensible Hafen- und Kanalinfrastruktur in Amerika betreibt -- Annullierung von Konzessionen, gerichtlich angeordnete Betreiberwechsel und die darauf folgenden kommerziellen und maritimen Vergeltungsmaßnahmen.',ARRAY['AMERICAS-CENTRAL','AMERICAS-ANDEAN','AMERICAS-USA','ASIA-CHINA','ASIA-HONGKONG'],true,106,'Panama''s Supreme Court voided CK Hutchison''s concession over two Panama Canal terminals in January 2026 and handed operations to Maersk and MSC; Peru''s courts upheld state control of the Chinese-built Chancay port five months later. Beijing treated both as expropriation of its companies, warned Panama of "heavy prices", suspended Cosco''s port operations, pressed the European carriers to withdraw, and detained Panama-flagged vessels under port-state-control inspections -- drawing a joint US-and-allies statement backing Panama''s sovereignty. The contest is over operators and legal title, not the waterways themselves, and it is the sharpest test yet of how far a host state can unwind Chinese infrastructure positions without absorbing retaliation.','Panamas Oberster Gerichtshof erklärte im Januar 2026 die Konzession von CK Hutchison für zwei Terminals am Panamakanal für nichtig und übertrug den Betrieb an Maersk und MSC; fünf Monate später bestätigten perus Gerichte die staatliche Kontrolle über den von China gebauten Hafen Chancay. Peking wertete beides als Enteignung seiner Unternehmen, drohte Panama mit "hohen Preisen", setzte den Hafenbetrieb von Cosco aus, drängte die europäischen Reedereien zum Rückzug und hielt Schiffe unter Panama-Flagge im Rahmen von Hafenstaatkontrollen fest -- woraufhin die USA und Verbündete in einer gemeinsamen Erklärung Panamas Souveränität bekräftigten. Der Streit dreht sich um Betreiber und Rechtstitel, nicht um die Wasserstraßen selbst, und ist der bislang schärfste Test dafür, wie weit ein Gastland chinesische Infrastrukturpositionen zurückdrehen kann, ohne Vergeltung zu tragen.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('latam_resource_access','Critical minerals and infrastructure access','Zugang zu kritischen Rohstoffen und Infrastruktur','External competition for South American critical minerals, mining concessions and transport infrastructure, including lithium, copper and rare earths.','Externer Wettbewerb um südamerikanische kritische Rohstoffe, Bergbaukonzessionen und Verkehrsinfrastruktur, darunter Lithium, Kupfer und Seltene Erden.',ARRAY['AMERICAS-BRAZIL','AMERICAS-SOUTHERNCONE','AMERICAS-ANDEAN'],true,105,'The United States, China, the European Union and India all pursue supply agreements and mining stakes across Brazil, Chile, Argentina, Peru and Bolivia. Chinese operators additionally finance and build physical infrastructure, including the Chancay deep-water terminal in Peru and river and rail projects in the Southern Cone.','Die Vereinigten Staaten, China, die Europäische Union und Indien verfolgen alle Lieferabkommen und Bergbaubeteiligungen in Brasilien, Chile, Argentinien, Peru und Bolivien. Chinesische Akteure finanzieren und bauen zusätzlich physische Infrastruktur, darunter das Tiefwasserterminal Chancay in Peru sowie Fluss- und Bahnprojekte im Südkegel.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('latam_theater','Latin America instability',NULL,NULL,NULL,ARRAY['AMERICAS-USA','AMERICAS-VENEZUELA','AMERICAS-CUBA','AMERICAS-MEXICO','AMERICAS-CENTRAL','AMERICAS-COLOMBIA','AMERICAS-BRAZIL','AMERICAS-CHILE','AMERICAS-ARGENTINA','AMERICAS-BOLIVIA','AMERICAS-PERU','AMERICAS-GUYANA'],false,27,NULL,NULL,'theater',ARRAY['venezuela_political_transition','essequibo_dispute','us_venezuela_relations','venezuela_sanctions_oil'],ARRAY['panama_canal'],'regional','{"type": "Point", "coordinates": [-66.9, 10.5]}'::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('latam_us_trade_pressure','US tariff and sanctions pressure','US-Zoll- und Sanktionsdruck','United States tariffs, sanctions designations and trade-enforcement measures applied to South American states.','Zölle, Sanktionslistungen und handelspolitische Zwangsmaßnahmen der Vereinigten Staaten gegenüber südamerikanischen Staaten.',ARRAY['AMERICAS-BRAZIL','AMERICAS-SOUTHERNCONE','AMERICAS-ANDEAN'],true,106,'Washington has proposed or imposed tariffs on Brazilian goods and issued sanctions designations touching Brazilian and Colombian officials and networks. Affected governments respond through negotiation, retaliation or appeals to the domestic electorate, and the measures intersect with election cycles in the targeted states.','Washington hat Zölle auf brasilianische Waren vorgeschlagen oder verhängt und Sanktionslistungen gegen brasilianische und kolumbianische Amtsträger und Netzwerke ausgesprochen. Betroffene Regierungen reagieren mit Verhandlungen, Gegenmaßnahmen oder der Ansprache der eigenen Wählerschaft; die Maßnahmen überschneiden sich mit Wahlzyklen in den betroffenen Staaten.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('m23_conflict','M23 insurgency in eastern Congo','M23-Aufstand im Osten der DR Kongo','M23 is an armed movement operating in North and South Kivu, aligned since 2023 with the Alliance Fleuve Congo. It has held Goma and other eastern towns, and the Congolese government, the United Nations and Western states attribute its capability to support from Rwanda -- an attribution Kigali rejects. The node also covers the other armed groups active in the same provinces, including the Allied Democratic Forces and CODECO.','M23 ist eine bewaffnete Bewegung in Nord- und Süd-Kivu, seit 2023 mit der Alliance Fleuve Congo verbunden. Sie hielt Goma und weitere Städte im Osten; die kongolesische Regierung, die Vereinten Nationen und westliche Staaten führen ihre Schlagkraft auf Unterstützung aus Ruanda zurück -- eine Zuschreibung, die Kigali zurückweist. Erfasst sind auch die übrigen bewaffneten Gruppen in denselben Provinzen, darunter die Allied Democratic Forces und CODECO.',ARRAY['AFRICA-DRC'],true,82,'Kinetic coverage fell steadily across the first half of 2026, from heavy fighting and drone strikes early in the year to an M23 withdrawal and government forces retaking ground by May.','Die Berichterstattung über Kampfhandlungen ging im ersten Halbjahr 2026 stetig zurück -- von schweren Gefechten und Drohnenangriffen zu Jahresbeginn bis zum Rückzug der M23 und der Rückeroberung von Gebieten durch Regierungstruppen im Mai.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('panama_canal_theater','US-China confrontation over the Panama Canal','US-chinesische Konfrontation um den Panamakanal','Port seizures, Chinese retaliation threats and transit politics have made the canal a front line of hemispheric great-power competition.','Hafenuebernahmen, chinesische Vergeltungsdrohungen und Transitpolitik haben den Kanal zu einer Frontlinie des hemisphaerischen Grossmachtwettbewerbs gemacht.',ARRAY['AMERICAS-CENTRAL','AMERICAS-USA','ASIA-CHINA'],false,NULL,NULL,NULL,'theater',ARRAY['panama_ports_dispute','panama_canal_transit_security'],ARRAY['panama_canal','colon_port'],'regional','{"type": "Point", "coordinates": [-79.6, 9.0]}'::jsonb,'AMERICAS-CENTRAL')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('panama_canal_transit_security','Canal transit security and neutrality','Transitsicherheit und Neutralitaet des Kanals','Ship-detention accusations, neutrality-treaty politics and the canal''s exposure to US-China escalation and drought-driven capacity limits.','Vorwuerfe von Schiffsfestsetzungen, Neutralitaetsvertragspolitik und die Anfaelligkeit des Kanals fuer US-chinesische Eskalation und duerrebedingte Kapazitaetsgrenzen.',ARRAY['AMERICAS-CENTRAL','AMERICAS-USA','ASIA-CHINA'],false,NULL,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-CENTRAL')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('panama_ports_dispute','Canal ports dispute and Hutchison eviction','Streit um die Kanalhaefen und Hutchison-Verdraengung','Panama''s seizure of the Balboa and Cristobal terminals from CK Hutchison after a Supreme Court ruling, and Beijing''s threatened retaliation.','Panamas Uebernahme der Terminals Balboa und Cristobal von CK Hutchison nach einem Urteil des Obersten Gerichts und Pekings angedrohte Vergeltung.',ARRAY['AMERICAS-CENTRAL','AMERICAS-USA','ASIA-CHINA'],false,NULL,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-CENTRAL')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('sahel_france_rupture','Rupture with France','Bruch mit Frankreich','The breakdown of relations between France and the Sahel states: severed diplomatic ties, expelled or withdrawn diplomats, prosecutions of French nationals on security charges, and the colonial-legacy arguments advanced on both sides.','Der Zusammenbruch der Beziehungen zwischen Frankreich und den Sahelstaaten: abgebrochene diplomatische Beziehungen, ausgewiesene oder abgezogene Diplomaten, Strafverfahren gegen französische Staatsangehörige wegen Sicherheitsdelikten und die auf beiden Seiten vorgebrachten Argumente zum kolonialen Erbe.',ARRAY['AFRICA-SAHEL','EUROPE-FRANCE'],true,105,'Burkina Faso broke off diplomatic relations with France and Paris called the move hostile; France withdrew its diplomats. A French intelligence officer was sentenced to twenty years in Bamako for offences against state security, a charge Paris rejects. Niger''s leadership publicly blamed France for the jihadist assault on Niamey airport, and France advised its nationals to leave Mali.','Burkina Faso brach die diplomatischen Beziehungen zu Frankreich ab; Paris nannte den Schritt feindselig und zog seine Diplomaten ab. Ein französischer Nachrichtendienstoffizier wurde in Bamako wegen Straftaten gegen die Staatssicherheit zu zwanzig Jahren verurteilt -- ein Vorwurf, den Paris zurückweist. Nigers Führung machte Frankreich öffentlich für den dschihadistischen Angriff auf den Flughafen von Niamey verantwortlich, und Frankreich empfahl seinen Staatsangehörigen, Mali zu verlassen.','atomic',NULL,'{}','regional',NULL::jsonb,'AFRICA-SAHEL')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('sahel_french_withdrawal','Post-French security vacuum and great power competition',NULL,NULL,NULL,ARRAY['AFRICA-SAHEL','EUROPE-FRANCE','AMERICAS-USA','EUROPE-RUSSIA'],false,79,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('sahel_jihadist_insurgency','Jihadist insurgency and territorial contest','Dschihadistischer Aufstand und territorialer Wettstreit','Operations by jihadist armed groups across the Sahel and the Lake Chad basin -- JNIM, Islamic State affiliates, Boko Haram and ISWAP -- and the counterinsurgency campaigns waged against them by national armies and their foreign partners, including the civilian toll of both.','Operationen dschihadistischer bewaffneter Gruppen in der Sahelzone und im Tschadseebecken -- JNIM, Ableger des Islamischen Staats, Boko Haram und ISWAP -- sowie die Aufstandsbekämpfung durch nationale Armeen und ihre ausländischen Partner, einschließlich der zivilen Opfer beider Seiten.',ARRAY['AFRICA-SAHEL','AFRICA-NIGERIA','NON-STATE-JIHADISTS','NON-STATE-BOKO-HARAM'],true,101,'The largest node in the theater. In 2026 JNIM moved from rural control to pressure on capitals, blockading Bamako''s fuel supply and mounting coordinated raids on multiple cities; Islamic State claimed an assault on Niamey''s airport. In the Lake Chad basin, Boko Haram and ISWAP continued mass abductions and attacks on military positions. Rights monitors and Amnesty documented large civilian death tolls from army airstrikes on both sides of the Nigeria-Sahel divide.','Der größte Knoten des Theaters. 2026 ging JNIM von der Kontrolle ländlicher Räume zum Druck auf Hauptstädte über, blockierte Bamakos Treibstoffversorgung und führte koordinierte Angriffe auf mehrere Städte; der Islamische Staat reklamierte einen Angriff auf den Flughafen von Niamey. Im Tschadseebecken setzten Boko Haram und ISWAP Massenentführungen und Angriffe auf Militärstellungen fort. Menschenrechtsbeobachter und Amnesty dokumentierten hohe zivile Opferzahlen durch Luftangriffe der Armeen auf beiden Seiten der nigerianisch-sahelischen Grenze.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('sahel_junta_consolidation','Junta consolidation and sovereigntist realignment','Junta-Konsolidierung und souveränistische Neuausrichtung','How the military governments that took power in Mali, Burkina Faso, Niger and Guinea consolidate control -- party bans, media suspensions, treatment of international bodies and postponed transitions -- and the sovereigntist doctrine they advance to justify it.','Wie die Militärregierungen, die in Mali, Burkina Faso, Niger und Guinea die Macht übernahmen, ihre Kontrolle festigen -- Parteiverbote, Mediensperren, der Umgang mit internationalen Institutionen und verschobene Übergänge -- und die souveränistische Doktrin, mit der sie dies begründen.',ARRAY['AFRICA-SAHEL'],true,103,'Burkina Faso dissolved all political parties and Guinea dissolved forty, including the main opposition. Niger withdrew from the International Criminal Court, describing it as an instrument of neocolonial repression, and suspended French media outlets. The UN human-rights office in Burkina Faso closed after being suspended. Mali''s leadership assumed the defence portfolio directly after the minister was killed.','Burkina Faso löste sämtliche politischen Parteien auf, Guinea vierzig, darunter die wichtigste Opposition. Niger trat aus dem Internationalen Strafgerichtshof aus, den es als Instrument neokolonialer Repression bezeichnete, und suspendierte französische Medien. Das UN-Menschenrechtsbüro in Burkina Faso schloss nach seiner Suspendierung. Malis Führung übernahm das Verteidigungsressort direkt, nachdem der Minister getötet worden war.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('sahel_security_patron_contest','Contest for security patronage','Wettstreit um die Sicherheitspatronage','The competition to supply the Sahel states with security assistance after the departure of French and UN forces: Russia''s Africa Corps, Turkish drones and training, renewed United States engagement, and Moroccan offers of Atlantic access to the landlocked members of the Alliance of Sahel States.','Der Wettstreit um Sicherheitsunterstützung für die Sahelstaaten nach dem Abzug französischer und UN-Kräfte: Russlands Africa Corps, türkische Drohnen und Ausbildung, erneutes Engagement der Vereinigten Staaten sowie marokkanische Angebote eines Atlantikzugangs für die Binnenstaaten der Allianz der Sahelstaaten.',ARRAY['AFRICA-SAHEL'],true,104,'The smallest node in the theater by volume but a persistent one. Africa Corps confirmed its withdrawal from Kidal, took casualties in rebel attacks and was reported retreating under jihadist pressure, while Moscow said its forces would stay in Mali and had helped stop an attempted coup. Niger''s president was received in Ankara as Türkiye expanded its training and drone footprint.','Der volumenmäßig kleinste, aber beständige Knoten des Theaters. Das Africa Corps bestätigte seinen Rückzug aus Kidal, erlitt Verluste bei Rebellenangriffen und wich Berichten zufolge unter dschihadistischem Druck zurück, während Moskau erklärte, seine Kräfte blieben in Mali und hätten geholfen, einen Putschversuch zu stoppen. Nigers Präsident wurde in Ankara empfangen, während die Türkei ihre Ausbildungs- und Drohnenpräsenz ausweitete.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('sahel_theater','Sahel military transition zone','Militärische Übergangszone Sahel','The Sahel and Lake Chad basin as a single conflict zone: jihadist insurgency, Tuareg separatism in northern Mali, military governments consolidating power after successive coups, the competition to replace France as the region''s security patron, and the rupture of relations with Paris.','Die Sahelzone und das Tschadseebecken als zusammenhängende Konfliktzone: dschihadistischer Aufstand, Tuareg-Separatismus in Nordmali, Militärregierungen, die nach aufeinanderfolgenden Putschen ihre Macht festigen, der Wettstreit um Frankreichs Nachfolge als Sicherheitspatron der Region und der Bruch der Beziehungen zu Paris.',ARRAY['AFRICA-SAHEL','EUROPE-FRANCE','EUROPE-RUSSIA','AMERICAS-USA'],true,22,'Coverage in the first half of 2026 is dominated by a single sequence: a coordinated JNIM and Tuareg offensive that killed Mali''s defence minister, blockaded Bamako and took Kidal, while Russia''s Africa Corps withdrew from the town it had helped hold. Around it sit the Lake Chad war against Boko Haram and ISWAP, party dissolutions in Burkina Faso and Niger''s exit from the ICC, and Burkina Faso''s severing of diplomatic relations with France.','Die Berichterstattung im ersten Halbjahr 2026 wird von einer einzigen Abfolge bestimmt: eine koordinierte Offensive von JNIM und Tuareg-Verbänden, die Malis Verteidigungsminister tötete, Bamako blockierte und Kidal einnahm, während sich Russlands Africa Corps aus der Stadt zurückzog, die es hatte halten helfen. Daneben stehen der Krieg am Tschadsee gegen Boko Haram und ISWAP, Parteiauflösungen in Burkina Faso, Nigers Austritt aus dem Internationalen Strafgerichtshof und der Abbruch der diplomatischen Beziehungen Burkina Fasos zu Frankreich.','theater',ARRAY['sahel_jihadist_insurgency','sahel_tuareg_separatism','sahel_junta_consolidation','sahel_security_patron_contest','sahel_france_rupture'],ARRAY['niger_delta_basin'],'regional','{"type": "Point", "coordinates": [0.9, 14.4]}'::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('sahel_tuareg_separatism','Tuareg separatism and the northern Mali question','Tuareg-Separatismus und die Frage Nordmalis','The unresolved status of northern Mali and the Tuareg-led armed movements that claim it, including their control of Kidal and their relations with both the central government and the jihadist groups operating in the same territory.','Der ungeklärte Status Nordmalis und die tuareg-geführten bewaffneten Bewegungen, die ihn beanspruchen -- einschließlich ihrer Kontrolle über Kidal und ihres Verhältnisses sowohl zur Zentralregierung als auch zu den im selben Gebiet operierenden dschihadistischen Gruppen.',ARRAY['AFRICA-SAHEL'],true,102,'Tuareg formations took full control of Kidal in 2026 after an arrangement under which Russian forces withdrew from the town, and declared that the government in Bamako would fall. They claimed coordinated attacks jointly with JNIM -- a tactical alignment between a secular separatist movement and an al-Qaeda affiliate that both Bamako and Moscow cite as grounds to treat the two as one.','Tuareg-Verbände übernahmen 2026 die vollständige Kontrolle über Kidal, nachdem sich russische Kräfte im Rahmen einer Vereinbarung aus der Stadt zurückgezogen hatten, und erklärten, die Regierung in Bamako werde fallen. Sie reklamierten koordinierte Angriffe gemeinsam mit JNIM -- eine taktische Annäherung zwischen einer säkularen Separatistenbewegung und einem al-Qaida-Ableger, die Bamako wie Moskau als Grund anführen, beide als eines zu behandeln.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('sahel_wagner_presence','Wagner and Russian military expansion in Sahel',NULL,NULL,NULL,ARRAY['AFRICA-SAHEL','EUROPE-RUSSIA','EUROPE-FRANCE','AMERICAS-USA'],false,80,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('somalia_state_security','Somali state security and coastal control','Somalias Staatssicherheit und Kontrolle der Küste','The Somali federal government is contesting control of its territory and coastline simultaneously: an insurgency by al-Shabaab, a peacekeeping mission facing a funding crisis, disputed federal elections that have produced armed clashes in Mogadishu, and a resurgence of piracy off the eastern seaboard. Turkey, the United States, Egypt and Gulf states are all engaged.','Die somalische Bundesregierung ringt gleichzeitig um die Kontrolle über ihr Territorium und ihre Küste: ein Aufstand von al-Shabaab, eine Friedensmission in der Finanzierungskrise, umstrittene Bundeswahlen mit bewaffneten Zusammenstößen in Mogadischu und ein Wiederaufleben der Piraterie vor der Ostküste. Die Türkei, die USA, Ägypten und Golfstaaten sind engagiert.',ARRAY['AFRICA-HORN','MIDEAST-TURKEY','AMERICAS-USA'],true,76,'Deliberately a broad slice: insurgency, the AU mission, the election crisis and piracy are one story about state capacity, not four separate ones.','Bewusst breit geschnitten: Aufstand, AU-Mission, Wahlkrise und Piraterie sind eine einzige Geschichte über staatliche Handlungsfähigkeit, nicht vier getrennte.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('somaliland_recognition_contest','Somaliland recognition contest','Der Streit um die Anerkennung Somalilands','Somaliland declared independence from Somalia in 1991 and has governed itself since without broad international recognition. Israel''s recognition and exchange of ambassadors, alongside discussions of port access, critical minerals and military basing, has made its status an active international dispute involving Somalia, the African Union, Arab and Muslim states, Turkey and the United States.','Somaliland erklärte 1991 seine Unabhängigkeit von Somalia und regiert sich seither selbst, ohne breite internationale Anerkennung. Israels Anerkennung und der Austausch von Botschaftern haben den Status -- zusammen mit Gesprächen über Hafenzugang, kritische Rohstoffe und Militärstützpunkte -- zu einem aktiven internationalen Konflikt gemacht, an dem Somalia, die Afrikanische Union, arabische und muslimische Staaten, die Türkei und die USA beteiligt sind.',ARRAY['AFRICA-HORN','MIDEAST-ISRAEL','AMERICAS-USA','MIDEAST-EGYPT','MIDEAST-TURKEY'],true,74,'The single largest strand of Horn coverage in 2026, and the one that pulls the most outside powers in.','Der mit Abstand größte Berichterstattungsstrang am Horn im Jahr 2026 -- und derjenige, der die meisten auswärtigen Mächte einbezieht.','atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_culture_wars','National culture war conflicts and polarisation',NULL,NULL,NULL,ARRAY['AMERICAS-USA'],false,89,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_domestic_theater','United States domestic governance conflict','Innenpolitischer Machtkonflikt in den USA','Conflicts over the powers, staffing and rules of United States federal institutions, and over how those institutions treat people inside the country. Covers the courts and executive authority, the central bank, election administration, immigration enforcement in the interior, federal personnel, the security of political figures, media regulation, and the investigation of elite networks. Foreign coverage treats these as indicators of American reliability and of the standards Washington applies abroad.','Konflikte über die Befugnisse, die Besetzung und die Regeln von US-Bundesinstitutionen sowie darüber, wie diese Institutionen Menschen im Inland behandeln. Umfasst Gerichte und Exekutivgewalt, die Notenbank, die Wahlorganisation, den Einwanderungsvollzug im Landesinneren, Bundespersonal, den Schutz politischer Amtsträger, die Medienaufsicht und die Aufklärung von Elitennetzwerken. Ausländische Berichterstattung sieht darin Indikatoren für die Verlässlichkeit der USA und für die Maßstäbe, die Washington im Ausland anlegt.',ARRAY['AMERICAS-USA'],true,24,'Eight distinct disputes run in parallel here. Interior immigration enforcement and the Epstein files generate the largest volume and the widest non-English coverage. The Supreme Court sits at the centre of several at once, having rejected the birthright-citizenship order and struck down the global tariff authority while upholding removal power elsewhere. A contested Federal Reserve succession, a rolling cycle of cabinet departures, a redistricting and ballot-rules fight ahead of the midterms, repeated security incidents around political figures, and regulatory pressure on broadcasters complete the set.','Acht eigenständige Auseinandersetzungen laufen hier parallel. Der Einwanderungsvollzug im Landesinneren und die Epstein-Akten erzeugen das größte Volumen und die breiteste fremdsprachige Berichterstattung. Der Supreme Court steht gleich in mehreren im Mittelpunkt: Er wies die Anordnung zum Geburtsortsprinzip zurück und kippte die globale Zollbefugnis, bestätigte andernorts aber die Entlassungsbefugnis. Eine umstrittene Fed-Nachfolge, eine fortlaufende Kette von Kabinettsabgängen, ein Streit um Wahlkreise und Stimmzettelregeln vor den Zwischenwahlen, wiederholte Sicherheitsvorfälle um politische Amtsträger und regulatorischer Druck auf Sender vervollständigen das Bild.','theater',ARRAY['us_electoral_legitimacy','us_judicial_constraint','us_executive_loyalty','us_fed_independence','us_interior_immigration_enforcement','us_epstein_elite_network','us_political_violence','us_press_freedom'],'{}','global',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_electoral_legitimacy','Electoral legitimacy and the midterm contest','Wahllegitimität und der Midterm-Wettstreit','Disputes over how United States elections are administered: the drawing of congressional district boundaries, rules on mail and absentee balloting, voter identification and citizenship-verification requirements, maintenance of voter rolls, and the scope of the Voting Rights Act. Contested through state legislatures and the federal courts.','Auseinandersetzungen über die Organisation von Wahlen in den USA: der Zuschnitt von Kongresswahlkreisen, Regeln zur Brief- und Abwesenheitswahl, Ausweis- und Staatsbürgerschaftsnachweise, die Pflege der Wählerverzeichnisse und die Reichweite des Voting Rights Act. Ausgetragen über die Parlamente der Bundesstaaten und die Bundesgerichte.',ARRAY['AMERICAS-USA'],true,101,'A redistricting contest runs across Texas, Florida, California, Virginia, Utah and South Carolina, with both parties redrawing maps and litigating the results. A Supreme Court ruling narrowing the Voting Rights Act reopened map fights in several states. Federal judges blocked a Postal Service order restricting mail balloting; House Republicans advanced a proof-of-citizenship requirement. An FBI raid on an Ohio voting-rights organisation drew attention shortly before the midterms.','Ein Streit um Wahlkreiszuschnitte zieht sich durch Texas, Florida, Kalifornien, Virginia, Utah und South Carolina, wobei beide Parteien Karten neu zeichnen und die Ergebnisse beklagen. Ein Urteil des Supreme Court zur Einschränkung des Voting Rights Act ließ Kartenstreitigkeiten in mehreren Bundesstaaten neu aufleben. Bundesrichter stoppten eine Anordnung der Post zur Einschränkung der Briefwahl; die Republikaner im Repräsentantenhaus brachten eine Nachweispflicht der Staatsbürgerschaft voran.','atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-USA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_epstein_elite_network','Epstein files and elite networks','Epstein-Akten und Elitennetzwerke','The investigation and disclosure of records concerning Jeffrey Epstein and the people connected to him: Justice Department file releases, congressional depositions and contempt proceedings, civil litigation and settlements, and parallel inquiries opened by other governments. Centred on United States court and congressional process, with subjects in several countries.','Ermittlungen und Aktenfreigaben zu Jeffrey Epstein und den mit ihm verbundenen Personen: Freigaben des Justizministeriums, Vernehmungen und Missachtungsverfahren im Kongress, Zivilklagen und Vergleiche sowie parallele Untersuchungen anderer Regierungen. Zentriert auf US-Gerichts- und Kongressverfahren, mit Betroffenen in mehreren Ländern.',ARRAY['AMERICAS-USA'],true,106,'The Justice Department released successive batches of files and video. Bill and Hillary Clinton testified and later faced contempt resolutions; Ghislaine Maxwell invoked the Fifth Amendment before the House Oversight Committee; the attorney general was subpoenaed and subsequently removed. Consequences reached well beyond the United States: a British former ambassador left the Labour Party and the prime minister''s chief of staff resigned, a Goldman Sachs lawyer stepped down, French prosecutors searched premises linked to a former minister, and Norway and Poland opened inquiries.','Das Justizministerium gab nacheinander Aktenpakete und Videomaterial frei. Bill und Hillary Clinton sagten aus und sahen sich später Missachtungsanträgen gegenüber; Ghislaine Maxwell verweigerte vor dem Kontrollausschuss die Aussage; die Justizministerin wurde vorgeladen und anschließend abberufen. Die Folgen reichten weit über die USA hinaus: Ein früherer britischer Botschafter verließ die Labour-Partei und der Stabschef des Premierministers trat zurück, eine Anwältin von Goldman Sachs schied aus, französische Staatsanwälte durchsuchten Räume mit Bezug zu einem Ex-Minister, und Norwegen und Polen leiteten Untersuchungen ein.','atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-USA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_executive_loyalty','Cabinet turnover and executive loyalty','Kabinettsumbau und Loyalität in der Exekutive','Departures, dismissals and replacements among senior United States federal officials: cabinet secretaries, the attorney general, intelligence and law-enforcement leadership, inspectors general and federal prosecutors. Covers both the appointments process and the reasons given for removals.','Abgänge, Entlassungen und Neubesetzungen unter hohen US-Bundesbeamten: Kabinettsmitglieder, die Justizministerin, die Führung von Nachrichtendiensten und Strafverfolgung, Generalinspekteure und Bundesstaatsanwälte. Umfasst sowohl das Ernennungsverfahren als auch die genannten Gründe für Abberufungen.',ARRAY['AMERICAS-USA'],true,103,'The attorney general was removed after appearing before the House Oversight Committee on the Epstein files; the homeland security secretary departed following a fatal shooting by an officer in Minneapolis; the director of national intelligence resigned. The FBI dismissed agents who had worked on earlier investigations touching the president. Several posts were filled on a temporary basis pending Senate confirmation.','Die Justizministerin wurde nach ihrem Auftritt vor dem Kontrollausschuss des Repräsentantenhauses zu den Epstein-Akten abberufen; die Heimatschutzministerin schied nach tödlichen Schüssen eines Beamten in Minneapolis aus; die Koordinatorin der Nachrichtendienste trat zurück. Das FBI entließ Beamte, die an früheren Ermittlungen mit Bezug zum Präsidenten gearbeitet hatten. Mehrere Posten wurden bis zur Bestätigung durch den Senat kommissarisch besetzt.','atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-USA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_federal_state_authority','Federal versus state authority and governance',NULL,NULL,NULL,ARRAY['AMERICAS-USA'],false,87,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_fed_independence','Federal Reserve independence','Unabhängigkeit der US-Notenbank','The relationship between the United States executive and the Federal Reserve: nomination and confirmation of the chair and governors, the legal limits on removing them, and disputes over the central bank''s autonomy in setting policy. Distinct from routine monetary-policy coverage, which concerns rate decisions rather than institutional control.','Das Verhältnis zwischen der US-Exekutive und der Federal Reserve: Nominierung und Bestätigung des Vorsitzes und der Gouverneure, die rechtlichen Grenzen ihrer Abberufung und Streit über die Autonomie der Notenbank bei der Politikgestaltung. Abzugrenzen von der routinemäßigen Geldpolitik-Berichterstattung, die Zinsentscheidungen und nicht institutionelle Kontrolle betrifft.',ARRAY['AMERICAS-USA'],true,104,'Kevin Warsh was nominated to succeed Jerome Powell as chair and cleared the Senate committee stage. An attempt to remove governor Lisa Cook was blocked in court, and a Justice Department referral against Powell was later dropped. Powell served out his term, publicly warning that the institution was undergoing a stress test and that lost credibility would be difficult to restore.','Kevin Warsh wurde als Nachfolger von Jerome Powell für den Vorsitz nominiert und passierte die Ausschussstufe im Senat. Der Versuch, die Gouverneurin Lisa Cook abzuberufen, wurde gerichtlich gestoppt; eine Anzeige des Justizministeriums gegen Powell wurde später fallengelassen. Powell beendete seine Amtszeit und warnte öffentlich, die Institution durchlaufe einen Stresstest und verlorene Glaubwürdigkeit sei schwer wiederherzustellen.','atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-USA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_interior_immigration_enforcement','Interior immigration enforcement','Einwanderungsdurchsetzung im Landesinneren','Immigration enforcement conducted inside the United States rather than at the border: arrests and removals by Immigration and Customs Enforcement, detention facilities and conditions within them, judicial review of individual cases, and disputes between federal agencies and state or city governments over cooperation. Border, cartel and bilateral trade questions belong to the US-Mexico theater.','Einwanderungsvollzug innerhalb der USA statt an der Grenze: Festnahmen und Abschiebungen durch die Einwanderungsbehörde ICE, Hafteinrichtungen und die Bedingungen darin, gerichtliche Überprüfung von Einzelfällen sowie Streit zwischen Bundesbehörden und Bundesstaaten oder Städten über die Zusammenarbeit. Grenz-, Kartell- und bilaterale Handelsfragen gehören zum US-Mexiko-Feld.',ARRAY['AMERICAS-USA'],true,105,'Congress approved a large multi-year funding increase for the agency. Deaths in custody rose and a measles outbreak was recorded at a Texas facility; judges ordered individual releases, including of a five-year-old and an 86-year-old French national. Agents were deployed to airports during a partial government shutdown, and their planned presence at stadiums during the World Cup drew majority public opposition in polling. State and city governments clashed with federal authorities over cooperation, and a county charged an officer over a non-fatal shooting.','Der Kongress bewilligte eine große mehrjährige Mittelaufstockung für die Behörde. Todesfälle in Gewahrsam nahmen zu, in einer Einrichtung in Texas wurden Masern festgestellt; Richter ordneten Freilassungen an, darunter die eines Fünfjährigen und einer 86-jährigen Französin. Beamte wurden während eines teilweisen Regierungsstillstands an Flughäfen eingesetzt, ihre geplante Präsenz in Stadien während der WM stieß in Umfragen mehrheitlich auf Ablehnung. Bundesstaaten und Städte gerieten mit Bundesbehörden über die Zusammenarbeit aneinander.','atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-USA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_judicial_constraint','Federal courts and executive power','Bundesgerichte und die Macht der Exekutive','Litigation over the reach of United States executive authority and the rulings that decide it: emergency and merits decisions of the Supreme Court, injunctions issued by federal district judges, and appellate review. Covers both decisions constraining the executive and decisions expanding its discretion.','Rechtsstreitigkeiten über die Reichweite der US-Exekutivgewalt und die Urteile, die darüber entscheiden: Eil- und Hauptsacheentscheidungen des Supreme Court, einstweilige Verfügungen von Bundesbezirksrichtern und Berufungsverfahren. Umfasst sowohl Entscheidungen, die die Exekutive begrenzen, als auch solche, die ihren Ermessensspielraum erweitern.',ARRAY['AMERICAS-USA'],true,102,'The Court rejected an attempt to limit birthright citizenship and ruled the global tariff order an unlawful use of executive power, prompting a replacement 10% tariff. It blocked the removal of a Federal Reserve governor while upholding removal power over other agencies, and expanded immigration discretion in TPS and southern-border decisions. Lower courts blocked a mail-ballot order and the defunding of public broadcasters.','Das Gericht wies den Versuch zurück, das Geburtsortsprinzip einzuschränken, und erklärte die globale Zollanordnung für einen unrechtmäßigen Gebrauch der Exekutivgewalt, woraufhin ein pauschaler Zoll von 10 Prozent folgte. Es stoppte die Abberufung einer Fed-Vorständin, bestätigte aber die Entlassungsbefugnis gegenüber anderen Behörden und erweiterte das Ermessen bei TPS- und Grenzentscheidungen. Untergerichte stoppten eine Briefwahlanordnung und die Mittelstreichung für öffentliche Sender.','atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-USA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_political_violence','Political violence and protective security','Politische Gewalt und Personenschutz','Attacks, attempted attacks and threats directed at United States political figures and institutions, and the protective and judicial response: Secret Service operations, prosecutions of suspects, security arrangements for officials and judges, and disclosed plots against political events.','Angriffe, Angriffsversuche und Drohungen gegen politische Amtsträger und Institutionen in den USA sowie die Schutz- und Justizreaktion: Einsätze des Secret Service, Strafverfahren gegen Verdächtige, Sicherheitsvorkehrungen für Amtsträger und Richter sowie aufgedeckte Anschlagspläne auf politische Veranstaltungen.',ARRAY['AMERICAS-USA'],true,107,'Shots were fired at the White House Correspondents'' Dinner, from which the president was evacuated; a suspect was charged and pleaded not guilty, and officials later said the president was the likely target. A separate armed man was killed entering the Mar-a-Lago perimeter, gunfire was exchanged near the White House and near the vice-president''s motorcade, and the FBI reported foiling a drone-and-sniper plot against an event. A member of Congress was attacked at a town hall in Minneapolis, and a Supreme Court justice described heightened security and threats to the judiciary.','Beim Korrespondentendinner im Weißen Haus fielen Schüsse, der Präsident wurde evakuiert; ein Verdächtiger wurde angeklagt und bekannte sich nicht schuldig, Behörden nannten den Präsidenten später als wahrscheinliches Ziel. Ein bewaffneter Mann wurde beim Eindringen auf das Gelände von Mar-a-Lago erschossen, nahe dem Weißen Haus und dem Konvoi des Vizepräsidenten fielen Schüsse, und das FBI vereitelte nach eigenen Angaben einen Anschlagsplan mit Drohnen und Scharfschützen. Ein Kongressmitglied wurde bei einer Bürgerversammlung in Minneapolis angegriffen.','atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-USA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_press_freedom','Press freedom and broadcast regulation','Pressefreiheit und Rundfunkaufsicht','The relationship between United States federal authority and news organisations: Federal Communications Commission action on broadcast licences, funding decisions affecting public broadcasters, press access to government departments, defamation litigation brought against news outlets, and First Amendment rulings arising from these.','Das Verhältnis zwischen US-Bundesbehörden und Nachrichtenorganisationen: Maßnahmen der Rundfunkaufsicht FCC zu Sendelizenzen, Finanzierungsentscheidungen für öffentliche Sender, Pressezugang zu Ministerien, Verleumdungsklagen gegen Medien und die daraus folgenden Urteile zum Ersten Verfassungszusatz.',ARRAY['AMERICAS-USA'],true,108,'The FCC opened licence reviews at stations carrying a network programme after a presenter''s joke about the first lady, and the network''s lawyers accused the regulator of acting for political reasons. A federal judge blocked an order ending funding for NPR and PBS on First Amendment grounds. The Pentagon moved to restrict press access again after losing in court, a $10 billion defamation suit was refiled against a newspaper, and the Committee to Protect Journalists and foreign outlets recorded visa revocations affecting a Costa Rican newspaper''s executives.','Die FCC leitete Lizenzüberprüfungen bei Sendern ein, die ein Netzwerkprogramm ausstrahlen, nachdem ein Moderator einen Witz über die First Lady gemacht hatte; die Anwälte des Senders warfen der Aufsicht politisch motiviertes Handeln vor. Ein Bundesrichter stoppte unter Berufung auf den Ersten Verfassungszusatz die Streichung der Mittel für NPR und PBS. Das Pentagon schränkte den Pressezugang nach einer Niederlage vor Gericht erneut ein, eine Verleumdungsklage über 10 Milliarden Dollar gegen eine Zeitung wurde neu eingereicht.','atomic',NULL,'{}','regional',NULL::jsonb,'AMERICAS-USA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_russia_arms_control','Nuclear arms control and strategic stability','Nukleare Rüstungskontrolle und strategische Stabilität','The nuclear arms-control relationship between the United States and Russia: treaty limits on deployed warheads and delivery systems, verification and inspection arrangements, strategic-stability talks, missile-defence programmes and novel delivery systems that fall outside existing frameworks.','Das nukleare Rüstungskontrollverhältnis zwischen den Vereinigten Staaten und Russland: vertragliche Obergrenzen für stationierte Sprengköpfe und Trägersysteme, Verifikations- und Inspektionsregelungen, Gespräche über strategische Stabilität, Raketenabwehrprogramme sowie neuartige Trägersysteme außerhalb bestehender Rahmen.',ARRAY['AMERICAS-USA'],true,94,'New START expired on 4 February 2026, ending the last treaty limits on the two largest nuclear arsenals and with them the inspection and data-exchange regime. The UN called the lapse a grave moment and coverage widely anticipates an unconstrained arms race. Talks on a successor have not stopped -- proposals have been floated and reported as close to agreement more than once, and China has publicly urged the two to resume strategic-stability dialogue -- but nothing has been concluded. Moscow attributes the collapse to rejected proposals and to the Golden Dome missile-defence programme; Washington points to Russian systems built outside any treaty''s scope.','New START lief am 4. Februar 2026 aus und beendete die letzten vertraglichen Obergrenzen für die beiden größten Nukleararsenale und damit auch das Inspektions- und Datenaustauschregime. Die UN nannte dies einen ernsten Moment; die Berichterstattung erwartet überwiegend ein ungebremstes Wettrüsten. Gespräche über einen Nachfolger laufen weiter -- Vorschläge wurden mehrfach als kurz vor einer Einigung berichtet, und China forderte beide Seiten öffentlich zur Wiederaufnahme des Dialogs über strategische Stabilität auf -- abgeschlossen wurde nichts. Moskau führt den Zusammenbruch auf zurückgewiesene Vorschläge und das Raketenabwehrprogramm Golden Dome zurück; Washington verweist auf russische Systeme außerhalb jedes Vertragsrahmens.','atomic',NULL,'{}','regional',NULL::jsonb,'EUROPE-RUSSIA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_russia_bilateral_channel','Bilateral channel and normalisation','Bilateraler Gesprächskanal und Normalisierung','The working mechanism of the US-Russia relationship: envoy missions, foreign-minister contacts, leader-level calls, summit formats and the state of diplomatic and military channels between Washington and Moscow. Covers the machinery of contact itself rather than the substance of the Ukraine negotiations, which has its own node.','Der Arbeitsmechanismus des Verhältnisses zwischen den USA und Russland: Missionen von Sondergesandten, Kontakte der Außenminister, Telefonate auf Führungsebene, Gipfelformate sowie der Zustand der diplomatischen und militärischen Kanäle zwischen Washington und Moskau. Erfasst wird das Kontaktgeschehen selbst, nicht der Inhalt der Ukraine-Verhandlungen, für den ein eigener Knoten besteht.',ARRAY['AMERICAS-USA'],true,93,'Contact is far denser than at any point since 2022. US envoys have travelled repeatedly to Moscow, the two militaries have re-established high-level communication, foreign ministers speak by phone, and leader-level calls have become routine enough to include congratulatory exchanges. Moscow presents this as overdue recognition of parity while simultaneously accusing Washington of stalling and issuing ultimatums -- the two Kremlin registers run side by side.

The most telling pattern here is where the coverage lives rather than what it says. Russian state media treat the bilateral relationship as a standing subject and produce continuous commentary on its condition; Western outlets cover the same meetings and calls almost entirely as Ukraine-war developments, with the relationship itself appearing only as context. The result is that Moscow generates a large body of explicit narrative about the relationship while the Western position on it has to be inferred from war reporting -- an asymmetry in framing, not in the underlying events, and one reason the Kremlin''s account of the relationship travels more easily than any competing one.','Die Kontaktdichte ist so hoch wie zu keinem Zeitpunkt seit 2022. US-Sondergesandte reisten mehrfach nach Moskau, beide Streitkräfte stellten die Kommunikation auf hoher Ebene wieder her, die Außenminister telefonieren, und Gespräche auf Führungsebene sind so alltäglich geworden, dass sie Glückwünsche einschließen. Moskau stellt dies als überfällige Anerkennung der Ebenbürtigkeit dar und wirft Washington zugleich Hinhalten und Ultimaten vor -- beide Register laufen nebeneinander.

Aufschlussreicher als der Inhalt ist, wo diese Berichterstattung stattfindet. Russische Staatsmedien behandeln das bilaterale Verhältnis als dauerhaften Gegenstand und kommentieren seinen Zustand fortlaufend; westliche Medien berichten über dieselben Treffen und Telefonate fast ausschließlich als Entwicklungen des Ukrainekriegs, das Verhältnis selbst erscheint nur als Kontext. So entsteht in Moskau ein großer Bestand ausdrücklicher Erzählungen über die Beziehung, während die westliche Position dazu aus der Kriegsberichterstattung erschlossen werden muss -- eine Asymmetrie der Rahmung, nicht der Ereignisse, und ein Grund, weshalb die Kreml-Darstellung des Verhältnisses leichter Verbreitung findet als konkurrierende.','atomic',NULL,'{}','regional',NULL::jsonb,'EUROPE-RUSSIA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_russia_election_interference','Election interference and information warfare',NULL,NULL,NULL,ARRAY['AMERICAS-USA','EUROPE-RUSSIA'],false,95,NULL,NULL,'atomic',NULL,'{}','regional',NULL::jsonb,NULL)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_russia_sanctions_leverage','Sanctions relief as leverage','Sanktionslockerung als Druckmittel','American sanctions on Russian energy and finance used as an adjustable instrument: waivers, general licences and exemptions issued, extended, allowed to lapse and reinstated, and the effect of those decisions on Russian export revenue, on third-country buyers, and on coordination with European partners. Distinct from European enforcement action against the shadow fleet, which sits in the Russia-Europe theater.','Amerikanische Sanktionen gegen russische Energie und Finanzwirtschaft als verstellbares Instrument: Ausnahmegenehmigungen, Generallizenzen und Befreiungen, die erteilt, verlängert, auslaufen gelassen und wieder in Kraft gesetzt werden, sowie deren Wirkung auf russische Exporteinnahmen, auf Käufer in Drittstaaten und auf die Abstimmung mit europäischen Partnern. Abzugrenzen von der europäischen Durchsetzung gegen die Schattenflotte, die im Theater Russland-Europa liegt.',ARRAY['AMERICAS-USA'],true,92,'Waiver policy has moved repeatedly through 2026. Washington eased restrictions on cargoes already at sea, granted and then extended a 30-day waiver covering Indian purchases, exempted Rosneft''s German operations and approved a Lukoil carve-out for Bulgaria, before letting waivers lapse and signalling further changes. Each move drew objections from Kyiv and from European and British partners, and congressional pressure for a new sanctions bill persists. Indian and other buyers have continued purchasing throughout, treating the waivers as confirmation the restrictions were unenforceable rather than as permission.','Die Ausnahmepolitik hat sich 2026 mehrfach geändert. Washington lockerte Beschränkungen für bereits auf See befindliche Ladungen, gewährte und verlängerte eine 30-Tage-Ausnahme für indische Käufe, befreite das Deutschlandgeschäft von Rosneft und genehmigte eine Lukoil-Ausnahme für Bulgarien, ließ Ausnahmen dann auslaufen und kündigte weitere Änderungen an. Jeder Schritt rief Einwände aus Kyjiw sowie von europäischen und britischen Partnern hervor; im Kongress hält der Druck für ein neues Sanktionsgesetz an. Indische und andere Käufer kauften durchgehend weiter.','atomic',NULL,'{}','regional',NULL::jsonb,'EUROPE-RUSSIA')
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, description_en = EXCLUDED.description_en, description_de = EXCLUDED.description_de, centroid_ids = EXCLUDED.centroid_ids, is_active = EXCLUDED.is_active, display_order = EXCLUDED.display_order, editorial_summary_en = EXCLUDED.editorial_summary_en, editorial_summary_de = EXCLUDED.editorial_summary_de, fn_type = EXCLUDED.fn_type, member_fn_ids = EXCLUDED.member_fn_ids, affected_asset_ids = EXCLUDED.affected_asset_ids, scope = EXCLUDED.scope, anchor_point = EXCLUDED.anchor_point, primary_target = EXCLUDED.primary_target, updated_at = NOW();
INSERT INTO friction_nodes (id,name_en,name_de,description_en,description_de,centroid_ids,is_active,display_order,editorial_summary_en,editorial_summary_de,fn_type,member_fn_ids,affected_asset_ids,scope,anchor_point,primary_target) VALUES ('us_russia_theater','US-Russia strategic relationship','Das strategische Verhältnis zwischen den USA und Russland','The bilateral relationship between the United States and Russia, treated as a subject in its own right: the diplomatic channel between Washington and Moscow, the American sanctions instruments applied to Russian energy and finance, and the nuclear arms-control framework the two states share. Distinct from the war in Ukraine, which is covered by its own theater, though the two intersect constantly.','Das bilaterale Verhältnis zwischen den Vereinigten Staaten und Russland als eigenständiger Gegenstand: der diplomatische Kanal zwischen Washington und Moskau, die amerikanischen Sanktionsinstrumente gegenüber russischer Energie und Finanzwirtschaft sowie der gemeinsame nukleare Rüstungskontrollrahmen. Abzugrenzen vom Krieg in der Ukraine, der ein eigenes Theater hat, auch wenn sich beide ständig überschneiden.',ARRAY['AMERICAS-USA','EUROPE-RUSSIA'],true,26,'The relationship is in an unsettled thaw. Working contacts have been rebuilt -- envoy visits to Moscow, a resumed high-level military channel, repeated leader-level calls -- while Washington has repeatedly issued and withdrawn waivers on Russian oil, drawing objections from European and British partners still tightening enforcement. The last nuclear warhead limits lapsed with New START in February 2026, leaving the two arsenals unconstrained for the first time in decades. Coverage divides less along US-versus-Russia lines than over how much accommodation of Moscow is warranted, with Western outlets on both sides of that question and third-country buyers treating the whole framework as conditions to navigate.

Note where each camp does its arguing. Russian state media treat the bilateral relationship as a subject in itself and comment on it continuously; Western coverage engages the same events mainly through the war in Ukraine and through sanctions policy, seldom as bilateral commentary. Both camps are present across this theater, but they are not arguing on the same terrain.','Das Verhältnis befindet sich in einem ungefestigten Tauwetter. Arbeitskontakte wurden wieder aufgebaut -- Besuche von Sondergesandten in Moskau, ein wieder aufgenommener militärischer Kanal auf hoher Ebene, wiederholte Telefonate auf Führungsebene -- während Washington Ausnahmegenehmigungen für russisches Öl mehrfach erteilte und zurücknahm, was Einwände europäischer und britischer Partner hervorrief, die die Durchsetzung weiter verschärfen. Die letzten nuklearen Obergrenzen liefen im Februar 2026 mit New START aus; erstmals seit Jahrzehnten sind beide Arsenale unbegrenzt. Die Berichterstattung teilt sich weniger entlang der Linie USA gegen Russland als an der Frage, wie viel Entgegenkommen gegenüber Moskau gerechtfertigt ist.

Aufschlussreich ist, wo die jeweilige Seite ihre Argumente vorbringt. Russische Staatsmedien behandeln das bilaterale Verhältnis als eigenständigen Gegenstand und kommentieren es fortlaufend; westliche Berichterstattung nähert sich denselben Ereignissen vor allem über den Ukrainekrieg und über die Sanktionspolitik, selten als bilateraler Kommentar. Beide Lager sind in diesem Theater präsent, aber sie streiten nicht auf demselben Terrain.','theater',ARRAY['us_russia_sanctions_leverage','us_russia_bilateral_channel','us_russia_arms_control'],ARRAY['yamal_lng','west_siberian_basin','samotlor_field'],'global',NULL::jsonb,NULL)
