-- 5. narratives_v2: 136 rows.
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('colombia_peace_negotiation_defense','Talks are how the war ends','Gespräche beenden den Krieg','The supportive reading holds that negotiated demobilisation, transitional justice and rural investment are the only instruments that have historically reduced Colombia''s armed conflict, and that suspending talks under external pressure forfeits the mechanism without offering a replacement.','Die unterstützende Lesart hält fest, dass ausgehandelte Demobilisierung, Übergangsjustiz und Investitionen im ländlichen Raum die einzigen Instrumente sind, die Kolumbiens bewaffneten Konflikt historisch verringert haben, und dass die Aussetzung der Gespräche unter äußerem Druck diesen Mechanismus preisgibt, ohne Ersatz zu bieten.',ARRAY['AMERICAS-ANDEAN'],ARRAY['paz total','proceso de paz','negociac','peace talks','peace process','desmoviliz','transitional justice','justicia transicional','diálogo','acuerdo','resume','reanuda','ceasefire','cese'],true,ARRAY['El País','Deutsche Welle','Al Jazeera','Anadolu Agency','UN News','The Guardian','France 24','France 24 (EN)','BBC World'],'colombia_armed_groups_peace',1,'Negotiation is the workable route','Verhandlung ist der gangbare Weg',1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('colombia_peace_process_failure','Talks bought the cartels time','Gespräche verschafften den Kartellen Zeit','The critical reading holds that open-ended negotiations let guerrilla factions and cartels consolidate territory, recruit and expand coca and gold revenues while nominally at the table, and that violence rose over the period the policy was in force.','Die kritische Lesart hält fest, dass ergebnisoffene Verhandlungen es Guerillafraktionen und Kartellen erlaubten, Gebiete zu festigen, zu rekrutieren sowie Koka- und Goldeinnahmen auszuweiten, während sie nominell am Tisch saßen, und dass die Gewalt im Geltungszeitraum der Politik zunahm.',ARRAY['AMERICAS-ANDEAN'],ARRAY['violencia','fracaso','enseñorea','dispara','control territorial','reclutamiento','impunidad','failed','emboldened','expansión','suspend','war crimes','crímenes de guerra','extorsión'],true,ARRAY['El Mundo','Reforma','El Universal','Clarín','La Nación','Infobae'],'colombia_armed_groups_peace',2,'Negotiation emboldened the groups','Verhandlungen bestärkten die Gruppen', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('colombia_transition_mandate','Voters chose a harder line','Die Wähler wählten eine härtere Linie','The sympathetic reading treats the result as a decisive verdict on the outgoing government''s security record: an electorate exhausted by cartel violence and stalled negotiations voted for confrontation with armed groups and closer working relations with Washington.','Die wohlwollende Lesart wertet das Ergebnis als deutliches Urteil über die Sicherheitsbilanz der scheidenden Regierung: Eine von Kartellgewalt und stockenden Verhandlungen erschöpfte Wählerschaft stimmte für die Konfrontation mit bewaffneten Gruppen und engere Arbeitsbeziehungen zu Washington.',ARRAY['AMERICAS-ANDEAN'],ARRAY['mandato','mano dura','seguridad','crackdown','mega-prison','megacárcel','crime','rightward','giro a la derecha','ciclo de Petro','tough on','respaldo','cartel','orden','autoridad'],true,ARRAY['El Mundo','Reforma','El Universal','Clarín','La Nación','Infobae','Associated Press','Reuters','Bloomberg','Japan Times','Atlantic Council'],'colombia_political_transition',1,'A mandate for security','Ein Mandat für Sicherheit',2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('colombia_transition_institutional_concern','The result strains the guardrails','Das Ergebnis belastet die Schutzmechanismen','The critical reading raises the endorsement of a candidate by a foreign head of state before the vote, the outgoing president''s allegation of foreign interference, and the losing camp''s legal challenge as pressures on Colombian institutional norms, independent of the winner''s programme.','Die kritische Lesart benennt die Unterstützung eines Kandidaten durch ein ausländisches Staatsoberhaupt vor der Wahl, den Vorwurf ausländischer Einflussnahme durch den scheidenden Präsidenten und die Klage des unterlegenen Lagers als Belastungen kolumbianischer institutioneller Normen -- unabhängig vom Programm des Siegers.',ARRAY['AMERICAS-ANDEAN'],ARRAY['institucional','institutional','democracia','democracy','injerencia','interference','fraude','impugna','legal challenge','norms','autoritari','riesgo','concern','fears','ultraderech','far-right','extrema derecha','estrema destra','no reconoce','non riconosce','threat to','amenaza para','backsliding'],true,ARRAY['El País','The Guardian','Deutsche Welle','France 24','France 24 (EN)','Le Monde','BBC World','New York Times','CNN','Euronews','La Repubblica','Al Jazeera','Anadolu Agency'],'colombia_political_transition',2,'Concern for institutional norms','Sorge um institutionelle Normen', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('colombia_theater_hard_turn','The electorate chose confrontation','Die Wählerschaft wählte Konfrontation','One reading runs through every arena at once: voters rejected negotiation with armed groups, elected a government promising confrontation and closer alignment with Washington, and treated the outgoing security policy as the thing that failed.','Eine Lesart durchzieht alle Bereiche zugleich: Die Wähler lehnten Verhandlungen mit bewaffneten Gruppen ab, wählten eine Regierung, die Konfrontation und engere Anlehnung an Washington verspricht, und werteten die scheidende Sicherheitspolitik als das Gescheiterte.',ARRAY['AMERICAS-ANDEAN'],ARRAY['mandato','seguridad','mano dura','cartel','violencia','victoria','contundente'],true,ARRAY['El Mundo','Reforma','El Universal','Clarín','La Nación','Infobae'],'colombia_theater',1,'A country turning hard','Ein Land im harten Kurswechsel',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('colombia_theater_negotiated_path','Bargaining still works, at home and abroad','Verhandeln funktioniert weiter, innen wie außen','A second reading emphasises that both the confrontation with Washington and the conflict with armed groups were managed through bargaining rather than force: the military threat ended in a White House meeting, and negotiation remains the only instrument that has historically shrunk the armed conflict.','Eine zweite Lesart betont, dass sowohl die Konfrontation mit Washington als auch der Konflikt mit bewaffneten Gruppen durch Verhandlung statt Gewalt bearbeitet wurden: Die Militärdrohung endete in einem Treffen im Weißen Haus, und Verhandlung bleibt das einzige Instrument, das den bewaffneten Konflikt historisch verkleinert hat.',ARRAY['AMERICAS-ANDEAN'],ARRAY['détente','acuerdo','negociac','peace process','paz total','diálogo','meeting'],true,ARRAY['Reuters','Associated Press','BBC World','Deutsche Welle','CNN','The Guardian','New York Times','France 24','France 24 (EN)','Le Monde','NPR','Euronews','Bloomberg','Financial Times','El País','Al Jazeera','Anadolu Agency','UN News'],'colombia_theater',2,'The negotiated path holds','Der Verhandlungsweg trägt',1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('colombia_theater_external_pressure','Decisions shaped from outside','Von außen geformte Entscheidungen','Mainstream coverage across the arenas describes a state whose room for manoeuvre narrowed from outside: a threatened military operation, tariff and sanctions pressure, a foreign endorsement in a national election, and an understanding with Washington that reshaped domestic negotiations with armed groups.','Etablierte Berichterstattung beschreibt über alle Bereiche hinweg einen Staat, dessen Handlungsspielraum von außen verengt wurde: eine angedrohte Militäroperation, Zoll- und Sanktionsdruck, eine ausländische Wahlempfehlung im nationalen Wahlkampf und eine Verständigung mit Washington, die die inneren Verhandlungen mit bewaffneten Gruppen umformte.',ARRAY['AMERICAS-ANDEAN'],ARRAY['threat','amenaza','sovereignty','soberan','injerencia','interference','institutional','democracia','tariff','sanction'],true,ARRAY['Reuters','Associated Press','BBC World','Deutsche Welle','CNN','The Guardian','New York Times','France 24','France 24 (EN)','Le Monde','NPR','Euronews','Bloomberg','Financial Times','El País','La Repubblica','Al Jazeera','Anadolu Agency'],'colombia_theater',3,'Sovereignty under external pressure','Souveränität unter äußerem Druck', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('colombia_theater_hegemonic_critique','The region as a sphere of influence','Die Region als Einflusssphäre','State and non-Western outlets read the same events as a single demonstration of US primacy in the hemisphere -- military threats, strikes in neighbouring Venezuela and open intervention in an allied democracy''s election -- rather than as separate bilateral disputes.','Staatliche und außerwestliche Medien lesen dieselben Ereignisse als eine einzige Demonstration US-amerikanischer Vormacht in der Hemisphäre -- Militärdrohungen, Angriffe im benachbarten Venezuela und offene Einmischung in die Wahl einer verbündeten Demokratie -- und nicht als getrennte bilaterale Streitfälle.',ARRAY['AMERICAS-USA'],ARRAY['hegemon','imperial','soberan','injerencia','domination','unilateral','sphere of influence'],true,ARRAY['CGTN','China Daily','Global Times','Xinhua','RT','TASS','TASS (EN)','Sputnik','RIA Novosti','Press TV','Al-Ahram'],'colombia_theater',4,'Hemispheric domination critique','Kritik hemisphärischer Vorherrschaft', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('colombia_us_rapprochement','The channel was repaired','Der Gesprächskanal wurde repariert','Coverage of the reversal treats the White House meeting as evidence that the relationship remains negotiable: threats gave way to an invitation, both governments claimed a working understanding, and cooperation on security and trade resumed.','Die Berichterstattung über die Kehrtwende wertet das Treffen im Weißen Haus als Beleg dafür, dass die Beziehung verhandelbar bleibt: Auf Drohungen folgte eine Einladung, beide Regierungen reklamierten eine Arbeitsverständigung, und die Zusammenarbeit bei Sicherheit und Handel wurde wieder aufgenommen.',ARRAY['AMERICAS-USA'],ARRAY['détente','detente','amends','meeting','reunión','encuentro','invit','pacto','acuerdo','visita','recibe','host','talks','deal'],true,ARRAY['Reuters','Associated Press','BBC World','Deutsche Welle','CNN','The Guardian','New York Times','France 24','France 24 (EN)','Le Monde','NPR','Euronews','Bloomberg','Financial Times','El País'],'colombia_us_alignment',1,'Negotiated rapprochement','Ausgehandelte Annäherung',1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('colombia_us_coercion','Threats replaced diplomacy','Drohungen ersetzten Diplomatie','The critical reading holds that an allied government was subjected to a threatened military operation, tariff pressure and sanctions designations over a policy dispute, and that Bogotá''s formal complaint marked a durable shift in what the relationship can be assumed to guarantee.','Die kritische Lesart hält fest, dass eine verbündete Regierung wegen eines politischen Streits mit einer angedrohten Militäroperation, Zolldruck und Sanktionslistungen überzogen wurde und dass Bogotás förmliche Beschwerde eine dauerhafte Verschiebung dessen markiert, was die Beziehung noch garantiert.',ARRAY['AMERICAS-USA'],ARRAY['threat','amenaza','military operation','operación militar','military action','tariff','arancel','sanction','sanción','sovereignty','soberan','complaint','queja','insult','slander'],true,ARRAY['Reuters','Associated Press','BBC World','Deutsche Welle','CNN','The Guardian','New York Times','France 24','France 24 (EN)','Le Monde','NPR','Euronews','Bloomberg','Financial Times','El País'],'colombia_us_alignment',2,'Coercion against a partner','Zwang gegen einen Partner', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('colombia_us_imperial_overreach','A sovereign state treated as a subordinate','Ein souveräner Staat als Untergebener behandelt','State and non-Western outlets present the episode as an assertion of hemispheric domination rather than a bilateral dispute: military threats against a sovereign government, coupled with strikes in neighbouring Venezuela, are framed as the working method of US regional primacy.','Staatliche und außerwestliche Medien stellen die Episode als Behauptung hemisphärischer Vorherrschaft dar und nicht als bilateralen Streit: Militärdrohungen gegen eine souveräne Regierung, verbunden mit Angriffen im benachbarten Venezuela, gelten als Arbeitsmethode US-amerikanischer Regionalvormacht.',ARRAY['AMERICAS-USA'],ARRAY['hegemon','imperial','sovereignty','soberan','interference','injerencia','domination','bullying','unilateral'],true,ARRAY['CGTN','China Daily','Global Times','Xinhua','RT','TASS','TASS (EN)','Sputnik','RIA Novosti','Press TV','Al Jazeera','Anadolu Agency','Al-Ahram'],'colombia_us_alignment',3,'Hegemonic imposition','Hegemoniale Anmaßung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cuba_pressure_justified','The instruments are aimed at a government that rules without consent','Die Instrumente richten sich gegen eine Regierung, die ohne Zustimmung herrscht','Sanctions, designations and criminal charges target a one-party leadership implicated in trafficking and repression -- the pressure is aimed at a government, not at a people it does not represent.','Sanktionen, Listungen und Strafverfahren richten sich gegen eine Einparteienführung, die in Schmuggel und Repression verstrickt ist -- der Druck zielt auf eine Regierung, nicht auf ein Volk, das sie nicht vertritt.',ARRAY['AMERICAS-USA','AMERICAS-CUBA'],ARRAY['castrismo','Castroism','dictad','dictat','ditadura','Diktatur','communist rule','one-party','partido único','must go','teetering','autocrat','narcotráfico','drug trafficking','murder charges','accountab','rendición de cuentas','sin consentimiento'],false,ARRAY['Fox News','Jerusalem Post','Reuters','Associated Press','BBC World','CNN','New York Times','Washington Post','The Guardian','NPR','MSNBC','ABC News','Sky News','The Telegraph','Bloomberg','Wall Street Journal','Financial Times','The Economist','Globe and Mail','France 24','France 24 (EN)','Euronews','Deutsche Welle','Tagesschau','Der Spiegel','Die Zeit','Le Monde','Le Figaro','Corriere della Sera','La Repubblica','Straits Times','El País','El Mundo','Clarín','La Nación','Reforma','El Universal','Folha de S.Paulo','O Globo','O Estado de S. Paulo'],'cuba_embargo_sanctions',1,'Aimed at the government','Gegen die Regierung gerichtet',1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cuba_sanctions_overreach','Extraterritorial sanctions are collective punishment','Extraterritoriale Sanktionen sind Kollektivstrafe','Secondary sanctions that force European shippers and hotel groups out and penalise third countries reach far beyond US jurisdiction, and the burden falls on ordinary Cubans rather than the government.','Sekundärsanktionen, die europäische Reedereien und Hotelgruppen zum Rückzug zwingen und Drittstaaten bestrafen, reichen weit über die US-Jurisdiktion hinaus -- und die Last tragen gewöhnliche Kubaner, nicht die Regierung.',ARRAY['NON-STATE-EU','AMERICAS-USA','AMERICAS-CUBA'],ARRAY['extraterritorial','overreach','collective punishment','castigo colectivo','Kollektivstrafe','secondary sanctions','third countries','terceros países','unilateral','einseitig','coercive','coerci','counterproductive','contraproducente','kontraproduktiv','condemn','verurteil','condena','economic bombing','chok','asfixia','asphyx','strangl','breaking point','völkerrechtswidrig'],true,ARRAY['Reuters','Associated Press','BBC World','CNN','New York Times','Washington Post','The Guardian','NPR','MSNBC','ABC News','Sky News','The Telegraph','Bloomberg','Wall Street Journal','Financial Times','The Economist','Globe and Mail','France 24','France 24 (EN)','Euronews','Deutsche Welle','Tagesschau','Der Spiegel','Die Zeit','Le Monde','Le Figaro','Corriere della Sera','La Repubblica','Straits Times','UN News','El País','El Mundo','Clarín','La Nación','Reforma','El Universal','Folha de S.Paulo','O Globo','O Estado de S. Paulo','Mexico News Daily'],'cuba_embargo_sanctions',2,'Extraterritorial overreach','Extraterritoriale Übergriffigkeit', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cuba_economic_warfare','The blockade is economic warfare against a sovereign nation','Die Blockade ist Wirtschaftskrieg gegen eine souveräne Nation','Washington''s siege is an illegal act of economic aggression, condemned year after year by the UN General Assembly, designed to break a country that refuses to submit.','Washingtons Belagerung ist ein illegaler Akt wirtschaftlicher Aggression, Jahr für Jahr von der UN-Generalversammlung verurteilt, um ein Land zu brechen, das sich nicht unterwirft.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA','AMERICAS-CUBA'],NULL,true,ARRAY['TASS (EN)','TASS','RT','Lenta.ru','Izvestia','Gazeta.ru','Kommersant','CGTN','China Daily','Global Times','Press TV','Al Jazeera','Al Arabiya','Al-Ahram','Anadolu Agency','TRT World','Daily Sabah'],'cuba_embargo_sanctions',3,'Economic warfare','Wirtschaftskrieg', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cuba_collapse_self_inflicted','Decades of mismanagement, not the blockade, emptied the grid','Jahrzehnte der Misswirtschaft, nicht die Blockade, haben das Netz geleert','A Soviet-era grid left unmaintained, a state-run economy that never generated hard currency and a refusal to reform are why the lights went out; external pressure only exposed a model that had already failed.','Ein nie instand gehaltenes Netz aus Sowjetzeiten, eine Staatswirtschaft ohne Devisen und die Verweigerung von Reformen sind der Grund für die Dunkelheit; äußerer Druck hat nur ein längst gescheitertes Modell offengelegt.',ARRAY['AMERICAS-CUBA'],ARRAY['mismanagement','Misswirtschaft','mala gestión','decades of','décadas','Soviet-era','ageing','aging','obsolet','envejec','decay','marode','veraltet','state-run','central planning','Planwirtschaft','self-inflicted','failed model','modelo fallido','fracas','failing','arruin','ineficien','castrismo','gescheitert'],false,ARRAY['Fox News','Jerusalem Post','Reuters','Associated Press','BBC World','CNN','New York Times','Washington Post','The Guardian','NPR','MSNBC','ABC News','Sky News','The Telegraph','Bloomberg','Wall Street Journal','Financial Times','The Economist','Globe and Mail','France 24','France 24 (EN)','Euronews','Deutsche Welle','Tagesschau','Der Spiegel','Die Zeit','Le Monde','Le Figaro','Corriere della Sera','La Repubblica','Straits Times','El País','El Mundo','Clarín','La Nación','Reforma','El Universal','Folha de S.Paulo','O Globo','O Estado de S. Paulo'],'cuba_energy_collapse',1,'Self-inflicted collapse','Selbstverschuldeter Zusammenbruch',1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cuba_collapse_humanitarian_alarm','A humanitarian emergency is unfolding whoever is to blame','Eine humanitäre Notlage entfaltet sich, gleich wer schuld ist','Hospitals without power, uncollected refuse, malnutrition and UN warnings of collapse describe a civilian emergency that has outrun the argument about its causes.','Kliniken ohne Strom, nicht abgeholter Müll, Mangelernährung und UN-Warnungen vor einem Zusammenbruch beschreiben eine zivile Notlage, die den Streit über ihre Ursachen längst überholt hat.',ARRAY['NON-STATE-EU','AMERICAS-CUBA'],ARRAY['humanitarian','humanitär','humanitaria','emergency','emergenc','Notlage','children are dying','civilians','Zivilisten','civiles','hospital','malnutrition','malnutri','hunger','hambre','Hunger','UN warns','catastroph','catástrofe','Katastroph','suffering','Leid','sufrimiento','desperate','desesper','misery','agoniz','asfixia','chok','breaking point','penuria'],true,ARRAY['Reuters','Associated Press','BBC World','CNN','New York Times','Washington Post','The Guardian','NPR','MSNBC','ABC News','Sky News','The Telegraph','Bloomberg','Wall Street Journal','Financial Times','The Economist','Globe and Mail','France 24','France 24 (EN)','Euronews','Deutsche Welle','Tagesschau','Der Spiegel','Die Zeit','Le Monde','Le Figaro','Corriere della Sera','La Repubblica','Straits Times','UN News','El País','El Mundo','Clarín','La Nación','Reforma','El Universal','Folha de S.Paulo','O Globo','O Estado de S. Paulo','Mexico News Daily'],'cuba_energy_collapse',2,'Humanitarian emergency','Humanitäre Notlage', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cuba_collapse_starvation_siege','Starvation by siege is a deliberate instrument of policy','Aushungern durch Belagerung ist ein bewusstes Instrument der Politik','Cutting a small island''s fuel until its hospitals go dark and its children go hungry is not a side effect but the objective -- collective punishment used to force political surrender.','Einer kleinen Insel den Treibstoff zu nehmen, bis ihre Kliniken dunkel werden und ihre Kinder hungern, ist keine Nebenwirkung, sondern das Ziel -- Kollektivstrafe zur Erzwingung politischer Kapitulation.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA','AMERICAS-CUBA'],NULL,true,ARRAY['TASS (EN)','TASS','RT','Lenta.ru','Izvestia','Gazeta.ru','Kommersant','CGTN','China Daily','Global Times','Press TV','Al Jazeera','Al Arabiya','Al-Ahram','Anadolu Agency','TRT World','Daily Sabah'],'cuba_energy_collapse',3,'Starvation as a weapon','Aushungern als Waffe', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cuba_lifelines_prop_up','Outside shipments prop up a government that would otherwise have to change','Lieferungen von außen stützen eine Regierung, die sich sonst ändern müsste','Russian and Venezuelan cargoes and third-country aid buy time for a leadership that has refused reform, blunting the only pressure that has ever moved it.','Russische und venezolanische Ladungen sowie Hilfe aus Drittstaaten verschaffen einer reformunwilligen Führung Zeit und stumpfen den einzigen Druck ab, der je etwas bewegt hat.',ARRAY['AMERICAS-CUBA','EUROPE-RUSSIA'],ARRAY['prop up','props up','apuntalar','stütz','undercut','circumvent','umgehen','evade','eludir','sanctions-busting','prolong','prolongar','verlängert','buy time','oxígeno','respiro','rescue','rescate','castrismo','dictad','ditadura'],false,ARRAY['Fox News','Jerusalem Post','Reuters','Associated Press','BBC World','CNN','New York Times','Washington Post','The Guardian','NPR','MSNBC','ABC News','Sky News','The Telegraph','Bloomberg','Wall Street Journal','Financial Times','The Economist','Globe and Mail','France 24','France 24 (EN)','Euronews','Deutsche Welle','Tagesschau','Der Spiegel','Die Zeit','Le Monde','Le Figaro','Corriere della Sera','La Repubblica','Straits Times','El País','El Mundo','Clarín','La Nación','Reforma','Folha de S.Paulo','O Globo','O Estado de S. Paulo'],'cuba_external_lifelines',1,'Propping up the government','Stützung der Regierung',1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cuba_lifelines_humanitarian_duty','Relief is a humanitarian obligation and third states should not be coerced','Hilfe ist eine humanitäre Pflicht, und Drittstaaten dürfen nicht genötigt werden','Mexico, Spain, Brazil and Canada are meeting an obligation to a population in crisis, and pressuring them to withhold fuel and food turns civilians into the instrument of a dispute between governments.','Mexiko, Spanien, Brasilien und Kanada erfüllen eine Pflicht gegenüber einer Bevölkerung in der Krise; sie zum Zurückhalten von Treibstoff und Nahrung zu drängen, macht Zivilisten zum Werkzeug eines Regierungsstreits.',ARRAY['AMERICAS-MEXICO','EUROPE-SOUTH','AMERICAS-CUBA'],ARRAY['humanitarian','obligation','must reach','blocked','hampers','dialogue','diplomatic path','sovereign right','solidarity','donate','relief effort','humanitär','Pflicht','Dialog','souverän','Solidarität','humanitaria','obligación','vía diplomática','diálogo','soberan','solidaridad','donar','debe llegar'],true,ARRAY['Reuters','Associated Press','BBC World','CNN','New York Times','Washington Post','The Guardian','NPR','MSNBC','ABC News','Sky News','The Telegraph','Bloomberg','Wall Street Journal','Financial Times','The Economist','Globe and Mail','France 24','France 24 (EN)','Euronews','Deutsche Welle','Tagesschau','Der Spiegel','Die Zeit','Le Monde','Le Figaro','Corriere della Sera','La Repubblica','Straits Times','UN News','El País','El Mundo','Clarín','La Nación','Reforma','El Universal','Folha de S.Paulo','O Globo','O Estado de S. Paulo','Mexico News Daily'],'cuba_external_lifelines',2,'Humanitarian obligation','Humanitäre Pflicht', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cuba_lifelines_solidarity','Solidarity with a besieged island against an illegal siege','Solidarität mit einer belagerten Insel gegen eine illegale Belagerung','Fuel, grain and credit sent in the face of US threats are acts of principled solidarity between sovereign states, and the attempt to stop them shows the siege was never about the Cuban people.','Treibstoff, Getreide und Kredite, die trotz US-Drohungen geschickt werden, sind Akte prinzipientreuer Solidarität zwischen souveränen Staaten; der Versuch, sie zu stoppen, zeigt, dass es bei der Belagerung nie um das kubanische Volk ging.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA','AMERICAS-CUBA'],NULL,true,ARRAY['TASS (EN)','TASS','RT','Lenta.ru','Izvestia','Gazeta.ru','Kommersant','CGTN','China Daily','Global Times','Press TV','Al Jazeera','Al Arabiya','Al-Ahram','Anadolu Agency','TRT World','Daily Sabah'],'cuba_external_lifelines',3,'Sovereign solidarity','Souveräne Solidarität', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cuba_force_credible_threat','A credible threat of force is what brought Havana to the table','Eine glaubwürdige Drohung mit Gewalt hat Havanna an den Tisch gebracht','Carrier deployments and reconnaissance flights are signalling, not war -- and the shift from refusal to negotiation followed them, as did Havana''s own escalatory plotting.','Trägerverlegungen und Aufklärungsflüge sind Signale, kein Krieg -- und der Wechsel von Verweigerung zu Verhandlung folgte auf sie, ebenso wie Havannas eigene Eskalationspläne.',ARRAY['AMERICAS-USA','AMERICAS-CUBA'],ARRAY['credible','glaubwürdig','all options','alle Optionen','military option','opción militar','deterren','Abschreckung','disuasión','brought to the table','teetering','provocation','Provokation','provocación','drone attack','plotting','threat to the US','amenaza para'],false,ARRAY['Fox News','Jerusalem Post','Reuters','Associated Press','BBC World','CNN','New York Times','Washington Post','The Guardian','NPR','MSNBC','ABC News','Sky News','The Telegraph','Bloomberg','Wall Street Journal','Financial Times','The Economist','Globe and Mail','France 24','France 24 (EN)','Euronews','Deutsche Welle','Tagesschau','Der Spiegel','Die Zeit','Le Monde','Le Figaro','Corriere della Sera','La Repubblica','Straits Times','El País','El Mundo','Clarín','La Nación','Reforma','Folha de S.Paulo','O Globo','O Estado de S. Paulo'],'cuba_military_coercion',1,'Credible deterrence','Glaubwürdige Abschreckung',1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cuba_force_unlawful','Threatening to take an island is unlawful and reckless','Die Drohung, eine Insel zu nehmen, ist rechtswidrig und leichtsinnig','There is no congressional authorisation, no legal basis for seizing a sovereign state, and every historical precedent from the Bay of Pigs onward points to a costly failure.','Es gibt keine Ermächtigung des Kongresses, keine Rechtsgrundlage für die Inbesitznahme eines souveränen Staates, und jeder historische Präzedenzfall seit der Schweinebucht deutet auf ein teures Scheitern.',ARRAY['NON-STATE-EU','AMERICAS-USA','AMERICAS-CUBA'],ARRAY['unlawful','illegal','without authorisation','without authorization','war powers','no congressional','Bay of Pigs','quagmire','bloodbath','reckless','rechtswidrig','ohne Mandat','Kriegsvollmachten','Schweinebucht','leichtsinnig','Blutbad','ilegal','sin autorización','Bahía de Cochinos','baño de sangre','imprudente'],true,ARRAY['Reuters','Associated Press','BBC World','CNN','New York Times','Washington Post','The Guardian','NPR','MSNBC','ABC News','Sky News','The Telegraph','Bloomberg','Wall Street Journal','Financial Times','The Economist','Globe and Mail','France 24','France 24 (EN)','Euronews','Deutsche Welle','Tagesschau','Der Spiegel','Die Zeit','Le Monde','Le Figaro','Corriere della Sera','La Repubblica','Straits Times','UN News','El País','El Mundo','Clarín','La Nación','Reforma','El Universal','Folha de S.Paulo','O Globo','O Estado de S. Paulo','Mexico News Daily'],'cuba_military_coercion',2,'Unlawful and reckless','Rechtswidrig und leichtsinnig', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cuba_force_imperial_aggression','Gunboat diplomacy against a small neighbour is imperial aggression','Kanonenbootpolitik gegen einen kleinen Nachbarn ist imperiale Aggression','Moving a carrier group into the Caribbean and openly discussing seizing an island revives the crudest form of hemispheric domination, whatever pretext is offered.','Eine Trägergruppe in die Karibik zu verlegen und offen über die Inbesitznahme einer Insel zu sprechen, belebt die roheste Form hemisphärischer Vorherrschaft -- unter welchem Vorwand auch immer.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA','AMERICAS-CUBA'],NULL,true,ARRAY['TASS (EN)','TASS','RT','Lenta.ru','Izvestia','Gazeta.ru','Kommersant','CGTN','China Daily','Global Times','Press TV','Al Jazeera','Al Arabiya','Al-Ahram','Anadolu Agency','TRT World','Daily Sabah'],'cuba_military_coercion',3,'Imperial aggression','Imperiale Aggression', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cuba_repression_documented','One-party rule holds by arresting those who protest','Die Einparteienherrschaft hält sich, indem sie Protestierende verhaftet','Arrests after blackout protests, political prisoners used as bargaining chips and a party that permits no alternative describe control maintained by coercion, not consent.','Verhaftungen nach Protesten gegen Stromausfälle, politische Gefangene als Verhandlungsmasse und eine Partei, die keine Alternative zulässt, beschreiben Kontrolle durch Zwang, nicht durch Zustimmung.',ARRAY['AMERICAS-CUBA'],ARRAY['political prisoner','preso polític','presos polític','dissident','disidente','arrest','arrestan','detien','detenid','encarcel','jailed','crackdown','one-party','partido único','censorship','censur','repress','repres','bargaining chip','politische Gefangene','inhaftiert','verhaftet','Einparteien','Zensur','castrismo','dictad'],true,ARRAY['Fox News','Jerusalem Post','Reuters','Associated Press','BBC World','CNN','New York Times','Washington Post','The Guardian','NPR','MSNBC','ABC News','Sky News','The Telegraph','Bloomberg','Wall Street Journal','Financial Times','The Economist','Globe and Mail','France 24','France 24 (EN)','Euronews','Deutsche Welle','Tagesschau','Der Spiegel','Die Zeit','Le Monde','Le Figaro','Corriere della Sera','La Repubblica','Straits Times','El País','El Mundo','Clarín','La Nación','Reforma','Folha de S.Paulo','O Globo','O Estado de S. Paulo'],'cuba_regime_survival',1,'Rule by repression','Herrschaft durch Repression',1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cuba_reform_under_siege','A real opening is under way but external pressure is throttling it','Eine echte Öffnung läuft, doch äußerer Druck erstickt sie','The largest economic liberalisation since 1959 and the release of thousands of prisoners are genuine movement -- and the pressure campaign gives hardliners the argument that opening invites attack.','Die größte wirtschaftliche Liberalisierung seit 1959 und die Freilassung Tausender Gefangener sind echte Bewegung -- und die Druckkampagne liefert Hardlinern das Argument, Öffnung lade Angriffe ein.',ARRAY['AMERICAS-CUBA'],ARRAY['reform','liberalis','liberaliz','opening','private sector','released','freed','pardon','largest package','genuine','Reform','Öffnung','Privatsektor','freigelassen','Begnadigung','reforma','apertura','excarcela','liberad','indulto','sector privado'],true,ARRAY['Reuters','Associated Press','BBC World','CNN','New York Times','Washington Post','The Guardian','NPR','MSNBC','ABC News','Sky News','The Telegraph','Bloomberg','Wall Street Journal','Financial Times','The Economist','Globe and Mail','France 24','France 24 (EN)','Euronews','Deutsche Welle','Tagesschau','Der Spiegel','Die Zeit','Le Monde','Le Figaro','Corriere della Sera','La Repubblica','Straits Times','UN News','El País','El Mundo','Clarín','La Nación','Reforma','El Universal','Folha de S.Paulo','O Globo','O Estado de S. Paulo','Mexico News Daily'],'cuba_regime_survival',2,'Reform throttled by pressure','Reform durch Druck erstickt', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cuba_sovereign_resistance','A sovereign people is resisting an externally engineered regime change','Ein souveränes Volk widersteht einem von außen betriebenen Regimewechsel','What is called repression is a state defending itself against infiltration, sabotage and an openly declared campaign to remove its government -- self-determination is the issue, not dissent.','Was Repression genannt wird, ist ein Staat, der sich gegen Infiltration, Sabotage und eine offen erklärte Kampagne zum Sturz seiner Regierung verteidigt -- es geht um Selbstbestimmung, nicht um Dissens.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA','AMERICAS-CUBA'],NULL,true,ARRAY['TASS (EN)','TASS','RT','Lenta.ru','Izvestia','Gazeta.ru','Kommersant','CGTN','China Daily','Global Times','Press TV','Al Jazeera','Al Arabiya','Al-Ahram','Anadolu Agency','TRT World','Daily Sabah'],'cuba_regime_survival',3,'Sovereign resistance','Souveräner Widerstand', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cuba_theater_pressure_consensus','The government, not the blockade, is what has to change','Die Regierung, nicht die Blockade, muss sich ändern','A one-party leadership that jails its critics, has run its economy into the ground and refuses to give up power is the reason the island is in this position -- and the reason pressure keeps being applied.','Eine Einparteienführung, die ihre Kritiker einsperrt, die Wirtschaft ruiniert hat und die Macht nicht abgeben will, ist der Grund für die Lage der Insel -- und der Grund, warum weiter Druck ausgeübt wird.',ARRAY['AMERICAS-USA','AMERICAS-CUBA'],NULL,true,ARRAY['Fox News','Jerusalem Post','Reuters','Associated Press','BBC World','CNN','New York Times','Washington Post','The Guardian','NPR','MSNBC','ABC News','Sky News','The Telegraph','Bloomberg','Wall Street Journal','Financial Times','The Economist','Globe and Mail','France 24','France 24 (EN)','Euronews','Deutsche Welle','Tagesschau','Der Spiegel','Die Zeit','Le Monde','Le Figaro','Corriere della Sera','La Repubblica','Straits Times','El País','El Mundo','Clarín','La Nación','Reforma','El Universal','Folha de S.Paulo','O Globo','O Estado de S. Paulo','Mexico News Daily','UN News'],'cuba_theater',1,'The government is the problem','Die Regierung ist das Problem',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cuba_theater_western_critique','The pressure campaign has become a humanitarian and legal problem of its own','Die Druckkampagne ist selbst zu einem humanitären und rechtlichen Problem geworden','Extraterritorial sanctions on third countries, an island without electricity or medicine, and open talk of seizing a sovereign state have moved the campaign past what its own stated aims can justify.','Extraterritoriale Sanktionen gegen Drittstaaten, eine Insel ohne Strom und Medikamente und offenes Gerede über die Inbesitznahme eines souveränen Staates haben die Kampagne über das hinausgeführt, was ihre erklärten Ziele rechtfertigen.',ARRAY['NON-STATE-EU','AMERICAS-CUBA'],NULL,true,ARRAY['Reuters','Associated Press','BBC World','CNN','New York Times','Washington Post','The Guardian','NPR','MSNBC','ABC News','Sky News','The Telegraph','Bloomberg','Wall Street Journal','Financial Times','The Economist','Globe and Mail','France 24','France 24 (EN)','Euronews','Deutsche Welle','Tagesschau','Der Spiegel','Die Zeit','Le Monde','Le Figaro','Corriere della Sera','La Repubblica','Straits Times','UN News','El País','El Mundo','Clarín','La Nación','Reforma','El Universal','Folha de S.Paulo','O Globo','O Estado de S. Paulo','Mexico News Daily'],'cuba_theater',2,'Overreach and human cost','Übergriffigkeit und menschliche Kosten', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('cuba_theater_anti_imperial','A siege to break a sovereign nation that refuses to submit','Eine Belagerung, um eine souveräne Nation zu brechen, die sich nicht unterwirft','Fuel cut off, warships offshore, a former head of state indicted and allies punished for sending aid -- this is coercion of a small country for refusing hemispheric obedience, and solidarity with it is a defence of sovereignty itself.','Abgeschnittener Treibstoff, Kriegsschiffe vor der Küste, ein angeklagter früherer Staatschef und für Hilfslieferungen bestrafte Verbündete -- das ist Nötigung eines kleinen Landes für verweigerten hemisphärischen Gehorsam, und Solidarität mit ihm verteidigt die Souveränität selbst.',ARRAY['EUROPE-RUSSIA','ASIA-CHINA','AMERICAS-CUBA'],NULL,true,ARRAY['TASS (EN)','TASS','RT','Lenta.ru','Izvestia','Gazeta.ru','Kommersant','CGTN','China Daily','Global Times','Press TV','Al Jazeera','Al Arabiya','Al-Ahram','Anadolu Agency','TRT World','Daily Sabah'],'cuba_theater',3,'Siege and sovereignty','Belagerung und Souveränität', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('drc_minerals_as_development','Capital arriving at last','Kapital, das endlich ankommt','Demand for battery and data-centre metals is finally being converted into Congolese assets: a state mining champion under new leadership, a distressed cobalt producer rescued by an American buyer, exploration money flowing into lithium, copper exports to the United States multiplying, a reopened corridor to Zambian ports and a first domestic stock exchange. Export controls are treated here as a producer country learning to price what it owns.','Die Nachfrage nach Batterie- und Rechenzentrumsmetallen wird endlich in kongolesische Werte umgesetzt: ein staatlicher Bergbaukonzern unter neuer Führung, ein angeschlagener Kobaltproduzent durch einen amerikanischen Käufer gerettet, Explorationsgelder für Lithium, vervielfachte Kupferexporte in die USA, ein wieder geöffneter Korridor zu sambischen Häfen und eine erste eigene Börse. Exportkontrollen gelten hier als ein Förderland, das lernt, seinen Besitz zu bepreisen.',ARRAY['AFRICA-DRC','AMERICAS-USA'],ARRAY['deal','agreement','investment','invest','stake','boom','growth','exploration','approve','approved','takeover','acquisition','corridor','stock market','exports','reopen','investissement','croissance','exportations','Investition','Wachstum','Übernahme','Ausfuhren'],true,ARRAY['Mining.com','Bloomberg','Financial Times','S&P Global','OilPrice','News24','Reuters','The Australian','Egypt Today'],'drc_minerals_competition',1,'Investment and leverage','Investitionen und Verhandlungsmacht',2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('drc_minerals_human_cost','The price is paid at the pit','Bezahlt wird an der Grube','The same supply chain that supplies the energy transition also produces two hundred dead in a single coltan collapse, a town reporting bleeding children after a cobalt plant leak, and consumer brands that cannot demonstrate their metal did not finance an armed group. Buyers describe their own due diligence as failing: deposits offered to foreign investors sit inside contested territory, and the paperwork does not survive contact with the pit.','Dieselbe Lieferkette, die die Energiewende speist, produziert auch zweihundert Tote bei einem einzigen Coltan-Einsturz, eine Stadt mit blutenden Kindern nach einem Leck in einer Kobaltanlage und Markenhersteller, die nicht belegen können, dass ihr Metall keine bewaffnete Gruppe finanziert hat. Die Abnehmer bezeichnen ihre eigene Sorgfaltsprüfung als unzureichend: Vorkommen, die ausländischen Investoren angeboten werden, liegen in umkämpftem Gebiet, und die Papiere halten dem Vergleich mit der Grube nicht stand.',ARRAY['AFRICA-DRC'],ARRAY['toxic','sickened','poison','gas leak','waste','collapse','landslide','killed','dead','buried','child','children','artisanal','funds rebels','atrocities','war zone','de-risk','due diligence','human rights','exploitation','toxique','rejets','éboulement','glissement de terrain','morts','enfants','artisanale','droits humains','giftig','Einsturz','Erdrutsch','Tote','Kinderarbeit','Menschenrechte'],true,ARRAY['The Guardian','Wall Street Journal','Le Monde','France 24','France 24 (EN)','Deutsche Welle','Associated Press','BBC World','BBC','Al Jazeera','Folha de S.Paulo','Council on Foreign Relations','Globe and Mail','La Repubblica','Press TV','DR'],'drc_minerals_competition',2,'Human and environmental cost','Menschliche und ökologische Kosten', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('drc_minerals_as_resource_capture','A takeover of an established position','Übernahme einer gewachsenen Position','Seen from the incumbent side, the American entry is not new investment but the displacement of partners who built the refining and processing base over two decades, achieved through political leverage rather than commercial performance. Deposits are being tied to security guarantees, state mining leadership replaced during negotiations, and a producer country pressed into an exclusive alignment while its own officials call the terms constitutionally doubtful.','Aus Sicht der etablierten Seite ist der amerikanische Einstieg keine neue Investition, sondern die Verdrängung von Partnern, die über zwei Jahrzehnte die Raffinerie- und Verarbeitungsbasis aufgebaut haben -- erreicht durch politischen Druck, nicht durch wirtschaftliche Leistung. Vorkommen werden an Sicherheitsgarantien geknüpft, die staatliche Bergbauführung während der Verhandlungen ausgetauscht und ein Förderland in eine exklusive Bindung gedrängt, während eigene Amtsträger die Bedingungen für verfassungsrechtlich zweifelhaft halten.',ARRAY['AFRICA-DRC','ASIA-CHINA'],ARRAY['grab','capture','seize','exclusive','displace','squeeze out','leverage','unconstitutional','flawed','sovereignty','neocolonial','neo-colonial','plunder','scramble','strings attached','inconstitutionnel','souveraineté','néocolonial','pillage','verfassungswidrig','Souveränität','neokolonial','Ausplünderung'],true,ARRAY['Daily Nation','Daily Maverick','CGTN','Global Times','China Daily','Xinhua','RT','TASS','TASS (EN)','Sputnik','RIA Novosti'],'drc_minerals_competition',3,'Displacement of incumbents','Verdrängung der Etablierten', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('drc_accords_are_working','The accords are the route out of the war','Die Abkommen sind der Weg aus dem Krieg','External mediation is producing things the battlefield never did: a signed monitoring mechanism, prisoners released, humanitarian access agreed within fixed deadlines, and a commitment from both sides to protect civilians. Kinshasa is explicitly betting on the Washington track to secure the east, and the monitoring mission is being rebuilt around supporting the ceasefire rather than fighting a war.','Die externe Vermittlung bringt hervor, was das Schlachtfeld nie erreicht hat: einen unterzeichneten Überwachungsmechanismus, freigelassene Gefangene, humanitären Zugang mit festen Fristen und die Zusage beider Seiten, Zivilisten zu schützen. Kinshasa setzt ausdrücklich auf den Washingtoner Weg, um den Osten zu sichern, und die Beobachtermission wird darauf ausgerichtet, den Waffenstillstand zu stützen statt Krieg zu führen.',ARRAY['AFRICA-DRC','AMERICAS-USA'],ARRAY['signed','commit','commitment','progress','monitoring','release','released','prisoners','facilitate','de-escalate','breakthrough','mechanism','secure','chance','advance','prepares to support','deploy','signé','engagement','progrès','libérer','libération','faciliter','désescalade','sécuriser','compte sur','unterzeichnet','Fortschritt','Freilassung','Deeskalation','Chance'],true,ARRAY['France 24','France 24 (EN)','Le Monde','Reuters','Associated Press','Swissinfo','news.un.org','UN News','Al Jazeera','Anadolu Agency','Deutsche Welle','The Standard','Daily Nation','ANSA'],'drc_peace_process',1,'Mediation is delivering','Vermittlung zeigt Wirkung',2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('drc_accords_stalling','Signed, stalled, and unenforced','Unterzeichnet, blockiert, nicht durchgesetzt','The documents exist and the fighting continues. Peace deals are described by Kinshasa''s own spokesman as blocked by the conduct of the Rwandan president; the two sides trade accusations over a ceasefire neither observes; attacks continue while talks sit in Switzerland. Sanctions arrive after violations rather than preventing them, which makes the accords a record of intentions rather than a constraint on behaviour.','Die Dokumente existieren, die Kämpfe gehen weiter. Friedensabkommen werden vom Sprecher Kinshasas selbst als blockiert durch das Verhalten des ruandischen Präsidenten beschrieben; beide Seiten werfen einander Verstöße gegen einen Waffenstillstand vor, den keine Seite einhält; Angriffe dauern an, während in der Schweiz verhandelt wird. Sanktionen folgen den Verstößen, statt sie zu verhindern -- die Abkommen sind damit eher ein Protokoll von Absichten als eine Schranke für das Handeln.',ARRAY['AFRICA-DRC'],ARRAY['stalled','stalling','stagnate','stagnant','no progress','violation','violating','violated','accuses','accusations','breach','collapse','fragile','delay','delayed','persists','stagnent','bloqué','s''enlise','n''avance pas','violation','accuse','accusations','retard','ins Stocken','blockiert','Verstoß','Verzögerung','wirft vor'],true,ARRAY['France 24','France 24 (EN)','Le Monde','Le Figaro','Reuters','Associated Press','The Guardian','BBC World','Deutsche Welle','Washington Post','Financial Times','news.un.org','UN News','Al Jazeera','Anadolu Agency','Daily Sabah','The Standard','Daily Nation','Janes'],'drc_peace_process',2,'The process is not holding','Der Prozess trägt nicht', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('drc_sanctions_as_enforcement','Designations as the only real leverage','Listungen als einziges echtes Druckmittel','With no force willing to impose the accords on the ground, financial and travel designations have become the instrument that carries actual cost: the Rwandan army and its senior commanders listed, visa restrictions placed on Rwandan officials, and a former Congolese president designated over his support for the rebellion. Analysts read the move against Kigali as the sharpest turn in the conflict''s external handling to date.','Da keine Truppe bereit ist, die Abkommen vor Ort durchzusetzen, sind Finanz- und Reisebeschränkungen zum einzigen Instrument mit realen Kosten geworden: die ruandische Armee und ihre ranghohen Kommandeure gelistet, Visasperren gegen ruandische Amtsträger, und ein früherer kongolesischer Präsident wegen seiner Unterstützung der Rebellion benannt. Beobachter werten das Vorgehen gegen Kigali als die schärfste Wende im äußeren Umgang mit diesem Konflikt bislang.',ARRAY['AFRICA-DRC','AMERICAS-USA'],ARRAY['sanction','sanctions','sanctioned','designat','visa restriction','listed','penalt','asset freeze','sanctionne','sanctionné','sanctions','restrictions de visa','Sanktionen','sanktioniert','Einreiseverbot'],true,ARRAY['France 24','France 24 (EN)','Le Monde','Le Figaro','Reuters','Associated Press','The Guardian','BBC World','BBC','Deutsche Welle','Washington Post','Financial Times','Al Jazeera','Daily Nation','Punch Newspapers'],'drc_peace_process',3,'Enforcement by designation','Durchsetzung durch Listung',1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('drc_mediation_as_interference','Peacemaking with a price tag','Friedensstiftung mit Preisschild','The mediation is read here as leverage rather than diplomacy: a settlement brokered by the same power that is negotiating access to Congolese deposits, with sanctions used as the instrument of pressure and African sovereignty as the cost. On this account the accords are less a peace framework than the political wrapper around a resource arrangement, and the states applying the pressure are parties to the outcome rather than neutral arbiters.','Die Vermittlung wird hier als Druckmittel gelesen, nicht als Diplomatie: eine Regelung, vermittelt von derselben Macht, die zugleich über den Zugang zu kongolesischen Vorkommen verhandelt, mit Sanktionen als Druckinstrument und afrikanischer Souveränität als Preis. In dieser Lesart sind die Abkommen weniger ein Friedensrahmen als die politische Verpackung einer Rohstoffvereinbarung, und die Druck ausübenden Staaten sind Partei, nicht neutrale Schiedsrichter.',ARRAY['AFRICA-DRC','AMERICAS-USA'],ARRAY['interference','meddling','neocolonial','neo-colonial','imperial','exploitation','resource grab','unilateral','pressure','hegemony','so-called','double standard','ingérence','néocolonial','impérial','pression','unilatéral','Einmischung','neokolonial','Druck','Doppelmoral'],false,ARRAY['RT','TASS','TASS (EN)','Sputnik','RIA Novosti','Press TV','CGTN','Global Times','China Daily'],'drc_peace_process',3,'Pressure dressed as mediation','Druck im Gewand der Vermittlung', -2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('drc_sanctions_rejected','The designated parties reject the designations','Die Gelisteten weisen die Listungen zurück','Those named in the measures dispute both their basis and their effect. Kigali presents the designations as insults that will not alter Rwandan defence policy, and the former Congolese president describes his own listing as unjustified. On this reading the sanctions are an external actor taking sides in a regional dispute it does not fully understand, rather than a neutral enforcement of an agreement.','Die Benannten bestreiten sowohl die Grundlage als auch die Wirkung der Maßnahmen. Kigali stellt die Listungen als Beleidigungen dar, die an Ruandas Verteidigungspolitik nichts ändern, und der frühere kongolesische Präsident nennt seine eigene Listung ungerechtfertigt. In dieser Lesart ergreift ein externer Akteur Partei in einem regionalen Streit, den er nicht vollständig überblickt, statt ein Abkommen neutral durchzusetzen.',ARRAY['AFRICA-DRC'],ARRAY['denies','denied','denounces','denounced','rejects','rejected','unjustified','unfounded','hits back','insults','sovereignty','internal affairs','dément','rejette','dénonce','injustifié','souveraineté','weist zurück','bestreitet','ungerechtfertigt','Souveränität'],true,ARRAY['The Standard','Anadolu Agency','Al-Ahram','Mail & Guardian','News24','TRT World','Daily Sabah','RT','TASS','TASS (EN)','Sputnik'],'drc_peace_process',4,'The designations are rejected','Die Listungen werden zurückgewiesen', -2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('ethiopia_partnership_normalisation','Tensions overstated, partnership continues','Überzeichnete Spannungen, fortgesetzte Partnerschaft','Reports of an imminent northern war are exaggerated and often denied by the parties themselves; flights and administration are being restored, and Ethiopia remains a functioning partner for investment, infrastructure and trade regardless of the diplomatic noise around it.','Berichte über einen unmittelbar bevorstehenden Krieg im Norden sind übertrieben und werden von den Beteiligten selbst dementiert. Flugverbindungen und Verwaltung werden wiederhergestellt, und Äthiopien bleibt ungeachtet des diplomatischen Lärms ein funktionierender Partner für Investitionen, Infrastruktur und Handel.',ARRAY['AFRICA-HORN','ASIA-CHINA'],ARRAY['denies','untrue','resume','restore','cooperation','investment','partnership','development','dementiert','Zusammenarbeit','Wiederaufnahme'],false,ARRAY['CGTN','China Daily','Global Times','RT','TASS (EN)','Xinhua','ANSA'],'ethiopia_regional_confrontation',1,'Tensions are overstated','Die Spannungen sind überzeichnet',1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('ethiopia_renewed_war_alarm','A second northern war in the making','Ein zweiter Krieg im Norden bahnt sich an','The Pretoria settlement is unravelling: the Tigrayan party has restored its pre-war administration, drones are striking again, Eritrean troops are accused of crossing the border, and an election that excluded Tigray has removed the last political off-ramp.','Das Abkommen von Pretoria zerfällt: Die tigrayische Partei hat ihre Vorkriegsverwaltung wiederhergestellt, es fliegen wieder Drohnenangriffe, eritreischen Truppen wird ein Grenzübertritt vorgeworfen, und eine Wahl unter Ausschluss Tigrays hat den letzten politischen Ausweg beseitigt.',ARRAY['AFRICA-HORN'],ARRAY['brink','war','fears','renewed','clashes','drone','atrocities','massacre','accountability','excluded','withdrawal','incursion','Krieg','Eskalation','Gräueltaten','Rechenschaft'],true,ARRAY['Reuters','BBC World','BBC','AFP','AFP Fact Check','Deutsche Welle','France 24','France 24 (EN)','The Economist','Associated Press','The Guardian','Le Monde','Atlantic Council','Daily Nation','News24','UN News','Bloomberg','CNN','Al Jazeera','Anadolu Agency','TRT World','Japan Times','Straits Times','The Standard'],'ethiopia_regional_confrontation',2,'Alarm at a returning war','Alarm vor einem wiederkehrenden Krieg', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('ethiopia_regional_revisionism','A revisionist power destabilising the region','Eine revisionistische Macht destabilisiert die Region','Addis Ababa''s pursuit of a seaport and its unilateral control of the Nile dam are expansionist demands on its neighbours'' sovereignty, and the deepening Egyptian partnerships with Eritrea, Djibouti and Somalia are a legitimate defensive response to them.','Addis Abebas Streben nach einem Seehafen und seine einseitige Kontrolle über den Nilstaudamm sind expansionistische Ansprüche gegenüber der Souveränität seiner Nachbarn. Die vertieften ägyptischen Partnerschaften mit Eritrea, Dschibuti und Somalia sind eine legitime Antwort darauf.',ARRAY['AFRICA-HORN','MIDEAST-EGYPT'],ARRAY['expansionist','sovereignty','water','dam','GERD','Nile','isolate','parallel entities','littoral','Souveränität','Nil','Staudamm','expansionistisch'],true,ARRAY['Al-Ahram','Egypt Today','The National'],'ethiopia_regional_confrontation',3,'Ethiopia is the destabiliser','Äthiopien ist der Destabilisator', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('great_lakes_engagement_working','Outside engagement is starting to bite','Auswärtiges Engagement beginnt zu wirken','After years in which external actors declared concern and did little, the instruments finally have teeth: a monitoring mechanism signed in Switzerland, prisoners released and humanitarian corridors agreed, financial designations placed on a neighbouring army and on a former head of state, and capital moving into Congolese mining assets rather than around them. Engagement of this kind is treated as the one lever that has moved anything.','Nach Jahren, in denen äußere Akteure Besorgnis erklärten und wenig taten, haben die Instrumente endlich Wirkung: ein in der Schweiz unterzeichneter Überwachungsmechanismus, freigelassene Gefangene und vereinbarte humanitäre Korridore, Finanzlistungen gegen eine Nachbararmee und einen früheren Staatschef, und Kapital, das in kongolesische Bergbauwerte fließt statt an ihnen vorbei. Ein solches Engagement gilt als der einzige Hebel, der überhaupt etwas bewegt hat.',ARRAY['AFRICA-DRC','AMERICAS-USA'],ARRAY['signed','agreement','progress','release','investment','stake','sanctions','designat','monitoring','corridor','accord','signé','progrès','investissement','Abkommen','Fortschritt','Investition'],true,ARRAY['Mining.com','Bloomberg','S&P Global','OilPrice','The Australian','Egypt Today','France 24','France 24 (EN)','Le Monde','Le Figaro','Reuters','Associated Press','The Guardian','BBC','BBC World','Deutsche Welle','Washington Post','Financial Times','Al Jazeera','Swissinfo','ANSA','news.un.org','UN News','News24','Daily Nation','Punch Newspapers'],'great_lakes_theater',1,'Engagement is delivering','Engagement zeigt Wirkung',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('great_lakes_proxy_war_and_its_costs','A cross-border war paid for by civilians','Ein grenzüberschreitender Krieg, den Zivilisten bezahlen','The dominant international reading treats the fighting in the east as one system rather than several problems: an insurgency sustained from across a border, a mediation track that is signed but not observed, and an extraction economy that runs through the same contested ground. What connects them is who absorbs the cost -- populations detained in captured towns, displaced across borders, killed by strikes meant for combatants, or buried in a collapsed mine on territory the armed group controls.','Die vorherrschende internationale Lesart behandelt die Kämpfe im Osten als ein System, nicht als mehrere Probleme: ein von jenseits der Grenze getragener Aufstand, ein Vermittlungsweg, der unterzeichnet, aber nicht eingehalten wird, und eine Rohstoffwirtschaft, die durch dasselbe umkämpfte Gebiet läuft. Verbunden sind sie durch die Frage, wer die Kosten trägt -- Menschen, die in eroberten Städten festgehalten, über Grenzen vertrieben, von Angriffen auf Kombattanten getötet oder in einer eingestürzten Mine im Gebiet der bewaffneten Gruppe verschüttet werden.',ARRAY['AFRICA-DRC'],ARRAY['civilians','displaced','killed','abuse','atrocities','backing','proxy','stalled','violation','toxic','collapse','civils','déplacés','atrocités','soutien','éboulement','Zivilisten','Vertriebene','Unterstützung','Gräueltaten'],true,ARRAY['France 24','France 24 (EN)','Le Monde','Le Figaro','Reuters','Associated Press','The Guardian','BBC','BBC World','Deutsche Welle','Washington Post','Financial Times','The Economist','Al Jazeera','Daily Sabah','TRT World','Punch Newspapers','Swissinfo','ANSA','La Repubblica','Der Spiegel','Folha de S.Paulo','Globe and Mail','Wall Street Journal','Council on Foreign Relations','Janes','DR','news.un.org','UN News'],'great_lakes_theater',2,'Proxy war and human cost','Stellvertreterkrieg und menschliche Kosten', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('great_lakes_scepticism_of_outside_fixes','African scepticism about externally designed fixes','Afrikanische Skepsis gegenüber extern entworfenen Lösungen','Regional and African coverage is markedly cooler about solutions drafted elsewhere. The accords are reported as documents both sides accuse each other of breaking, the designations as measures the targeted governments simply reject, and the minerals arrangement as terms a neighbouring energy minister publicly contests and a Congolese figure calls constitutionally doubtful. The common thread is a question about who wrote the terms and who carries the consequences.','Die regionale und afrikanische Berichterstattung ist deutlich kühler gegenüber Lösungen, die anderswo entworfen wurden. Die Abkommen erscheinen als Dokumente, deren Bruch sich beide Seiten gegenseitig vorwerfen, die Listungen als Maßnahmen, die die betroffenen Regierungen schlicht zurückweisen, und die Rohstoffvereinbarung als Konditionen, die ein Energieminister des Nachbarlands öffentlich bestreitet und ein kongolesischer Akteur für verfassungsrechtlich zweifelhaft hält. Verbindend ist die Frage, wer die Bedingungen geschrieben hat und wer die Folgen trägt.',ARRAY['AFRICA-DRC'],ARRAY['rejects','denounces','unjustified','unconstitutional','flawed','clashes with','sovereignty','accusations','trade accusations','souveraineté','injustifié','Souveränität','ungerechtfertigt'],true,ARRAY['The Standard','Daily Nation','Daily Maverick','Mail & Guardian','News24','Al-Ahram'],'great_lakes_theater',3,'Scepticism about outside terms','Skepsis gegenüber fremden Bedingungen', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('horn_new_partnerships','New partnerships remaking the Horn','Neue Partnerschaften ordnen das Horn neu','A long-frozen map is finally moving: recognition, basing agreements and minerals deals are creating relationships that the old insistence on inherited borders had blocked for decades.','Eine lange eingefrorene Landkarte kommt in Bewegung: Anerkennung, Stützpunktabkommen und Rohstoffverträge schaffen Beziehungen, die das alte Beharren auf ererbten Grenzen jahrzehntelang verhindert hatte.',ARRAY['AFRICA-HORN','MIDEAST-ISRAEL'],ARRAY['recognition','historic','partnership','agreement','minerals','Anerkennung','Partnerschaft'],true,ARRAY['Jerusalem Post','Times of Israel','i24NEWS','Haaretz','News24'],'horn_africa_theater',1,'Realignment as opportunity','Neuordnung als Chance',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('horn_regional_stabilisers','Regional partners rebuilding state capacity','Regionale Partner bauen Staatlichkeit wieder auf','Turkish, Gulf and East African engagement is doing the unglamorous work of reconstituting functioning states in the Horn -- training armies, drilling for energy, reopening borders and trade.','Türkisches, arabisches und ostafrikanisches Engagement leistet die unspektakuläre Arbeit, funktionierende Staaten am Horn wiederherzustellen: Armeen ausbilden, Energie erschließen, Grenzen und Handel wieder öffnen.',ARRAY['AFRICA-HORN','MIDEAST-TURKEY','MIDEAST-EGYPT'],ARRAY['transformation','renewal','institutions','cooperation','partnership','training','trade','Wiederaufbau','Partnerschaft'],true,ARRAY['Anadolu Agency','Daily Sabah','TRT World','Daily Nation','The Standard','Egypt Today','Al-Ahram','ANSA'],'horn_africa_theater',2,'Stabilisation through partnership','Stabilisierung durch Partnerschaft',1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('horn_western_alarm','Western alarm at fragmentation and famine','Westliche Alarmrufe über Zerfall und Hungersnot','Reporting from Western outlets and UN agencies converges on deterioration: a northern Ethiopian war restarting, famine returning as aid collapses, piracy back at sea, and diplomatic recognition being auctioned for bases and minerals.','Berichte westlicher Medien und von UN-Organisationen laufen auf eine Verschlechterung hinaus: ein wieder aufflammender Krieg im Norden Äthiopiens, eine mit dem Wegbrechen der Hilfe zurückkehrende Hungersnot, erneute Piraterie und diplomatische Anerkennung, die gegen Stützpunkte und Rohstoffe versteigert wird.',ARRAY['AFRICA-HORN'],ARRAY['brink','fears','famine','hunger','clashes','piracy','drone','atrocities','civilian','Krieg','Hungersnot','Piraterie'],true,ARRAY['Reuters','BBC World','BBC','AFP','AFP Fact Check','Deutsche Welle','The Guardian','Financial Times','Le Monde','UN News','The Economist','Associated Press','France 24','France 24 (EN)','Die Zeit','Der Standard','IISS','Kurier','The Telegraph','Der Spiegel','Bloomberg','CNN','Atlantic Council','Japan Times','Straits Times','DR','Military Times','Defense News'],'horn_africa_theater',3,'Alarm at deterioration','Alarm über die Verschlechterung', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('horn_sovereignty_bloc','Sovereignty and non-interference','Souveränität und Nichteinmischung','Arab and Turkish coverage frames the realignment as a set of violations: inherited borders must hold, an outside power cannot confer statehood on a secessionist region, and upstream control of shared water is a standing threat to downstream states.','Arabische und türkische Berichterstattung deutet die Neuordnung als eine Reihe von Verstößen: Ererbte Grenzen müssen halten, eine fremde Macht kann einer sezessionistischen Region keine Staatlichkeit verleihen, und die Kontrolle über gemeinsame Wasserressourcen am Oberlauf bleibt eine Dauerbedrohung für die Anrainer flussabwärts.',ARRAY['AFRICA-HORN','MIDEAST-EGYPT','MIDEAST-TURKEY'],ARRAY['sovereignty','territorial integrity','illegal','null and void','condemn','reject','water','dam','Souveränität','verurteilen'],true,ARRAY['Al Jazeera','Al Arabiya','Arab News','Dawn','The National'],'horn_africa_theater',4,'Borders and sovereignty violated','Verletzte Grenzen und Souveränität', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('horn_russian_iranian_counter','Russian and Iranian counter-framing','Russische und iranische Gegendarstellung','Russian and Iranian state media read the Horn primarily as a theatre of American and Israeli overreach -- airstrikes, blocked peacekeeping funding and coastal basing -- rather than as a set of local disputes.','Russische und iranische Staatsmedien lesen das Horn vorrangig als Schauplatz amerikanischer und israelischer Übergriffigkeit -- Luftangriffe, blockierte Mittel für Friedensmissionen, Stützpunkte an der Küste -- und nicht als eine Reihe lokaler Konflikte.',ARRAY['AFRICA-HORN','AMERICAS-USA'],ARRAY['airstrike','intervention','base','imperial','blockade','foreign','Luftangriff','Einmischung'],true,ARRAY['RT','Press TV','TASS (EN)','Sputnik'],'horn_africa_theater',5,'Blame external intervention','Die Einmischung von außen ist schuld', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('mercosur_market_opportunity','The agreement opens a large market','Das Abkommen öffnet einen großen Markt','South American coverage presents the agreement as long-delayed access to a high-value market, a diversification away from dependence on any single buyer, and a test of whether the bloc can conclude and hold a major external deal.','Südamerikanische Berichterstattung stellt das Abkommen als lange verzögerten Zugang zu einem hochwertigen Markt dar, als Diversifizierung weg von der Abhängigkeit von einem einzelnen Abnehmer und als Prüfstein dafür, ob der Block ein großes Außenabkommen abschließen und halten kann.',ARRAY['AMERICAS-BRAZIL'],ARRAY['oportunidad','oportunidade','se firmó','firmaron','assinatura','assinado','histórico','histórica','entra en vigor','entrará en vigor','vigência','apertura','abre','ganan','ganha','beneficia','exportadores','exportação','integra','multilateralismo','ratificado','ratificação','avanza','avança'],true,ARRAY['Clarín','La Nación','O Globo','Folha de S.Paulo','O Estado de S. Paulo','Infobae','Brazil Reports','El Observador','La Tercera'],'latam_eu_market_access',1,'Market opening for the bloc','Marktöffnung für den Block',2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('mercosur_farm_protection','The deal undercuts European farmers','Das Abkommen unterbietet Europas Bauern','Opposition framing in European coverage holds that imported beef, poultry, sugar and ethanol produced under different cost and regulatory conditions will undercut domestic producers, and that quota concessions were granted without adequate safeguards.','Die Oppositionsdarstellung in europäischen Medien hält fest, dass eingeführtes Rind-, Geflügelfleisch, Zucker und Ethanol, die unter anderen Kosten- und Regulierungsbedingungen erzeugt werden, heimische Produzenten unterbieten und dass Quotenzugeständnisse ohne ausreichende Schutzklauseln gewährt wurden.',ARRAY['NON-STATE-EU'],ARRAY['agriculteur','Bauern','Landwirt','farmer','éleveur','viande','Rindfleisch','Fleisch','volaille','poultry','concurrence','Wettbewerbs','Standards','Schutzklausel','clause de sauvegarde','protest','manifestation','quota','Quote'],true,ARRAY['Le Figaro','Le Monde','Frankfurter Allgemeine','Süddeutsche Zeitung','Die Zeit','Tagesschau','Corriere della Sera','ANSA','NZZ','Swissinfo','EurActiv','Euronews','France 24','France 24 (EN)','Boulevard Voltaire'],'latam_eu_market_access',2,'European farm protection','Europäischer Agrarschutz', -2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('mercosur_environmental_critique','The deal rewards forest clearance','Das Abkommen belohnt Waldrodung','A separate European objection holds that expanding agricultural exports raises pressure on the Amazon and Cerrado, and that the agreement sits awkwardly beside the European Union''s own deforestation regulation and climate commitments.','Ein gesonderter europäischer Einwand hält fest, dass ausgeweitete Agrarexporte den Druck auf Amazonas und Cerrado erhöhen und dass das Abkommen im Widerspruch zur eigenen Entwaldungsverordnung und zu den Klimaverpflichtungen der Europäischen Union steht.',ARRAY['NON-STATE-EU'],ARRAY['déforestation','Entwaldung','Abholzung','deforestation','Amazon','Amazonas','Amazonie','Regenwald','climat','Klima','climate','Umwelt','environnement','EUDR'],true,ARRAY['Le Figaro','Le Monde','Frankfurter Allgemeine','Süddeutsche Zeitung','Die Zeit','Tagesschau','Corriere della Sera','ANSA','NZZ','Swissinfo','EurActiv','Euronews','France 24','France 24 (EN)','The Guardian'],'latam_eu_market_access',3,'Deforestation and climate objection','Entwaldungs- und Klimaeinwand', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('mercosur_european_obstruction','Europe signs, then restricts','Europa unterzeichnet und beschränkt dann','South American coverage of the agreement''s implementation phase reports a pattern of European restriction after signature: import bans on specific products, quota exhaustion, parliamentary and judicial challenges to ratification, and standards applied as barriers, read regionally as the terms being narrowed after the deal was concluded.','Südamerikanische Berichterstattung über die Umsetzungsphase des Abkommens beschreibt ein Muster europäischer Beschränkungen nach der Unterzeichnung: Einfuhrverbote für einzelne Erzeugnisse, ausgeschöpfte Quoten, parlamentarische und gerichtliche Anfechtungen der Ratifizierung sowie als Handelshemmnis wirkende Standards -- regional gelesen als nachträgliche Verengung der vereinbarten Bedingungen.',ARRAY['AMERICAS-BRAZIL'],ARRAY['golpe','prohíbe','prohibe','proíbe','proibiç','bloqueo','bloquea','bloqueia','paraliza','paralisa','veto','freno','frena','trava','barreira','barreras','obstácul','alerta','restric','restriç','suspende','impugna','acciona','Justiça','Justicia'],true,ARRAY['Clarín','La Nación','O Globo','Folha de S.Paulo','O Estado de S. Paulo','Infobae','Brazil Reports','El Observador','La Tercera'],'latam_eu_market_access',4,'European obstruction of the deal','Europäische Blockade des Abkommens', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('latam_theater_regional_agency','Courted by all sides, committed to none','Von allen umworben, keinem verpflichtet','South American coverage across all three arenas presents the region as an actor with leverage rather than a prize: playing buyers against each other, holding out for processing and value-added stages, and treating simultaneous deals with Washington, Brussels and Beijing as the point rather than a contradiction.','Südamerikanische Berichterstattung stellt die Region in allen drei Arenen als Akteur mit Verhandlungsmacht dar und nicht als Beute: Sie spielt Abnehmer gegeneinander aus, besteht auf Verarbeitung und Wertschöpfung im Land und betrachtet gleichzeitige Abkommen mit Washington, Brüssel und Peking als das Ziel und nicht als Widerspruch.',ARRAY['AMERICAS-BRAZIL'],ARRAY['soberan','estratégic','acordo','acuerdo','negociar','exporta','agregar valor','oportunidad','oportunidade'],true,ARRAY['Clarín','La Nación','O Globo','Folha de S.Paulo','O Estado de S. Paulo','Infobae','Brazil Reports','El Mercurio','La Tercera','El Observador'],'latam_hemispheric_theater',1,'The region negotiates for itself','Die Region verhandelt für sich selbst',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('latam_theater_eastern_partnership','A second partner on offer','Ein zweiter Partner steht bereit','Chinese and Russian state media present their engagement across minerals, finance and infrastructure as an alternative to Western conditionality, and frame US objections to those projects as an attempt to keep the region inside a single sphere of influence.','Chinesische und russische Staatsmedien stellen ihr Engagement bei Rohstoffen, Finanzierung und Infrastruktur als Alternative zu westlicher Konditionalität dar und werten US-Einwände gegen diese Projekte als Versuch, die Region in einer einzigen Einflusssphäre zu halten.',ARRAY['ASIA-CHINA'],ARRAY['cooperation','win-win','partnership','mutual benefit','sphere of influence','hegemon','合作','共赢'],true,ARRAY['CGTN','China Daily','Global Times','Xinhua','People''s Daily','RT','TASS','TASS (EN)','tass.com','Sputnik','RIA Novosti','Izvestia','Kommersant','BelTA'],'latam_hemispheric_theater',2,'Partnership beyond the West','Partnerschaft jenseits des Westens',1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('latam_theater_leverage_works','Leverage produced the concessions','Druckmittel haben die Zugeständnisse gebracht','America-First commentary holds that tariffs, designations and contract challenges are what actually moved South American governments, and that declining to use that leverage would cede the hemisphere''s trade terms and resource contracts to Beijing by default.','America-First-Kommentare halten fest, dass Zölle, Listungen und Auftragsanfechtungen es waren, die südamerikanische Regierungen tatsächlich bewegt haben, und dass ein Verzicht auf diese Druckmittel die Handelsbedingungen und Rohstoffverträge der Hemisphäre kampflos an Peking abträte.',ARRAY['AMERICAS-USA'],ARRAY['leverage','reciprocal','unfair','deal','concession','enforcement','hemisphere'],false,ARRAY['Fox News','New York Post','Washington Examiner','Breitbart','Newsmax','The National Interest','The Federalist','Daily Caller','Washington Times','National Review','Atlantic Council'],'latam_hemispheric_theater',3,'Pressure is the working instrument','Druck ist das wirksame Instrument',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('latam_theater_terms_imposed','The costs land locally','Die Kosten fallen vor Ort an','Mainstream and regional reporting treats the three arenas as variations on one asymmetry: tariffs, quota allocations and extraction contracts are largely determined abroad, while the adjustment costs -- to exporters, to public budgets, to the communities around mine sites -- are absorbed within the region.','Etablierte und regionale Berichterstattung behandelt die drei Arenen als Varianten derselben Asymmetrie: Zölle, Quotenzuteilungen und Förderverträge werden überwiegend im Ausland bestimmt, während die Anpassungskosten -- für Exporteure, öffentliche Haushalte und die Gemeinden rund um die Minen -- in der Region anfallen.',ARRAY['AMERICAS-BRAZIL'],ARRAY['coercion','asymmetr','sovereignty','soberan','extractivis','comunidades','represalia','punish'],true,ARRAY['Reuters','Associated Press','Bloomberg','Financial Times','The Guardian','Deutsche Welle','El País','Al Jazeera','The Hindu','NPR','S&P Global','Página 12'],'latam_hemispheric_theater',4,'Terms set from outside','Von außen gesetzte Bedingungen', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('latam_theater_european_objection','Europe resists its own agreement','Europa wehrt sich gegen sein eigenes Abkommen','European coverage carries the internal resistance to market opening: producer groups object to competition under different cost and regulatory conditions, environmental critics object to the pressure that expanded agricultural exports place on forest cover, and several member states and parliaments have moved to block or challenge ratification.','Europäische Berichterstattung trägt den internen Widerstand gegen die Marktöffnung: Erzeugerverbände wenden sich gegen Konkurrenz unter anderen Kosten- und Regulierungsbedingungen, Umweltkritiker gegen den Druck ausgeweiteter Agrarexporte auf die Waldbestände, und mehrere Mitgliedstaaten und Parlamente haben die Ratifizierung blockiert oder angefochten.',ARRAY['NON-STATE-EU'],ARRAY['agriculteur','Bauern','Landwirt','farmer','viande','Rindfleisch','déforestation','Entwaldung','Abholzung','Amazonas','Klima','Schutzklausel','ratifi','Quote','quota'],true,ARRAY['Le Figaro','Le Monde','Frankfurter Allgemeine','Süddeutsche Zeitung','Die Zeit','Tagesschau','Corriere della Sera','ANSA','NZZ','Swissinfo','EurActiv','Euronews','France 24','France 24 (EN)','Boulevard Voltaire'],'latam_hemispheric_theater',5,'European objection to the opening','Europäischer Einwand gegen die Öffnung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('latam_theater_strategic_warning','Commerce with a strategic tail','Handel mit strategischem Nachlauf','US security-oriented commentary reads Chinese port, rail and mineral holdings in the hemisphere as dual-use positioning rather than ordinary commerce, and treats each concession awarded as a durable strategic loss rather than a single contract.','US-sicherheitspolitische Kommentare deuten chinesische Hafen-, Bahn- und Mineralienbeteiligungen in der Hemisphäre als militärisch mitnutzbare Positionierung statt als gewöhnlichen Handel und werten jede vergebene Konzession als dauerhaften strategischen Verlust und nicht als einzelnen Auftrag.',ARRAY['AMERICAS-USA'],ARRAY['dual-use','strategic','military','backyard','hemisphere','Beijing','threat','influence'],true,ARRAY['Fox News','New York Post','Washington Examiner','Breitbart','Newsmax','The National Interest','The Federalist','Daily Caller','Washington Times','National Review','Atlantic Council'],'latam_hemispheric_theater',6,'Strategic penetration warning','Warnung vor strategischer Durchdringung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('latam_theater_western_terms_hold','The Western offer still sets the terms','Das westliche Angebot gibt weiter den Ton an','Across trade, minerals and infrastructure, Latin American states are still choosing rules, courts and partners anchored in the Western order -- cancelling opaque concessions, upholding regulatory control and contracting with European and North American operators -- and the pressure that follows from Beijing is read as vindication of the choice rather than a reason to reverse it.','Ob Handel, Rohstoffe oder Infrastruktur: Lateinamerikanische Staaten setzen weiterhin auf Regeln, Gerichte und Partner der westlichen Ordnung -- sie annullieren intransparente Konzessionen, behaupten die regulatorische Kontrolle und vergeben Aufträge an europäische und nordamerikanische Betreiber. Der darauf folgende Druck aus Peking gilt als Bestätigung dieser Entscheidung, nicht als Grund zur Umkehr.',ARRAY['AMERICAS-CENTRAL','AMERICAS-ANDEAN','AMERICAS-BRAZIL','AMERICAS-SOUTHERNCONE','AMERICAS-USA','NON-STATE-EU'],ARRAY['ruling','court','sovereignt','control','agreement','deal','investment','partnership','de-risk','contract'],true,ARRAY['Reuters','Associated Press','AP News','Financial Times','Wall Street Journal','Bloomberg','Nikkei Asia','The Guardian','BBC News','New York Times','Washington Post','Deutsche Welle','El País','Le Monde','Euronews','EurActiv','France 24 (EN)','S&P Global','Japan Times','CNN','The Telegraph','Der Spiegel','Handelsblatt','Fox News'],'latam_hemispheric_theater',7,'Western-anchored rules prevail','Westlich verankerte Regeln setzen sich durch',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('latam_theater_coercion_critique','Washington coerces, Beijing is punished','Washington erzwingt, Peking wird bestraft','The region''s choices are not free ones: Washington converts commercial and legal processes into instruments of pressure, stripping Chinese firms of lawfully held assets and framing ordinary investment as a security threat, while presenting the result as Latin American sovereignty. What is described as de-risking is a hemispheric monopoly reasserted at the expense of the region''s own room to manoeuvre.','Die Entscheidungen der Region sind keine freien: Washington macht kommerzielle und juristische Verfahren zu Druckmitteln, entzieht chinesischen Unternehmen rechtmäßig gehaltene Vermögenswerte und stellt gewöhnliche Investitionen als Sicherheitsbedrohung dar -- um das Ergebnis dann als lateinamerikanische Souveränität auszugeben. Was als De-Risking bezeichnet wird, ist ein wiederhergestelltes Monopol über die Hemisphäre auf Kosten des eigenen Handlungsspielraums der Region.',ARRAY['ASIA-CHINA','ASIA-HONGKONG','EUROPE-RUSSIA'],ARRAY['cold war mentality','coercion','smear','hegemon','unilateral','interference','rights and interests','politiciz','hypocri','bullying'],true,ARRAY['Global Times','People''s Daily','CGTN','China Daily','Xinhua','RT','TASS','TASS (EN)','tass.com','Sputnik','RIA Novosti'],'latam_hemispheric_theater',8,'Hemispheric coercion critique','Kritik an hemisphärischem Zwang', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('port_control_restored','Host-state control restored','Wiederhergestellte Kontrolle des Gastlandes','Courts in Panama and Peru acted lawfully to return chokepoint terminals to host-state control, closing a strategic vulnerability created by operators answerable to Beijing; China''s response -- detaining Panama-flagged vessels and pressing carriers to withdraw -- confirms the risk it was meant to address.','Gerichte in Panama und Peru haben rechtmäßig gehandelt, um Terminals an Nadelöhren wieder unter die Kontrolle des Gastlandes zu bringen und eine strategische Verwundbarkeit durch Betreiber im Einflussbereich Pekings zu beseitigen; Chinas Reaktion -- das Festhalten von Schiffen unter Panama-Flagge und der Druck auf Reedereien, sich zurückzuziehen -- bestätigt genau das Risiko, um das es ging.',ARRAY['AMERICAS-CENTRAL','AMERICAS-ANDEAN','AMERICAS-USA'],ARRAY['sovereignt','Souveränität','soberan','unconstitutional','verfassungswidrig','inconstitucional','court','Gericht','ruling','Urteil','quashed','voids','annull','takes control','take control','wrests','reclaim','takes back','ousting','ousts','ejecting','kicks','seizes','seized','hands canal','to operate','reprend le contrôle','übernimmt','zurück','security risk','Sicherheitsrisiko','vulnerab','verwundbar','de-risk','bullying','coercion','Zwang','retaliation','Vergeltung','detention','detentions','heavy price','necessary action','told Maersk','drop Panama','non-negotiable','backs Panama','joint statement'],true,ARRAY['Reuters','Financial Times','Wall Street Journal','Bloomberg','Associated Press','AP News','Nikkei Asia','Fox News','CNN','The Telegraph','Deutsche Welle','Le Monde','El País','Euronews','EurActiv','France 24 (EN)','Japan Times','S&P Global','The Guardian','BBC News','New York Times','Washington Post','Der Spiegel','Handelsblatt'],'latam_port_infrastructure_control',1,'Lawful reassertion of control','Rechtmäßige Rückgewinnung der Kontrolle',2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('port_sovereignty_squeeze','A small state squeezed between two powers','Ein kleiner Staat zwischen zwei Mächten','Whatever the legal merits, Panama and Peru are being made the terrain of a US-China contest they did not choose: Washington backs its case with a military buildup and hemispheric-sovereignty rhetoric while Beijing answers with shipping coercion, and the host states absorb the cost of both.','Ungeachtet der Rechtslage werden Panama und Peru zum Austragungsort eines US-chinesischen Wettstreits, den sie nicht gewählt haben: Washington untermauert seine Position mit militärischem Aufmarsch und Rhetorik zur Souveränität der Hemisphäre, Peking antwortet mit Druck auf die Schifffahrt -- und die Gastländer tragen die Kosten beider Seiten.',ARRAY['AMERICAS-CENTRAL','AMERICAS-ANDEAN'],ARRAY['on edge','flexing','military might','buildup','Aufmarsch','troops','Truppen','tropas','Southern Command','squeez','caught between','zwischen den Fronten','battleground','pressure on Panama','Druck auf Panama','presión sobre Panamá','strong-arm','arm-twist','forced to choose','zur Wahl gezwungen'],false,ARRAY['Reuters','Financial Times','Wall Street Journal','Bloomberg','Associated Press','AP News','Nikkei Asia','Fox News','CNN','The Telegraph','Deutsche Welle','Le Monde','El País','Euronews','EurActiv','France 24 (EN)','Japan Times','S&P Global','The Guardian','BBC News','New York Times','Washington Post','Der Spiegel','Handelsblatt','Al Jazeera','Anadolu Agency','The Hindu','Times of India','Al Arabiya','Daily Sabah','Gulf News','Republic TV','NDTV','Straits Times'],'latam_port_infrastructure_control',2,'Great-power squeeze on the host state','Großmachtdruck auf das Gastland', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('port_expropriation_coercion','Expropriation under US pressure','Enteignung unter US-Druck','The port rulings were not independent justice but the product of US coercion: a lawful commercial concession was torn up and Chinese-linked assets stripped to satisfy Washington, which openly covets the waterway itself -- a cold-war reflex that punishes companies for their nationality and leaves host states less sovereign, not more.','Die Hafenurteile waren keine unabhängige Justiz, sondern das Ergebnis von US-Zwang: Eine rechtmäßige kommerzielle Konzession wurde annulliert und chinesisch verbundene Vermögenswerte enteignet, um Washington zufriedenzustellen, das offen nach der Wasserstraße selbst greift -- ein Reflex des Kalten Krieges, der Unternehmen für ihre Nationalität bestraft und die Gastländer weniger souverän zurücklässt, nicht souveräner.',ARRAY['ASIA-CHINA','ASIA-HONGKONG'],ARRAY['cold war mentality','Kalter Krieg','coveting','covets','smear','groundless','hypocri','Heuchelei','lawful','legitimate rights','rights and interests','politiciz','politicis','politisier','heavy price','interference','Einmischung','unilateral'],true,ARRAY['Global Times','People''s Daily','CGTN','China Daily','Xinhua','RT','TASS','Sputnik'],'latam_port_infrastructure_control',3,'Politicised seizure of commercial assets','Politisierte Enteignung kommerzieller Vermögenswerte', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('resource_south_south_partnership','Cooperation brings development','Kooperation bringt Entwicklung','Chinese and Russian state media frame mineral purchases, port finance and rail construction as mutually beneficial South-South cooperation that delivers infrastructure Western lenders declined to fund, and cast US warnings about those projects as smear campaigns intended to deny the region a second partner.','Chinesische und russische Staatsmedien stellen Mineralienkäufe, Hafenfinanzierung und Bahnbau als beiderseits vorteilhafte Süd-Süd-Kooperation dar, die Infrastruktur liefert, deren Finanzierung westliche Kreditgeber ablehnten, und werten US-Warnungen vor diesen Projekten als Verleumdungskampagnen, die der Region einen zweiten Partner verwehren sollen.',ARRAY['ASIA-CHINA'],ARRAY['cooperation','win-win','partnership','development','mutual benefit','Zusammenarbeit','cooperación','beneficio mutuo','合作','共赢'],true,ARRAY['CGTN','China Daily','Global Times','Xinhua','People''s Daily','RT','TASS','TASS (EN)','tass.com','Sputnik','RIA Novosti','Izvestia','Kommersant','BelTA'],'latam_resource_access',1,'South-South development partnership','Süd-Süd-Entwicklungspartnerschaft',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('resource_sovereign_development','The region sets its own terms','Die Region setzt eigene Bedingungen','South American outlets present their governments as active agents rather than objects of competition: courting several buyers at once, legislating national minerals policy and pressing to capture processing and value-added stages domestically instead of exporting raw ore.','Südamerikanische Medien stellen ihre Regierungen als handelnde Akteure statt als Objekte des Wettbewerbs dar: Sie umwerben mehrere Abnehmer zugleich, verankern eine nationale Rohstoffpolitik gesetzlich und drängen darauf, Verarbeitung und Wertschöpfung im Land zu halten, statt Roherz auszuführen.',ARRAY['AMERICAS-BRAZIL'],ARRAY['soberan','estratégic','agregar valor','valor agregado','política nacional','industrializ','negociar','acordo','acuerdo'],true,ARRAY['Clarín','La Nación','O Globo','Folha de S.Paulo','O Estado de S. Paulo','Infobae','Brazil Reports','El Mercurio','La Tercera'],'latam_resource_access',2,'Sovereign resource strategy','Souveräne Rohstoffstrategie',1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('resource_extractivism_critique','Extraction externalises its costs','Die Förderung lagert ihre Kosten aus','Critical regional coverage holds that whichever external buyer prevails, the extraction model itself transfers water, land and environmental burdens onto local and indigenous communities while the processed value accrues abroad.','Kritische regionale Berichterstattung hält fest, dass unabhängig davon, welcher externe Abnehmer sich durchsetzt, das Fördermodell selbst Wasser-, Land- und Umweltlasten auf lokale und indigene Gemeinschaften abwälzt, während die verarbeitete Wertschöpfung im Ausland anfällt.',ARRAY['AMERICAS-BRAZIL'],ARRAY['extractivis','contaminac','contaminaç','comunidades','indígena','saqueo','socioambiental','medio ambiente','meio ambiente','agua','água','protesta','protesto'],true,ARRAY['Clarín','La Nación','O Globo','Folha de S.Paulo','O Estado de S. Paulo','Infobae','Brazil Reports','El Mercurio','La Tercera','Página 12'],'latam_resource_access',3,'Extractivism and local cost','Extraktivismus und lokale Kosten', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('resource_strategic_penetration','Beijing is buying strategic depth','Peking kauft strategische Tiefe','US security-oriented commentary treats Chinese port, rail and mineral holdings in the region as dual-use strategic positioning in the Western hemisphere rather than ordinary commerce, and urges Washington to contest those contracts.','US-sicherheitspolitische Kommentare werten chinesische Hafen-, Bahn- und Mineralienbeteiligungen in der Region als militärisch mitnutzbare strategische Positionierung in der westlichen Hemisphäre statt als gewöhnlichen Handel und drängen Washington, diese Aufträge zu bestreiten.',ARRAY['AMERICAS-USA'],ARRAY['dual-use','strategic','military','backyard','hemisphere','influence','threat','Beijing'],true,ARRAY['Fox News','New York Post','Washington Examiner','Breitbart','Newsmax','The National Interest','The Federalist','Daily Caller','Washington Times','National Review','Atlantic Council'],'latam_resource_access',4,'Strategic penetration warning','Warnung vor strategischer Durchdringung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('trade_pressure_enforcement_justified','Tariffs answer unfair practice','Zölle antworten auf unfaire Praktiken','America-First commentary holds that tariffs and designations are proportionate responses to trade practices, judicial overreach and criminal networks in the targeted states, and that leverage is the only instrument that has produced concessions.','America-First-Kommentare halten Zölle und Listungen für verhältnismäßige Antworten auf Handelspraktiken, justizielle Übergriffe und kriminelle Netzwerke in den betroffenen Staaten und sehen Druckmittel als einziges Instrument, das Zugeständnisse bewirkt hat.',ARRAY['AMERICAS-USA'],ARRAY['unfair','reciprocal','leverage','deal','concession','enforcement'],false,ARRAY['Fox News','New York Post','Washington Examiner','Breitbart','Newsmax','The National Interest','The Federalist','Daily Caller','Washington Times','National Review'],'latam_us_trade_pressure',1,'Legitimate trade enforcement','Legitime Handelsdurchsetzung',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('trade_pressure_sovereignty_defense','Tariffs punish a trade partner','Zölle bestrafen einen Handelspartner','Mainstream and regional coverage treats the measures as economic coercion applied to states that run trade deficits with the United States, notes their entanglement with domestic election cycles, and reports the targeted governments seeking negotiated relief or alternative markets.','Etablierte und regionale Berichterstattung wertet die Maßnahmen als wirtschaftlichen Zwang gegen Staaten, die gegenüber den Vereinigten Staaten Handelsdefizite aufweisen, verweist auf ihre Verflechtung mit innenpolitischen Wahlzyklen und berichtet, dass die betroffenen Regierungen Verhandlungslösungen oder Alternativmärkte suchen.',ARRAY['AMERICAS-BRAZIL'],ARRAY['coercion','retaliation','sovereignty','soberan','represalia','negotiat','punish','threat'],true,ARRAY['Reuters','Associated Press','Bloomberg','Financial Times','The Guardian','Deutsche Welle','El País','Clarín','La Nación','O Globo','Folha de S.Paulo','O Estado de S. Paulo','Al Jazeera','The Hindu','NPR','S&P Global'],'latam_us_trade_pressure',2,'Coercion against a sovereign partner','Zwang gegen einen souveränen Partner', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('m23_externally_backed_offensive','An externally backed offensive','Eine von außen unterstützte Offensive','M23 is not a self-sustaining local rebellion but a force armed and directed from across the border, able to seize cities, strike airports with drones and hold territory because a neighbouring state supplies it. The sanctions imposed on Rwandan commanders and on Joseph Kabila are the belated recognition of a cross-border war being fought through a proxy.','M23 ist kein sich selbst tragender lokaler Aufstand, sondern eine von jenseits der Grenze bewaffnete und geführte Truppe, die Städte einnehmen, Flughäfen mit Drohnen angreifen und Gebiete halten kann, weil ein Nachbarstaat sie versorgt. Die Sanktionen gegen ruandische Kommandeure und gegen Joseph Kabila sind die späte Anerkennung eines grenzüberschreitenden Krieges, der über einen Stellvertreter geführt wird.',ARRAY['AFRICA-DRC','AMERICAS-USA'],ARRAY['backing','backed','support for','supporting','proxy','sanctions','visa restrictions','Rwandan army','Rwandan officials','offensive','seized','captured','retake','retook','occupied','incursion','soutien','soutenu','appuyé','offensive','conquise','contrôlé','Unterstützung','unterstützt','Sanktionen','Offensive'],true,ARRAY['France 24','France 24 (EN)','Le Monde','Le Figaro','Reuters','Associated Press','The Guardian','BBC World','BBC','Deutsche Welle','Washington Post','Financial Times','The Economist','Swissinfo','ANSA','news.un.org','UN News','Al Jazeera','Anadolu Agency','Daily Sabah','TRT World','Daily Nation','Punch Newspapers','Janes'],'m23_conflict',1,'A cross-border proxy war','Ein grenzüberschreitender Stellvertreterkrieg', -2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('m23_civilian_toll','The population pays for every advance','Die Bevölkerung zahlt für jeden Vorstoß','Whoever is judged responsible, the measurable result of this war is borne by civilians: thousands detained and abused in captured towns, mass displacement across the Burundian and Rwandan borders, aid workers killed by drones, and rights investigators documenting killings and rapes in Uvira. Territorial gains and losses change faster than the humanitarian damage they leave.','Wer auch immer als verantwortlich gilt: Die messbaren Folgen dieses Krieges tragen die Zivilisten. Tausende werden in eroberten Städten festgehalten und misshandelt, Massen fliehen über die burundische und ruandische Grenze, Helfer sterben durch Drohnen, und Ermittler dokumentieren Tötungen und Vergewaltigungen in Uvira. Geländegewinne wechseln schneller als der humanitäre Schaden, den sie hinterlassen.',ARRAY['AFRICA-DRC'],ARRAY['civilian','civilians','displaced','displacement','refugee','refugees','abuse','abusing','detaining','detained','atrocities','killings','rapes','massacre','aid worker','humanitarian','hunger','human rights','HRW','trauma','civils','déplacés','réfugiés','atrocités','exactions','humanitaire','traumatismes','droits humains','Zivilisten','Vertriebene','Flüchtlinge','Gräueltaten','humanitär','Menschenrechte'],true,ARRAY['France 24','France 24 (EN)','Le Monde','Le Figaro','Reuters','Associated Press','The Guardian','BBC World','BBC','Deutsche Welle','Washington Post','The Economist','news.un.org','UN News','Al Jazeera','Anadolu Agency','Daily Sabah','TRT World','Daily Nation','The Standard','Der Spiegel'],'m23_conflict',2,'The humanitarian cost','Die humanitären Kosten', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('m23_backing_charge_rejected','The accused parties reject the charge','Die Beschuldigten weisen den Vorwurf zurück','Kigali and the figures named in Western sanctions dispute the proxy account entirely. They present the sanctions as insults that will not change Rwandan defence policy, describe the designations as unjustified, and point to the armed groups operating on the Congolese side of the border and to Kinshasa''s inability to protect its own eastern population as the actual origin of the fighting.','Kigali und die in westlichen Sanktionen genannten Personen bestreiten die Stellvertreter-Darstellung vollständig. Sie bezeichnen die Sanktionen als Beleidigungen, die an Ruandas Verteidigungspolitik nichts ändern, nennen die Listungen ungerechtfertigt und verweisen auf die bewaffneten Gruppen auf kongolesischer Seite sowie auf Kinshasas Unfähigkeit, die eigene Bevölkerung im Osten zu schützen, als eigentlichen Ursprung der Kämpfe.',ARRAY['AFRICA-DRC'],ARRAY['denies','denied','denounces','denounced','rejects','rejected','unjustified','unfounded','hits back','insults','internal affairs','dément','rejette','dénonce','injustifié','weist zurück','bestreitet','ungerechtfertigt'],true,ARRAY['The Standard','Daily Nation','Mail & Guardian','Anadolu Agency','Al-Ahram','News24','Punch Newspapers','RT','TASS (EN)'],'m23_conflict',3,'The charge is disputed','Der Vorwurf ist bestritten',1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('sahel_break_with_paris_justified','Cutting ties ends a relationship that never became equal','Der Bruch beendet eine Beziehung, die nie gleichberechtigt wurde','Severing relations, expelling diplomats and prosecuting intelligence officers close a colonial-era arrangement in which the former ruler kept bases, currency influence and a veto on security policy long after formal independence.','Der Abbruch der Beziehungen, die Ausweisung von Diplomaten und die Verfolgung von Nachrichtendienstoffizieren beenden ein koloniales Arrangement, in dem die frühere Kolonialmacht noch lange nach der formalen Unabhängigkeit Stützpunkte, Währungseinfluss und ein Veto in der Sicherheitspolitik behielt.',ARRAY['AFRICA-SAHEL','EUROPE-FRANCE'],'{}',true,ARRAY['RT','rt.com','TASS','TASS (EN)','tass.com','tass.ru','RIA Novosti','ria.ru','Kommersant','kommersant.ru','BelTA','BelTA Russian','CGTN','news.cgtn.com','newsaf.cgtn.com','Global Times','China Daily','Xinhua','Vanguard','Vanguard News','Punch','Punch Newspapers'],'sahel_france_rupture',1,'Ending the colonial relationship','Ende der kolonialen Beziehung',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('sahel_rupture_deepens_isolation','The break leaves the Sahel with fewer options, not more','Der Bruch lässt der Sahelzone weniger Optionen, nicht mehr','Jailing a diplomat for twenty years, blaming Paris for jihadist attacks and cutting the last diplomatic channels remove partners and aid at the moment the security situation is deteriorating fastest -- and the sovereignty gained is largely rhetorical.','Einen Diplomaten zu zwanzig Jahren Haft zu verurteilen, Paris für dschihadistische Anschläge verantwortlich zu machen und die letzten diplomatischen Kanäle zu kappen, entzieht Partner und Hilfe genau dann, wenn sich die Sicherheitslage am schnellsten verschlechtert -- und die gewonnene Souveränität bleibt weitgehend rhetorisch.',ARRAY['AFRICA-SAHEL','EUROPE-FRANCE'],'{}',true,ARRAY['France 24','France 24 (EN)','Le Monde','Le Figaro','Reuters','Associated Press','BBC World','Deutsche Welle','Die Zeit','Der Spiegel','Euronews','The Guardian','El País','Straits Times','Daily Nation','News24','Novinite','Kyiv Post','Al Jazeera','Al-Ahram','Al Arabiya','Anadolu Agency','Gulf News'],'sahel_france_rupture',2,'Isolation, not sovereignty','Isolation statt Souveränität', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('sahel_counterterror_necessity','A legitimate war against armed extremist groups','Ein legitimer Krieg gegen bewaffnete extremistische Gruppen','Sahelian and Nigerian armies, with the partners they have chosen, are fighting internationally designated armed groups that kill civilians, abduct schoolchildren and blockade cities -- and operations that degrade those groups deserve support rather than second-guessing.','Die Armeen der Sahelzone und Nigerias kämpfen gemeinsam mit den von ihnen gewählten Partnern gegen international gelistete bewaffnete Gruppen, die Zivilisten töten, Schulkinder entführen und Städte blockieren -- Operationen, die diese Gruppen schwächen, verdienen Unterstützung statt Zweifel.',ARRAY['AFRICA-SAHEL','AFRICA-NIGERIA','EUROPE-RUSSIA'],ARRAY['troops kill','soldiers kill','army kill','killed','neutralis','neutraliz','eliminated','surrender','surrendered','repel','repelled','foiled','thwart','operation','offensive against','anti-jihadist','counterterror','counter-terror','arrested','captured','degrade','airstrikes kill','terrorists','bandits','freed','rescued','liberated','neutralisés','abattus','opération','riposte','repoussé','libérés','reddition','terroristes','уничтож','ликвидир','отраж','боевик','击毙','剿灭','解救','قضت','أحبطت','حررت','getötet','zurückgeschlagen'],true,ARRAY['RT','rt.com','TASS','TASS (EN)','tass.com','tass.ru','RIA Novosti','ria.ru','Kommersant','kommersant.ru','BelTA','BelTA Russian','CGTN','news.cgtn.com','newsaf.cgtn.com','Global Times','China Daily','People''s Daily','Xinhua','Vanguard','Vanguard News','Punch','Punch Newspapers','The Nation Newspaper','Premium Times Nigeria'],'sahel_jihadist_insurgency',1,'Counterterror necessity','Notwendige Terrorbekämpfung',2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('sahel_state_losing_ground','The state is losing territory it cannot recover','Der Staat verliert Gebiet, das er nicht zurückgewinnen kann','Coordinated assaults on Bamako, the fuel blockade of the capital and the fall of garrison towns show armies that no longer control their own terrain, and a military government whose core promise -- security -- has failed.','Koordinierte Angriffe auf Bamako, die Treibstoffblockade der Hauptstadt und der Fall von Garnisonsstädten zeigen Armeen, die ihr eigenes Terrain nicht mehr kontrollieren, und eine Militärregierung, deren Kernversprechen -- Sicherheit -- gescheitert ist.',ARRAY['AFRICA-SAHEL','AFRICA-NIGERIA'],ARRAY['losing','lost control','loses','seize','seized','capture','captured','advance','advancing','offensive','coordinated','simultaneous','blockade','siege','encircl','expand','spread','spreading','sweeping','unprecedented','splinter','press attacks','under pressure','overrun','no longer control','tipping point','crisis','percée','pression','se propage','propagation','bousculent','bascule','blocus','offensive','coordonnées','coordonnée','sans précédent','inédit','fragilis','vacille','recule','étouffer','emprise','s''empare','ampleur','assaut','enlisement','verliert','Vormarsch','beispiellos','Druck','Belagerung','erobert','pierde','avanza','asedio','ofensiva','sin precedentes','perde','avanzata','assedio'],true,ARRAY['France 24','France 24 (EN)','Le Monde','Le Figaro','Reuters','Associated Press','BBC World','Deutsche Welle','Die Zeit','Der Spiegel','Der Standard','Tagesschau','Süddeutsche Zeitung','Frankfurter Allgemeine','The Guardian','Washington Post','New York Times','The Telegraph','Sky News','Euronews','El País','El Mundo','La Repubblica','Corriere della Sera','Straits Times','Bangkok Post','WION','NDTV','The Hindu','Times of India','Janes','Kyiv Post','Novinite','News24','Daily Nation','Council on Foreign Relations','War on the Rocks','Military Times','Defense News','Financial Times','iROZHLAS','Republic TV','The National'],'sahel_jihadist_insurgency',2,'State losing ground','Staat verliert Boden', -2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('sahel_counterinsurgency_abuses','The counterinsurgency is killing the civilians it claims to protect','Die Aufstandsbekämpfung tötet die Zivilisten, die sie zu schützen vorgibt','Drone strikes on weddings, mass executions documented by rights monitors, and the abuses of foreign auxiliaries mean the campaign against the armed groups is itself a major source of civilian death -- and impunity is fuelling recruitment.','Drohnenangriffe auf Hochzeiten, von Menschenrechtsbeobachtern dokumentierte Massenexekutionen und die Übergriffe ausländischer Hilfstruppen machen den Feldzug gegen die bewaffneten Gruppen selbst zu einer Hauptursache ziviler Todesfälle -- und die Straflosigkeit befeuert die Rekrutierung.',ARRAY['AFRICA-SAHEL','AFRICA-NIGERIA'],ARRAY['exaction','atrocit','abuses','human rights','Human Rights Watch','HRW','Amnesty','impunity','impunité','droits de l''homme','Menschenrechte','Übergriffe','Gräueltaten','derechos humanos','summary execution','extrajudicial','mass grave','charnier','disappearance','misfire','civilian deaths','killed civilians','civils tués','morts civils','victimes civiles','feared dead','wedding','mariage','market','marché','crimes de l''armée','army behind','par l''armée'],true,ARRAY['Al Jazeera','Al-Ahram','Ahram Online','Al Arabiya','Al Arabiya English','Anadolu Agency','Anadolu Ajansı','TRT World','Daily Sabah','Gulf News','Gulf Times','Arab News','UN News','France 24','France 24 (EN)','Le Monde','Le Figaro','Deutsche Welle','The Guardian','Der Spiegel','Die Zeit','BBC World','Washington Post'],'sahel_jihadist_insurgency',3,'Civilian cost of the campaign','Ziviler Preis des Feldzugs', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('sahel_sovereigntist_self_reliance','Reclaiming sovereignty after decades of external tutelage','Rückgewinnung der Souveränität nach Jahrzehnten äußerer Bevormundung','The Sahel governments are choosing their own partners, leaving institutions they judge to serve others'' interests, and refusing the conditionality that came with Western support -- an assertion of independence that the states which lost influence naturally portray as decline.','Die Sahel-Regierungen wählen ihre eigenen Partner, verlassen Institutionen, die aus ihrer Sicht fremden Interessen dienen, und weisen die Auflagen westlicher Unterstützung zurück -- eine Behauptung von Unabhängigkeit, die jene Staaten, die an Einfluss verloren, erwartungsgemäß als Niedergang darstellen.',ARRAY['AFRICA-SAHEL','EUROPE-RUSSIA'],'{}',true,ARRAY['RT','rt.com','TASS','TASS (EN)','tass.com','tass.ru','RIA Novosti','ria.ru','Kommersant','kommersant.ru','BelTA','BelTA Russian','CGTN','news.cgtn.com','newsaf.cgtn.com','Global Times','China Daily','People''s Daily','Xinhua','Vanguard','Vanguard News','Punch','Punch Newspapers'],'sahel_junta_consolidation',1,'Sovereigntist realignment','Souveränistische Neuausrichtung',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('sahel_democratic_closure','Military rule is closing the last civic space','Die Militärherrschaft schließt den letzten zivilgesellschaftlichen Raum','Dissolving every political party, suspending foreign media, forcing out the UN human-rights office and abandoning international courts are not sovereignty measures but the removal of every remaining check -- and the transitions promised at each coup keep receding.','Die Auflösung sämtlicher Parteien, die Suspendierung ausländischer Medien, die Vertreibung des UN-Menschenrechtsbüros und der Austritt aus internationalen Gerichten sind keine Souveränitätsmaßnahmen, sondern die Beseitigung jeder verbliebenen Kontrolle -- und die bei jedem Putsch versprochenen Übergänge rücken immer weiter weg.',ARRAY['AFRICA-SAHEL'],'{}',true,ARRAY['France 24','France 24 (EN)','Le Monde','Le Figaro','Reuters','Associated Press','BBC World','Deutsche Welle','Die Zeit','Der Spiegel','Der Standard','Tagesschau','Süddeutsche Zeitung','Frankfurter Allgemeine','The Guardian','Washington Post','New York Times','Euronews','El País','El Mundo','Straits Times','Novinite','News24','Daily Nation','The Standard','Kyiv Post','UN News','Al Jazeera','Al-Ahram','Al Arabiya','Anadolu Agency','Gulf News'],'sahel_junta_consolidation',2,'Democratic closure','Demokratische Schließung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('sahel_russian_partnership_delivers','The new partnership delivers what the old one did not','Die neue Partnerschaft liefert, was die alte nicht leistete','Russian forces fight alongside Sahelian armies without demanding governance conditions, intervened to stop an attempted coup and struck the armed groups directly -- results that a decade of Western deployments never produced.','Russische Kräfte kämpfen an der Seite der Sahel-Armeen, ohne Regierungsauflagen zu stellen, griffen ein, um einen Putschversuch zu stoppen, und trafen die bewaffneten Gruppen direkt -- Ergebnisse, die ein Jahrzehnt westlicher Einsätze nie erbrachte.',ARRAY['AFRICA-SAHEL','EUROPE-RUSSIA'],'{}',true,ARRAY['RT','rt.com','TASS','TASS (EN)','tass.com','tass.ru','RIA Novosti','ria.ru','Kommersant','kommersant.ru','BelTA','BelTA Russian','CGTN','news.cgtn.com','newsaf.cgtn.com','Global Times','China Daily','Xinhua'],'sahel_security_patron_contest',1,'Partnership delivers','Partnerschaft liefert',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('sahel_patron_model_failing','The replacement security model is buckling','Das neue Sicherheitsmodell gerät ins Wanken','Africa Corps pulled out of Kidal, lost personnel to rebel attacks and is retreating under jihadist pressure, while Türkiye''s drones and training offer capability without the mass required -- the states that expelled their old partners have not found one that can hold the terrain.','Das Africa Corps zog sich aus Kidal zurück, verlor Personal bei Rebellenangriffen und weicht unter dschihadistischem Druck zurück, während die Drohnen und Ausbildung der Türkei Fähigkeiten ohne die nötige Masse bieten -- die Staaten, die ihre alten Partner vertrieben, haben keinen gefunden, der das Terrain halten kann.',ARRAY['AFRICA-SAHEL','EUROPE-RUSSIA'],'{}',true,ARRAY['France 24','France 24 (EN)','Le Monde','Le Figaro','Reuters','Associated Press','BBC World','Deutsche Welle','Die Zeit','Der Spiegel','The Guardian','Washington Post','Euronews','El País','Straits Times','Kyiv Post','Janes','Military Times','Defense News','Financial Times','Council on Foreign Relations','War on the Rocks','Al Jazeera','Al-Ahram','Al Arabiya','Anadolu Agency','TRT World','Daily Sabah','Gulf News'],'sahel_security_patron_contest',2,'Replacement model failing','Neues Modell scheitert', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('sahel_theater_partnership_frame','A sovereign realignment that is finally fighting the real enemy','Eine souveräne Neuausrichtung, die endlich den wahren Feind bekämpft','The Sahel states threw out the powers that failed them, chose partners who impose no political conditions, and are now waging the counterterror campaign the West never delivered -- the criticism from Paris and Washington reflects lost influence, not concern for Sahelians.','Die Sahelstaaten haben die Mächte hinausgeworfen, die an ihnen scheiterten, Partner ohne politische Auflagen gewählt und führen nun jenen Anti-Terror-Feldzug, den der Westen nie lieferte -- die Kritik aus Paris und Washington spiegelt verlorenen Einfluss, nicht Sorge um die Menschen der Sahelzone.',ARRAY['AFRICA-SAHEL','EUROPE-RUSSIA'],'{}',true,ARRAY['RT','rt.com','TASS','TASS (EN)','tass.com','tass.ru','RIA Novosti','ria.ru','Kommersant','kommersant.ru','BelTA','BelTA – News','BelTA Russian','CGTN','news.cgtn.com','newsaf.cgtn.com','newsus.cgtn.com','Global Times','China Daily','China Daily - Global Edition','People''s Daily','People''s Daily Online','Xinhua','Xinhuanet Deutsch','German.people.cn'],'sahel_theater',1,'Sovereign realignment','Souveräne Neuausrichtung',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('sahel_theater_regional_security_response','A regional security emergency being fought by national armies','Ein regionaler Sicherheitsnotstand, den nationale Armeen bekämpfen','Seen from Abuja and the Lake Chad states, this is not a great-power contest but a war of national survival against groups that raid schools, blockade towns and cross borders at will -- and the story is the army''s operations, casualties and capability gaps.','Aus Sicht Abujas und der Tschadseestaaten ist dies kein Großmächtewettstreit, sondern ein Krieg ums nationale Überleben gegen Gruppen, die Schulen überfallen, Städte blockieren und nach Belieben Grenzen überschreiten -- und die Geschichte handelt von Operationen, Verlusten und Fähigkeitslücken der Armee.',ARRAY['AFRICA-NIGERIA','AFRICA-SAHEL'],'{}',true,ARRAY['Punch','Punch Newspapers','Vanguard','Vanguard News','Premium Times Nigeria','The Nation Newspaper'],'sahel_theater',2,'Regional security emergency','Regionaler Sicherheitsnotstand',1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('sahel_theater_state_collapse_critique','A managed collapse: military rule that delivers neither security nor politics','Ein verwalteter Zusammenbruch: Militärherrschaft ohne Sicherheit und ohne Politik','Four years after the coups the juntas have banned the parties, expelled the monitors and severed the partnerships -- while jihadist coalitions blockade capitals, the north slips away and the replacement patrons retreat. Sovereignty has been asserted; the state has not been rebuilt.','Vier Jahre nach den Putschen haben die Juntas die Parteien verboten, die Beobachter ausgewiesen und die Partnerschaften gekappt -- während dschihadistische Koalitionen Hauptstädte blockieren, der Norden entgleitet und die neuen Schutzmächte zurückweichen. Souveränität wurde behauptet; der Staat wurde nicht wiederaufgebaut.',ARRAY['AFRICA-SAHEL','EUROPE-FRANCE'],'{}',true,ARRAY['France 24','France 24 (EN)','Le Monde','Le Figaro','Reuters','Associated Press','BBC World','Deutsche Welle','Die Zeit','Der Spiegel','Der Standard','Tagesschau','Süddeutsche Zeitung','Frankfurter Allgemeine','The Guardian','Washington Post','New York Times','The Telegraph','Sky News','Euronews','El País','El Mundo','La Repubblica','Corriere della Sera','Straits Times','Bangkok Post','WION','NDTV','The Hindu','Times of India','Janes','Kyiv Post','Novinite','News24','Daily Nation','The Standard','Republic TV','The National','Council on Foreign Relations','War on the Rocks','Military Times','Defense News','Financial Times','Bloomberg','iROZHLAS'],'sahel_theater',3,'Managed collapse','Verwalteter Zusammenbruch', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('sahel_theater_civilian_cost','The population pays for every side''s campaign','Die Bevölkerung zahlt für den Feldzug jeder Seite','Between jihadist massacres, army airstrikes on markets and the abuses of foreign auxiliaries, civilians in the Sahel and the Lake Chad basin are being killed and displaced by all the armed actors claiming to protect them -- and no external patron has made that safer.','Zwischen dschihadistischen Massakern, Luftangriffen der Armee auf Märkte und den Übergriffen ausländischer Hilfstruppen werden Zivilisten in der Sahelzone und im Tschadseebecken von allen bewaffneten Akteuren getötet und vertrieben, die vorgeben, sie zu schützen -- und keine äußere Schutzmacht hat daran etwas verbessert.',ARRAY['AFRICA-SAHEL','AFRICA-NIGERIA'],'{}',true,ARRAY['Al Jazeera','Al-Ahram','Ahram Online','Al Arabiya','Al Arabiya English','Anadolu Agency','Anadolu Ajansı','TRT World','Daily Sabah','Gulf News','Gulf Times','Arab News','UN News','news.un.org'],'sahel_theater',4,'Civilian cost','Ziviler Preis', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('sahel_northern_autonomy_claim','Northern Mali is a political question, not only a military one','Nordmali ist eine politische Frage, nicht nur eine militärische','The Tuareg movements hold Kidal and press a decades-old claim over the north that no government has settled by force; treating an unresolved territorial dispute purely as terrorism forecloses the negotiation that any durable outcome requires.','Die Tuareg-Bewegungen halten Kidal und verfolgen einen jahrzehntealten Anspruch auf den Norden, den keine Regierung militärisch gelöst hat; einen ungelösten Territorialkonflikt allein als Terrorismus zu behandeln, verbaut die Verhandlung, die jede dauerhafte Lösung braucht.',ARRAY['AFRICA-SAHEL'],'{}',true,ARRAY['France 24','France 24 (EN)','Le Monde','Le Figaro','Reuters','Associated Press','BBC World','Deutsche Welle','Die Zeit','Der Spiegel','Euronews','The Guardian','El País','Straits Times','Bangkok Post','NDTV','The Hindu','Kyiv Post','Janes','Al Jazeera','Al-Ahram','Al Arabiya','Anadolu Agency','Gulf News','Republic TV','The National'],'sahel_tuareg_separatism',1,'Unresolved territorial claim','Ungelöster Gebietsanspruch', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('sahel_separatism_as_jihadist_alliance','The separatists are a front for the armed extremists','Die Separatisten sind ein Vorwand für die bewaffneten Extremisten','The northern armed groups now attack alongside al-Qaeda-linked fighters and coordinate their claims with them; that alliance disqualifies any presentation of them as a national-liberation movement with a case to negotiate.','Die bewaffneten Gruppen im Norden greifen inzwischen gemeinsam mit al-Qaida-nahen Kämpfern an und stimmen ihre Erklärungen mit ihnen ab; dieses Bündnis widerlegt jede Darstellung als nationale Befreiungsbewegung mit Verhandlungsanspruch.',ARRAY['AFRICA-SAHEL','EUROPE-RUSSIA'],'{}',true,ARRAY['RT','rt.com','TASS','TASS (EN)','tass.com','tass.ru','RIA Novosti','ria.ru','Kommersant','kommersant.ru','BelTA','BelTA Russian','CGTN','news.cgtn.com','newsaf.cgtn.com','Global Times','China Daily','Xinhua','Vanguard','Vanguard News','Punch','Punch Newspapers'],'sahel_tuareg_separatism',2,'A front for the extremists','Vorwand für die Extremisten',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('somali_state_rebuilding','A state rebuilding with regional partners','Ein Staat im Wiederaufbau mit regionalen Partnern','The federal government is steadily recovering ground and capacity: offensives are pushing al-Shabaab out of districts, offshore energy exploration and Turkish training are building genuine state institutions, and neighbours increasingly treat Mogadishu as a partner rather than a problem.','Die Bundesregierung gewinnt stetig Gebiete und Handlungsfähigkeit zurück: Offensiven drängen al-Shabaab aus Distrikten, Offshore-Energieerkundung und türkische Ausbildung schaffen echte staatliche Institutionen, und die Nachbarn behandeln Mogadischu zunehmend als Partner statt als Problem.',ARRAY['AFRICA-HORN','MIDEAST-TURKEY'],ARRAY['transformation','renewal','institutions','cooperation','partnership','drilling','energy','training','offensive','recaptured','Wiederaufbau','Partnerschaft','Institutionen'],true,ARRAY['Anadolu Agency','Daily Sabah','TRT World','Daily Nation','The Standard','Egypt Today','Al-Ahram','ANSA'],'somalia_state_security',1,'The state is being rebuilt','Der Staat wird wiederaufgebaut',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('somali_fragility_and_harm','A fragile state and an abandoned population','Ein fragiler Staat und eine im Stich gelassene Bevölkerung','The recovery is thinner than claimed: famine is returning as aid funding collapses, the capital saw armed clashes over a delayed election, piracy has resumed off the coast, and the counter-terror campaign is inflicting civilian casualties with little accountability.','Die Erholung ist dünner als behauptet: Mit dem Wegbrechen der Hilfsgelder kehrt die Hungersnot zurück, in der Hauptstadt kam es wegen einer verschobenen Wahl zu bewaffneten Zusammenstößen, vor der Küste ist die Piraterie zurück, und der Anti-Terror-Einsatz fordert zivile Opfer ohne nennenswerte Rechenschaft.',ARRAY['AFRICA-HORN'],ARRAY['famine','hunger','malnutrition','drought','aid','clashes','protest','election delay','piracy','pirates','civilian','casualties','Hungersnot','Dürre','Piraterie','Zusammenstöße'],true,ARRAY['UN News','The Guardian','BBC World','BBC','Reuters','Deutsche Welle','Associated Press','Financial Times','Kurier','France 24','France 24 (EN)','Al Jazeera','The Telegraph','Der Spiegel','Die Zeit','Der Standard','DR','Military Times','Defense News'],'somalia_state_security',2,'Fragility and humanitarian failure','Fragilität und humanitäres Versagen', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('somali_foreign_militarisation_critique','Foreign militarisation is the destabiliser','Ausländische Militarisierung ist der Destabilisator','Somalia''s insecurity is being deepened from outside: American airstrikes kill civilians while Washington blocks UN support for the African Union mission, and an Israeli military foothold on the coast would turn Somali waters into another front in someone else''s war.','Somalias Unsicherheit wird von außen verschärft: Amerikanische Luftangriffe töten Zivilisten, während Washington die UN-Unterstützung für die Mission der Afrikanischen Union blockiert; ein israelischer Militärstützpunkt an der Küste würde somalische Gewässer zu einer weiteren Front in einem fremden Krieg machen.',ARRAY['AFRICA-HORN','AMERICAS-USA'],ARRAY['airstrike','strikes','blocks','blockade','foreign','intervention','base','legitimate target','sovereignty','imperial','Luftangriff','Einmischung','Stützpunkt'],true,ARRAY['RT','Press TV','TASS (EN)','Sputnik'],'somalia_state_security',3,'Outside intervention is to blame','Die Einmischung von außen ist schuld', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('somaliland_statehood_earned','Recognition of an earned statehood','Anerkennung einer erarbeiteten Staatlichkeit','Somaliland has governed itself peacefully and held competitive elections for over three decades, and recognition simply acknowledges a reality the world has ignored; the partnership with Israel opens trade, minerals and security cooperation for a state long locked out of them.','Somaliland regiert sich seit über drei Jahrzehnten friedlich selbst und hält kompetitive Wahlen ab; die Anerkennung bestätigt lediglich eine Realität, die die Welt ignoriert hat. Die Partnerschaft mit Israel eröffnet einem lange ausgeschlossenen Staat Handel, Rohstoffe und Sicherheitskooperation.',ARRAY['AFRICA-HORN','MIDEAST-ISRAEL'],ARRAY['recognition','recognise','recognize','ambassador','embassy','historic','self-determination','democratic','Anerkennung','Botschaft','Selbstbestimmung'],true,ARRAY['Jerusalem Post','Times of Israel','i24NEWS','Haaretz','News24'],'somaliland_recognition_contest',1,'Recognition is deserved','Die Anerkennung ist verdient',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('somali_territorial_integrity','A violation of Somalia''s territorial integrity','Ein Verstoß gegen Somalias territoriale Integrität','Somaliland is part of Somalia under international law and the African Union''s founding principle of inherited borders; a unilateral recognition traded for minerals and a military base is an illegal act that rewards secession and invites external powers to redraw the Horn.','Somaliland ist völkerrechtlich Teil Somalias und unterliegt dem Gründungsprinzip der Afrikanischen Union von der Unverletzlichkeit der ererbten Grenzen. Eine einseitige, gegen Rohstoffe und einen Militärstützpunkt eingetauschte Anerkennung ist ein illegaler Akt, der Sezession belohnt und fremde Mächte einlädt, das Horn neu zu ordnen.',ARRAY['AFRICA-HORN','MIDEAST-EGYPT','MIDEAST-TURKEY'],ARRAY['sovereignty','territorial integrity','illegal','null and void','condemn','reject','violation','interference','Souveränität','territoriale Integrität','verurteilen','völkerrechtswidrig'],true,ARRAY['Al Jazeera','Egypt Today','Al-Ahram','Daily Sabah','Anadolu Agency','Al Arabiya','Arab News','TRT World','Press TV','RT','TASS (EN)','Dawn'],'somaliland_recognition_contest',2,'The recognition is illegitimate','Die Anerkennung ist unrechtmäßig', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('somaliland_transactional_scramble','Statehood traded for bases and minerals','Staatlichkeit im Tausch gegen Stützpunkte und Rohstoffe','Recognition is being priced rather than judged: Somaliland has offered critical minerals and basing rights in exchange for diplomatic status, and the result pulls a stable territory into a Red Sea military scramble it has no capacity to control.','Die Anerkennung wird nicht beurteilt, sondern verhandelt: Somaliland bietet kritische Rohstoffe und Stützpunktrechte im Tausch gegen diplomatischen Status an. Das Ergebnis zieht ein bislang stabiles Gebiet in ein militärisches Wettrennen am Roten Meer, das es nicht kontrollieren kann.',ARRAY['AFRICA-HORN','AMERICAS-USA'],ARRAY['minerals','critical mineral','military base','basing','port','leverage','scramble','strategic','maelstrom','Bodenschätze','Stützpunkt','Militärbasis'],true,ARRAY['Financial Times','Le Monde','Deutsche Welle','IISS','Reuters','BBC World','France 24','France 24 (EN)','Die Zeit','Der Standard','Daily Nation','The Standard'],'somaliland_recognition_contest',3,'A transactional great-power bargain','Ein transaktionaler Großmachthandel', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('usdom_theater_conservative_case','A mandate being executed against institutional resistance','Ein Mandat, das gegen institutionellen Widerstand umgesetzt wird','The administration-aligned reading across the theater: enforcement, personnel changes, electoral rule-tightening and regulatory action are the delivery of an electoral mandate against agencies, courts and media described as resistant to it.','Die regierungsnahe Lesart über das gesamte Feld: Vollzug, Personalwechsel, strengere Wahlregeln und regulatorisches Vorgehen sind die Umsetzung eines Wahlmandats gegen Behörden, Gerichte und Medien, die als widerständig beschrieben werden.',ARRAY['AMERICAS-USA'],'{}',true,ARRAY['Fox News','New York Post','Washington Times','Newsmax'],'us_domestic_theater',1,'Mandate delivery','Umsetzung des Mandats',1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('usdom_theater_liberal_alarm','Checks and balances under sustained strain','Gewaltenteilung unter anhaltender Belastung','The mainstream and international reading across the theater: contested election rules, personnel purges, pressure on the central bank and on broadcasters, and enforcement outrunning due process are treated as a connected strain on American institutional checks -- with the courts as the contested variable.','Die Lesart der Leitmedien und der internationalen Presse über das gesamte Feld: umstrittene Wahlregeln, Personalsäuberungen, Druck auf die Notenbank und auf Sender sowie ein Vollzug, der rechtsstaatliche Verfahren überholt, gelten als zusammenhängende Belastung der institutionellen Kontrolle -- mit den Gerichten als umstrittener Variable.',ARRAY['AMERICAS-USA'],'{}',true,ARRAY['Reuters','Associated Press','AFP','BBC World','BBC','Al Jazeera','Deutsche Welle','France 24 (EN)','France 24','Euronews','Straits Times','Channel NewsAsia','NDTV','Times of India','Indian Express','Hindustan Times','Globe and Mail','News24','Sky News','WION','Anadolu Agency','Dawn','CBC','ABC News','SMH.com.au','Philippine Daily Inquirer','NHK World','KBS World','Al Arabiya','i24NEWS','Jerusalem Post','Haaretz','Times of Israel','El País','Le Monde','Le Figaro','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Corriere della Sera','La Repubblica','Tagesschau','Der Standard','Die Presse','Kurier','Handelsblatt','Neue Zürcher Zeitung','Swissinfo','iROZHLAS','ERR News','The Telegraph','CNN','New York Times','Washington Post','NPR','The Guardian','MSNBC','Reuters','Associated Press','AFP','BBC World','BBC','Al Jazeera','Deutsche Welle','France 24 (EN)','France 24','Euronews','Straits Times','Channel NewsAsia','NDTV','Times of India','Indian Express','Hindustan Times','Globe and Mail','News24','Sky News','WION','Anadolu Agency','Dawn','CBC','ABC News','SMH.com.au','Philippine Daily Inquirer','NHK World','KBS World','Al Arabiya','i24NEWS','Jerusalem Post','Haaretz','Times of Israel','El País','Le Monde','Le Figaro','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Corriere della Sera','La Repubblica','Tagesschau','Der Standard','Die Presse','Kurier','Handelsblatt','Neue Zürcher Zeitung','Swissinfo','iROZHLAS','ERR News','The Telegraph','Financial Times','Bloomberg','Bloomberg.com','Wall Street Journal','The Economist','S&P Global','Nikkei Asia','OilPrice','Reuters','Handelsblatt','Swissinfo'],'us_domestic_theater',2,'Institutional strain','Institutionelle Belastung', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('usdom_theater_decline','American decline and the collapse of its claim to model status','Amerikanischer Niedergang und das Ende des Vorbildanspruchs','The Russian, Chinese and Iranian state reading across the theater: elite impunity, domestic policing, contested elections, politicised money and pressure on media are assembled into a single argument that the United States has no standing to set standards for others. Bystander framing, not support for any American faction.','Die Lesart russischer, chinesischer und iranischer Staatsmedien über das gesamte Feld: Straflosigkeit der Eliten, innere Überwachung, umstrittene Wahlen, politisiertes Geld und Druck auf Medien werden zu einem einzigen Argument verbunden -- die Vereinigten Staaten könnten für andere keine Maßstäbe setzen. Eine Außenperspektive, keine Unterstützung einer amerikanischen Fraktion.',ARRAY['AMERICAS-USA'],ARRAY['hypocrisy','double standard','decline','decay','crisis of democracy','so-called democracy','impunity','elite','Heuchelei','Doppelmoral','Niedergang','hipocresía','declive'],true,ARRAY['RT','TASS','TASS (EN)','Sputnik','CGTN','Global Times','China Daily','People''s Daily','Xinhua','Press TV','Tehran Times','IRNA'],'us_domestic_theater',3,'No standing to lead','Kein Führungsanspruch', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('usdom_electoral_integrity_case','Tightening the rules is protecting the integrity of the vote','Strengere Regeln schützen die Integrität der Wahl','Coverage presenting voter-ID requirements, proof-of-citizenship rules, voter-roll maintenance and limits on mail balloting as ordinary safeguards against fraud, and redistricting as a lawful power of elected state legislatures. Vocabulary: integrity, safeguard, proof of citizenship, voter ID, clean rolls, secure.','Berichterstattung, die Ausweispflichten, Staatsbürgerschaftsnachweise, die Pflege der Wählerverzeichnisse und Beschränkungen der Briefwahl als übliche Schutzmaßnahmen gegen Betrug darstellt und den Neuzuschnitt von Wahlkreisen als rechtmäßige Befugnis gewählter Parlamente.',ARRAY['AMERICAS-USA'],ARRAY['integrity','safeguard','secure','proof of citizenship','voter ID','clean','fraud','verify','lawful','constitutional','Integrität','Wahlbetrug','Nachweis','rechtmäßig'],true,ARRAY['Reuters','Associated Press','AFP','BBC World','BBC','Al Jazeera','Deutsche Welle','France 24 (EN)','France 24','Euronews','Straits Times','Channel NewsAsia','NDTV','Times of India','Indian Express','Hindustan Times','Globe and Mail','News24','Sky News','WION','Anadolu Agency','Dawn','CBC','ABC News','SMH.com.au','Philippine Daily Inquirer','NHK World','KBS World','Al Arabiya','i24NEWS','Jerusalem Post','Haaretz','Times of Israel','Fox News','New York Post','Washington Times','Newsmax'],'us_electoral_legitimacy',1,'Integrity safeguards','Schutz der Wahlintegrität',1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('usdom_electoral_franchise_threat','The rules are being rewritten to shape the result in advance','Die Regeln werden umgeschrieben, um das Ergebnis vorab zu formen','Coverage documenting mid-cycle redistricting races between states, the Voting Rights Act narrowed, mail-ballot restrictions struck down and reimposed, proof-of-citizenship bills, an FBI raid on a voting-rights group, and open discussion of how an incumbent might tilt a midterm. Vocabulary: gerrymander, tilt, crackdown, restrict, purge, strike down, block, master plan.','Berichterstattung über Neuzuschnitte von Wahlkreisen mitten im Zyklus, die Einschränkung des Voting Rights Act, gekippte und wieder eingeführte Briefwahlbeschränkungen, Gesetze zum Staatsbürgerschaftsnachweis, eine FBI-Razzia bei einer Wahlrechtsorganisation und offene Debatten darüber, wie ein Amtsinhaber eine Zwischenwahl beeinflussen könnte.',ARRAY['AMERICAS-USA'],ARRAY['gerrymander','tilt','crackdown','restrict','restriction','purge','strike down','struck down','blocks','blocked','suppress','master plan','raid','meddle','meddling','advantage','splinter','rig','Wahlkreis','Einschränkung','Razzia','manipulieren'],true,ARRAY['Reuters','Associated Press','AFP','BBC World','BBC','Al Jazeera','Deutsche Welle','France 24 (EN)','France 24','Euronews','Straits Times','Channel NewsAsia','NDTV','Times of India','Indian Express','Hindustan Times','Globe and Mail','News24','Sky News','WION','Anadolu Agency','Dawn','CBC','ABC News','SMH.com.au','Philippine Daily Inquirer','NHK World','KBS World','Al Arabiya','i24NEWS','Jerusalem Post','Haaretz','Times of Israel','El País','Le Monde','Le Figaro','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Corriere della Sera','La Repubblica','Tagesschau','Der Standard','Die Presse','Kurier','Handelsblatt','Neue Zürcher Zeitung','Swissinfo','iROZHLAS','ERR News','The Telegraph','CNN','New York Times','Washington Post','NPR','The Guardian','MSNBC','El País','Le Monde','Le Figaro','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Corriere della Sera','La Repubblica','Tagesschau','Der Standard','Die Presse','Kurier','Handelsblatt','Neue Zürcher Zeitung','Swissinfo','iROZHLAS','ERR News','The Telegraph'],'us_electoral_legitimacy',2,'Franchise under pressure','Wahlrecht unter Druck', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('usdom_electoral_democracy_facade','A system that lectures others while contesting its own elections','Ein System, das andere belehrt und die eigenen Wahlen bestreitet','Russian, Chinese and Iranian state coverage using redistricting fights, ballot litigation and fraud claims to argue that American electoral democracy is a facade, and that US election observation and democracy promotion abroad lack standing.','Russische, chinesische und iranische Staatsmedien nutzen Streit um Wahlkreise, Klagen um Stimmzettel und Betrugsvorwürfe, um zu argumentieren, die amerikanische Wahldemokratie sei eine Fassade und die US-Wahlbeobachtung im Ausland entbehre der Grundlage.',ARRAY['AMERICAS-USA'],ARRAY['hypocrisy','double standard','decline','decay','crisis of democracy','so-called democracy','impunity','elite','Heuchelei','Doppelmoral','Niedergang','hipocresía','declive'],true,ARRAY['RT','TASS','TASS (EN)','Sputnik','CGTN','Global Times','China Daily','People''s Daily','Xinhua','Press TV','Tehran Times','IRNA'],'us_electoral_legitimacy',3,'Democracy as facade','Demokratie als Fassade', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('usdom_epstein_accountability','The files are forcing accountability on a protected elite','Die Akten erzwingen Rechenschaft von einer geschützten Elite','Wire, international and US coverage treating the document releases, depositions and contempt votes as an accountability process that is working: names are surfacing across both parties and across borders, witnesses are being compelled to testify, and figures long thought untouchable are being questioned, charged or forced to resign. Vocabulary: unseal, release, testify, deposition, subpoena, contempt, grilled, indicted, arrest, resign.','Agentur-, internationale und US-Berichterstattung, die Aktenfreigaben, Vernehmungen und Missachtungsbeschlüsse als funktionierenden Rechenschaftsprozess darstellt: Namen tauchen partei- und länderübergreifend auf, Zeugen werden zur Aussage gezwungen, und lange unantastbar geglaubte Personen werden befragt, angeklagt oder zum Rücktritt gedrängt.',ARRAY['AMERICAS-USA'],ARRAY['unseal','unsealed','release','released','testify','testifies','testimony','deposition','subpoena','contempt','grilled','indicted','charged','arrest','resign','steps down','probe','investigation','files show','documents','freigegeben','Aussage','Vernehmung','Ermittlung','zurückgetreten','Rücktritt','declassified'],true,ARRAY['Reuters','Associated Press','AFP','BBC World','BBC','Al Jazeera','Deutsche Welle','France 24 (EN)','France 24','Euronews','Straits Times','Channel NewsAsia','NDTV','Times of India','Indian Express','Hindustan Times','Globe and Mail','News24','Sky News','WION','Anadolu Agency','Dawn','CBC','ABC News','SMH.com.au','Philippine Daily Inquirer','NHK World','KBS World','Al Arabiya','i24NEWS','Jerusalem Post','Haaretz','Times of Israel','El País','Le Monde','Le Figaro','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Corriere della Sera','La Repubblica','Tagesschau','Der Standard','Die Presse','Kurier','Handelsblatt','Neue Zürcher Zeitung','Swissinfo','iROZHLAS','ERR News','The Telegraph','CNN','New York Times','Washington Post','NPR','The Guardian','MSNBC','Fox News','New York Post','Washington Times','Newsmax'],'us_epstein_elite_network',1,'Accountability advancing','Rechenschaft schreitet voran',1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('usdom_epstein_obstruction','Disclosure is being managed, delayed and selectively withheld','Die Offenlegung wird gesteuert, verzögert und selektiv zurückgehalten','Coverage arguing the release process is being controlled to protect the powerful: files redacted or withheld, testimony taken behind closed doors, the attorney general accused of shielding names, witnesses pleading the Fifth, and briefings dismissed as theatre. Vocabulary: hiding, withheld, redacted, sealed, stonewall, closed-door, refuses, blocked, cover-up.','Berichterstattung, die argumentiert, der Freigabeprozess werde zum Schutz der Mächtigen gesteuert: geschwärzte oder zurückgehaltene Akten, Aussagen hinter verschlossenen Türen, eine Justizministerin, der vorgeworfen wird, Namen zu decken, Zeugen, die die Aussage verweigern, und als Theater abgetane Unterrichtungen.',ARRAY['AMERICAS-USA'],ARRAY['hiding','hidden','withheld','withholding','redacted','redactions','sealed','stonewall','closed-door','behind closed doors','refuses','refused','blocked','cover-up','coverup','pleads the Fifth','Fifth Amendment','excused','fake hearing','walk out','delay','zurückgehalten','geschwärzt','verweigert','Vertuschung','blockiert'],true,ARRAY['Reuters','Associated Press','AFP','BBC World','BBC','Al Jazeera','Deutsche Welle','France 24 (EN)','France 24','Euronews','Straits Times','Channel NewsAsia','NDTV','Times of India','Indian Express','Hindustan Times','Globe and Mail','News24','Sky News','WION','Anadolu Agency','Dawn','CBC','ABC News','SMH.com.au','Philippine Daily Inquirer','NHK World','KBS World','Al Arabiya','i24NEWS','Jerusalem Post','Haaretz','Times of Israel','El País','Le Monde','Le Figaro','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Corriere della Sera','La Repubblica','Tagesschau','Der Standard','Die Presse','Kurier','Handelsblatt','Neue Zürcher Zeitung','Swissinfo','iROZHLAS','ERR News','The Telegraph','CNN','New York Times','Washington Post','NPR','The Guardian','MSNBC'],'us_epstein_elite_network',2,'Disclosure obstructed','Offenlegung blockiert', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('usdom_epstein_western_impunity','A Western elite protecting itself, exposed by its own scandal','Eine westliche Elite, die sich selbst schützt, entlarvt durch den eigenen Skandal','Russian, Chinese and Iranian state coverage using the Epstein files to indict the Western establishment as a class -- British ministers and envoys, Scandinavian royals, EU diplomats, philanthropists and financiers -- and to argue that the moral authority the West claims abroad is not supported at home. Not aligned with either American party: the target is Western elite impunity itself, extending to conspiratorial framing.','Russische, chinesische und iranische Staatsmedien nutzen die Epstein-Akten, um das westliche Establishment als Klasse anzuklagen -- britische Minister und Gesandte, skandinavische Royals, EU-Diplomaten, Philanthropen und Finanziers -- und zu argumentieren, die vom Westen im Ausland beanspruchte moralische Autorität sei im Inneren nicht gedeckt. Keiner US-Partei zugeordnet: Ziel ist die Straflosigkeit westlicher Eliten selbst.',ARRAY['AMERICAS-USA'],ARRAY['hypocrisy','double standard','decline','decay','crisis of democracy','so-called democracy','impunity','elite','Heuchelei','Doppelmoral','Niedergang','hipocresía','declive'],true,ARRAY['RT','TASS','TASS (EN)','Sputnik','CGTN','Global Times','China Daily','People''s Daily','Xinhua','Press TV','Tehran Times','IRNA'],'us_epstein_elite_network',3,'Western elite impunity','Straflosigkeit westlicher Eliten', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('usdom_loyalty_prerogative','A president is entitled to a team that executes his agenda','Ein Präsident hat Anspruch auf ein Team, das seine Agenda umsetzt','Coverage treating dismissals, resignations and replacements across the cabinet, the FBI and the intelligence agencies as the normal prerogative of an elected executive removing officials who will not deliver, and as overdue housecleaning of agencies described as resistant.','Berichterstattung, die Entlassungen, Rücktritte und Neubesetzungen im Kabinett, beim FBI und bei den Nachrichtendiensten als normales Vorrecht einer gewählten Exekutive darstellt, Amtsträger zu entfernen, die nicht liefern, und als überfälligen Hausputz in als widerständig beschriebenen Behörden.',ARRAY['AMERICAS-USA'],'{}',true,ARRAY['Fox News','New York Post','Washington Times','Newsmax'],'us_executive_loyalty',1,'Executive prerogative','Vorrecht der Exekutive',1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('usdom_loyalty_hollowing','Professional institutions are being hollowed out by loyalty tests','Fachbehörden werden durch Loyalitätsprüfungen ausgehöhlt','Coverage of a rolling cycle of dismissals and resignations -- an attorney general removed, a homeland security secretary out, an intelligence chief resigning, FBI agents fired over past investigations, inspectors general and prosecutors displaced -- read as the replacement of professional judgement with personal loyalty, and as a loss of institutional capacity.','Berichterstattung über eine fortlaufende Kette von Entlassungen und Rücktritten -- eine abberufene Justizministerin, eine ausgeschiedene Heimatschutzministerin, eine zurückgetretene Geheimdienstkoordinatorin, wegen früherer Ermittlungen entlassene FBI-Beamte, verdrängte Generalinspekteure und Staatsanwälte -- gelesen als Ersetzung fachlichen Urteils durch persönliche Loyalität.',ARRAY['AMERICAS-USA'],ARRAY['fired','fires','firing','ousted','ouster','removed','removal','resign','resigns','resignation','steps down','quit','exit','purge','purges','shakeup','shake-up','next on','forced out','dismissed','sacked','acting','temporary','vacancy','raise questions','concerned','loyalty','loyalist','entlassen','Rücktritt','abberufen','besorgt','Säuberung','destituida','dimite','renuncia'],true,ARRAY['Reuters','Associated Press','AFP','BBC World','BBC','Al Jazeera','Deutsche Welle','France 24 (EN)','France 24','Euronews','Straits Times','Channel NewsAsia','NDTV','Times of India','Indian Express','Hindustan Times','Globe and Mail','News24','Sky News','WION','Anadolu Agency','Dawn','CBC','ABC News','SMH.com.au','Philippine Daily Inquirer','NHK World','KBS World','Al Arabiya','i24NEWS','Jerusalem Post','Haaretz','Times of Israel','El País','Le Monde','Le Figaro','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Corriere della Sera','La Repubblica','Tagesschau','Der Standard','Die Presse','Kurier','Handelsblatt','Neue Zürcher Zeitung','Swissinfo','iROZHLAS','ERR News','The Telegraph','CNN','New York Times','Washington Post','NPR','The Guardian','MSNBC','Reuters','Associated Press','AFP','BBC World','BBC','Al Jazeera','Deutsche Welle','France 24 (EN)','France 24','Euronews','Straits Times','Channel NewsAsia','NDTV','Times of India','Indian Express','Hindustan Times','Globe and Mail','News24','Sky News','WION','Anadolu Agency','Dawn','CBC','ABC News','SMH.com.au','Philippine Daily Inquirer','NHK World','KBS World','Al Arabiya','i24NEWS','Jerusalem Post','Haaretz','Times of Israel','El País','Le Monde','Le Figaro','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Corriere della Sera','La Repubblica','Tagesschau','Der Standard','Die Presse','Kurier','Handelsblatt','Neue Zürcher Zeitung','Swissinfo','iROZHLAS','ERR News','The Telegraph'],'us_executive_loyalty',2,'Institutional hollowing','Aushöhlung der Institutionen', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('usdom_loyalty_court_politics','Court politics inside a distracted superpower','Hofpolitik in einer abgelenkten Supermacht','Russian, Chinese and Iranian state coverage reading the churn of American cabinet appointments as palace intrigue and evidence of an administration consumed by internal rivalry rather than governing -- used to argue that Washington is an unreliable counterpart.','Russische, chinesische und iranische Staatsmedien deuten den ständigen Wechsel im amerikanischen Kabinett als Palastintrige und als Beleg für eine von internen Rivalitäten aufgezehrte Regierung -- genutzt für das Argument, Washington sei ein unzuverlässiger Partner.',ARRAY['AMERICAS-USA'],ARRAY['hypocrisy','double standard','decline','decay','crisis of democracy','so-called democracy','impunity','elite','Heuchelei','Doppelmoral','Niedergang','hipocresía','declive'],true,ARRAY['RT','TASS','TASS (EN)','Sputnik','CGTN','Global Times','China Daily','People''s Daily','Xinhua','Press TV','Tehran Times','IRNA'],'us_executive_loyalty',3,'Palace intrigue','Palastintrige', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('usdom_fed_orderly_succession','A normal succession that leaves the institution intact','Eine normale Nachfolge, die die Institution unangetastet lässt','Business and wire coverage treating the chair nomination and Senate confirmation as an ordinary handover -- a nominee clearing committee, an incumbent serving out his term, the board continuing to set policy on its own reading of inflation -- and stressing that the legal architecture of independence has held. Vocabulary: confirmation, clears, nomination, hearing, term, transition, independent.','Wirtschafts- und Agenturberichterstattung, die die Nominierung des Vorsitzes und die Bestätigung durch den Senat als gewöhnliche Übergabe behandelt -- ein Kandidat, der den Ausschuss passiert, ein Amtsinhaber, der seine Amtszeit beendet, ein Gremium, das die Politik weiter nach eigener Einschätzung der Inflation bestimmt.',ARRAY['AMERICAS-USA'],ARRAY['confirmation','confirm','clears','nomination','nominate','hearing','term','transition','independent','independence','stays on','remain','Bestätigung','Nominierung','Amtszeit','unabhängig'],true,ARRAY['Financial Times','Bloomberg','Bloomberg.com','Wall Street Journal','The Economist','S&P Global','Nikkei Asia','OilPrice','Reuters','Handelsblatt','Swissinfo','Reuters','Associated Press','AFP','BBC World','BBC','Al Jazeera','Deutsche Welle','France 24 (EN)','France 24','Euronews','Straits Times','Channel NewsAsia','NDTV','Times of India','Indian Express','Hindustan Times','Globe and Mail','News24','Sky News','WION','Anadolu Agency','Dawn','CBC','ABC News','SMH.com.au','Philippine Daily Inquirer','NHK World','KBS World','Al Arabiya','i24NEWS','Jerusalem Post','Haaretz','Times of Israel'],'us_fed_independence',1,'Orderly succession','Geordnete Nachfolge',1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('usdom_fed_capture_risk','Political pressure is testing the limits of central-bank independence','Politischer Druck testet die Grenzen der Notenbankunabhängigkeit','Coverage of the pressure side of the same story -- an attempt to remove a sitting governor blocked in court, a criminal referral against the chair later dropped, public demands that he resign, a chair warning the institution is under a stress test and that lost credibility is hard to restore. Vocabulary: fire, remove, pressure, threat, probe, resign, stress test, credibility, clash.','Berichterstattung über die Druckseite derselben Geschichte -- ein vor Gericht gestoppter Versuch, eine amtierende Gouverneurin zu entfernen, eine später fallengelassene Strafanzeige gegen den Vorsitzenden, öffentliche Rücktrittsforderungen und die Warnung, die Institution stehe unter einem Stresstest und verlorene Glaubwürdigkeit sei schwer wiederherzustellen.',ARRAY['AMERICAS-USA'],ARRAY['fire','fired','firing','remove','removal','oust','pressure','threat','threatens','probe','resign','step down','stress test','credibility','clash','attack','entlassen','Druck','Rücktritt','Glaubwürdigkeit','Stresstest','despido','presión'],true,ARRAY['Financial Times','Bloomberg','Bloomberg.com','Wall Street Journal','The Economist','S&P Global','Nikkei Asia','OilPrice','Reuters','Handelsblatt','Swissinfo','Reuters','Associated Press','AFP','BBC World','BBC','Al Jazeera','Deutsche Welle','France 24 (EN)','France 24','Euronews','Straits Times','Channel NewsAsia','NDTV','Times of India','Indian Express','Hindustan Times','Globe and Mail','News24','Sky News','WION','Anadolu Agency','Dawn','CBC','ABC News','SMH.com.au','Philippine Daily Inquirer','NHK World','KBS World','Al Arabiya','i24NEWS','Jerusalem Post','Haaretz','Times of Israel','El País','Le Monde','Le Figaro','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Corriere della Sera','La Repubblica','Tagesschau','Der Standard','Die Presse','Kurier','Handelsblatt','Neue Zürcher Zeitung','Swissinfo','iROZHLAS','ERR News','The Telegraph','CNN','New York Times','Washington Post','NPR','The Guardian','MSNBC','El País','Le Monde','Le Figaro','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Corriere della Sera','La Repubblica','Tagesschau','Der Standard','Die Presse','Kurier','Handelsblatt','Neue Zürcher Zeitung','Swissinfo','iROZHLAS','ERR News','The Telegraph'],'us_fed_independence',2,'Independence under pressure','Unabhängigkeit unter Druck', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('usdom_fed_dollar_decline','Politicised money and the erosion of the dollar order','Politisiertes Geld und die Erosion der Dollarordnung','Russian, Chinese and Iranian state coverage reading the fight over the central bank as confirmation that the dollar system is politically managed and unreliable, and as an argument for reserve diversification and settlement outside US institutions.','Russische, chinesische und iranische Staatsmedien deuten den Streit um die Notenbank als Bestätigung, dass das Dollarsystem politisch gesteuert und unzuverlässig sei, und als Argument für die Diversifizierung von Reserven und Abwicklung außerhalb US-amerikanischer Institutionen.',ARRAY['AMERICAS-USA'],ARRAY['hypocrisy','double standard','decline','decay','crisis of democracy','so-called democracy','impunity','elite','Heuchelei','Doppelmoral','Niedergang','hipocresía','declive'],true,ARRAY['RT','TASS','TASS (EN)','Sputnik','CGTN','Global Times','China Daily','People''s Daily','Xinhua','Press TV','Tehran Times','IRNA'],'us_fed_independence',3,'Dollar order eroding','Erosion der Dollarordnung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('usdom_ice_enforcement_mandate','Enforcement is delivering a mandate voters asked for','Der Vollzug setzt ein von den Wählern gefordertes Mandat um','Coverage presenting interior enforcement as lawful execution of immigration statute and an electoral mandate: removals of people with criminal records, funding votes in Congress, court wins expanding executive discretion, and officers portrayed as targeted by violence. Vocabulary: criminal record, convicted, funding, mandate, law enforcement, officers assaulted.','Berichterstattung, die den Vollzug im Landesinneren als rechtmäßige Umsetzung des Einwanderungsrechts und eines Wahlmandats darstellt: Abschiebungen von Personen mit Vorstrafen, Finanzierungsabstimmungen im Kongress, Gerichtserfolge und als Gewaltopfer dargestellte Beamte.',ARRAY['AMERICAS-USA'],ARRAY['criminal record','convicted','criminal alien','public safety','funding','mandate','law enforcement','assaulted','attack on officers','illegal immigrant','fugitive','vollzogen','Straftäter','Vorstrafen'],true,ARRAY['Reuters','Associated Press','AFP','BBC World','BBC','Al Jazeera','Deutsche Welle','France 24 (EN)','France 24','Euronews','Straits Times','Channel NewsAsia','NDTV','Times of India','Indian Express','Hindustan Times','Globe and Mail','News24','Sky News','WION','Anadolu Agency','Dawn','CBC','ABC News','SMH.com.au','Philippine Daily Inquirer','NHK World','KBS World','Al Arabiya','i24NEWS','Jerusalem Post','Haaretz','Times of Israel','Fox News','New York Post','Washington Times','Newsmax'],'us_interior_immigration_enforcement',1,'Lawful enforcement','Rechtmäßiger Vollzug',1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('usdom_ice_due_process','Enforcement is outrunning due process and harming residents','Der Vollzug überholt rechtsstaatliche Verfahren und schadet Anwohnern','Coverage documenting deaths and illness in detention, arrests without warrants, detained children and elderly people, long-resident and legally present people swept up, judges ordering releases, and the chilling effect on schools, clinics and workplaces. Vocabulary: died in custody, without a warrant, judge orders release, detained despite, fear, raid on.','Berichterstattung über Todesfälle und Krankheiten in Haft, Festnahmen ohne Haftbefehl, inhaftierte Kinder und Ältere, langjährig oder legal Ansässige, die miterfasst werden, Richter, die Freilassungen anordnen, und die Abschreckungswirkung auf Schulen, Kliniken und Arbeitsplätze.',ARRAY['AMERICAS-USA'],ARRAY['died','death','custody','without a warrant','no warrant','orders release','release of','despite','fear','chilling','citizen','wrongly','mistakenly','children','5-year-old','86','rights','lawyers say','Todesfälle','Gewahrsam','ohne Haftbefehl','Angst','Freilassung','zu Unrecht','muerte','sin orden','miedo'],true,ARRAY['Reuters','Associated Press','AFP','BBC World','BBC','Al Jazeera','Deutsche Welle','France 24 (EN)','France 24','Euronews','Straits Times','Channel NewsAsia','NDTV','Times of India','Indian Express','Hindustan Times','Globe and Mail','News24','Sky News','WION','Anadolu Agency','Dawn','CBC','ABC News','SMH.com.au','Philippine Daily Inquirer','NHK World','KBS World','Al Arabiya','i24NEWS','Jerusalem Post','Haaretz','Times of Israel','El País','Le Monde','Le Figaro','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Corriere della Sera','La Repubblica','Tagesschau','Der Standard','Die Presse','Kurier','Handelsblatt','Neue Zürcher Zeitung','Swissinfo','iROZHLAS','ERR News','The Telegraph','CNN','New York Times','Washington Post','NPR','The Guardian','MSNBC','El País','Le Monde','Le Figaro','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Corriere della Sera','La Repubblica','Tagesschau','Der Standard','Die Presse','Kurier','Handelsblatt','Neue Zürcher Zeitung','Swissinfo','iROZHLAS','ERR News','The Telegraph'],'us_interior_immigration_enforcement',2,'Due-process alarm','Rechtsstaatliche Bedenken', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('usdom_ice_american_repression','A self-described democracy policing its own population','Eine selbsternannte Demokratie, die die eigene Bevölkerung überwacht','Russian, Chinese and Iranian state coverage using interior immigration raids to argue that American human-rights advocacy abroad is contradicted by its conduct at home -- masked agents, detention deaths, operations at schools and stadiums -- and to reject US standing to criticise others.','Russische, chinesische und iranische Staatsmedien nutzen Einwanderungsrazzien im Landesinneren, um zu argumentieren, dass amerikanisches Eintreten für Menschenrechte im Ausland dem eigenen Verhalten im Inland widerspricht, und sprechen den USA das Recht ab, andere zu kritisieren.',ARRAY['AMERICAS-USA'],ARRAY['hypocrisy','double standard','decline','decay','crisis of democracy','so-called democracy','impunity','elite','Heuchelei','Doppelmoral','Niedergang','hipocresía','declive'],true,ARRAY['RT','TASS','TASS (EN)','Sputnik','CGTN','Global Times','China Daily','People''s Daily','Xinhua','Press TV','Tehran Times','IRNA'],'us_interior_immigration_enforcement',3,'American repression','Amerikanische Repression', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('usdom_courts_checks_hold','The courts are still binding the executive','Die Gerichte binden die Exekutive weiterhin','Coverage of rulings that constrained the administration -- birthright citizenship upheld, the global tariff order struck down, a Federal Reserve governor kept in office, mail-ballot orders enjoined -- read as evidence that judicial review still functions. Vocabulary: rejects, strikes down, blocks, upholds, denies, rules against, injunction.','Berichterstattung über Urteile, die die Regierung einschränkten -- Bestätigung des Geburtsortsprinzips, Aufhebung der globalen Zollanordnung, Verbleib einer Fed-Vorständin im Amt, einstweilige Verfügungen gegen Briefwahlanordnungen -- gelesen als Beleg, dass richterliche Kontrolle weiterhin funktioniert.',ARRAY['AMERICAS-USA'],ARRAY['rejects','rejected','strikes down','struck down','blocks','blocked','upholds','upheld','denies','denied','rules against','injunction','setback for','loses','quashes','abgewiesen','gekippt','Rückschlag','bestätigt','Verfügung'],true,ARRAY['Reuters','Associated Press','AFP','BBC World','BBC','Al Jazeera','Deutsche Welle','France 24 (EN)','France 24','Euronews','Straits Times','Channel NewsAsia','NDTV','Times of India','Indian Express','Hindustan Times','Globe and Mail','News24','Sky News','WION','Anadolu Agency','Dawn','CBC','ABC News','SMH.com.au','Philippine Daily Inquirer','NHK World','KBS World','Al Arabiya','i24NEWS','Jerusalem Post','Haaretz','Times of Israel','El País','Le Monde','Le Figaro','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Corriere della Sera','La Repubblica','Tagesschau','Der Standard','Die Presse','Kurier','Handelsblatt','Neue Zürcher Zeitung','Swissinfo','iROZHLAS','ERR News','The Telegraph','CNN','New York Times','Washington Post','NPR','The Guardian','MSNBC','Reuters','Associated Press','AFP','BBC World','BBC','Al Jazeera','Deutsche Welle','France 24 (EN)','France 24','Euronews','Straits Times','Channel NewsAsia','NDTV','Times of India','Indian Express','Hindustan Times','Globe and Mail','News24','Sky News','WION','Anadolu Agency','Dawn','CBC','ABC News','SMH.com.au','Philippine Daily Inquirer','NHK World','KBS World','Al Arabiya','i24NEWS','Jerusalem Post','Haaretz','Times of Israel'],'us_judicial_constraint',1,'Checks holding','Kontrolle greift',1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('usdom_courts_deference','The bench is expanding executive discretion rather than checking it','Die Richterbank erweitert den Ermessensspielraum der Exekutive, statt ihn zu begrenzen','Coverage of the other half of the docket -- removal power upheld, immigration discretion expanded, emergency-docket orders issued without full argument, state policies overridden -- and of a court whose composition and procedure are themselves now contested. Vocabulary: expands, backs, allows, sides with, clears path, shadow docket, unprecedented, reshaping.','Berichterstattung über die andere Hälfte der Fälle -- Bestätigung der Entlassungsbefugnis, erweitertes Ermessen bei der Einwanderung, Beschlüsse im Eilverfahren ohne vollständige Verhandlung, überstimmte Bundesstaaten -- und über ein Gericht, dessen Zusammensetzung und Verfahren selbst umstritten sind.',ARRAY['AMERICAS-USA'],ARRAY['expands','expanded','backs','allows','sides with','clears path','clears the way','shadow docket','unprecedented','reshaping','power','hails','victory for','boosts','lets','erweitert','stärkt','beispiellos','Sieg für'],true,ARRAY['Reuters','Associated Press','AFP','BBC World','BBC','Al Jazeera','Deutsche Welle','France 24 (EN)','France 24','Euronews','Straits Times','Channel NewsAsia','NDTV','Times of India','Indian Express','Hindustan Times','Globe and Mail','News24','Sky News','WION','Anadolu Agency','Dawn','CBC','ABC News','SMH.com.au','Philippine Daily Inquirer','NHK World','KBS World','Al Arabiya','i24NEWS','Jerusalem Post','Haaretz','Times of Israel','El País','Le Monde','Le Figaro','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Corriere della Sera','La Repubblica','Tagesschau','Der Standard','Die Presse','Kurier','Handelsblatt','Neue Zürcher Zeitung','Swissinfo','iROZHLAS','ERR News','The Telegraph','CNN','New York Times','Washington Post','NPR','The Guardian','MSNBC','El País','Le Monde','Le Figaro','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Corriere della Sera','La Repubblica','Tagesschau','Der Standard','Die Presse','Kurier','Handelsblatt','Neue Zürcher Zeitung','Swissinfo','iROZHLAS','ERR News','The Telegraph'],'us_judicial_constraint',2,'Deference to the executive','Nachgiebigkeit gegenüber der Exekutive', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('usdom_courts_politicised','A judiciary treated as an instrument of factional power','Eine Justiz, die als Instrument fraktioneller Macht behandelt wird','Russian, Chinese and Iranian state coverage presenting American courts as an arena of partisan capture rather than neutral adjudication, and using that reading to reject US commentary on judicial independence elsewhere.','Russische, chinesische und iranische Staatsmedien stellen amerikanische Gerichte als Arena parteipolitischer Vereinnahmung statt neutraler Rechtsprechung dar und weisen damit US-Kommentare zur richterlichen Unabhängigkeit andernorts zurück.',ARRAY['AMERICAS-USA'],ARRAY['hypocrisy','double standard','decline','decay','crisis of democracy','so-called democracy','impunity','elite','Heuchelei','Doppelmoral','Niedergang','hipocresía','declive'],true,ARRAY['RT','TASS','TASS (EN)','Sputnik','CGTN','Global Times','China Daily','People''s Daily','Xinhua','Press TV','Tehran Times','IRNA'],'us_judicial_constraint',3,'Judiciary politicised','Politisierte Justiz', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('usdom_violence_protective_response','The protective response worked and the perpetrators face the law','Der Personenschutz funktionierte und die Täter stehen vor Gericht','Coverage centred on the security response and the prosecutions: agents returning fire and evacuating principals, a suspect identified and charged, a plot against a public event foiled, and officials thanking their details. Vocabulary: evacuated, whisked, detained, identified, charged, pleads, indicted, foiled, thanks.','Berichterstattung mit Schwerpunkt auf Sicherheitsreaktion und Strafverfolgung: Beamte, die das Feuer erwidern und Schutzpersonen evakuieren, ein identifizierter und angeklagter Verdächtiger, ein vereitelter Anschlag auf eine öffentliche Veranstaltung und Amtsträger, die ihren Schutzkommandos danken.',ARRAY['AMERICAS-USA'],ARRAY['evacuated','whisked','detained','identified','charged','pleads','indicted','convicted','foiled','thanks','arrested','shot dead','suspect','evakuiert','festgenommen','angeklagt','vereitelt','Verdächtiger'],true,ARRAY['Reuters','Associated Press','AFP','BBC World','BBC','Al Jazeera','Deutsche Welle','France 24 (EN)','France 24','Euronews','Straits Times','Channel NewsAsia','NDTV','Times of India','Indian Express','Hindustan Times','Globe and Mail','News24','Sky News','WION','Anadolu Agency','Dawn','CBC','ABC News','SMH.com.au','Philippine Daily Inquirer','NHK World','KBS World','Al Arabiya','i24NEWS','Jerusalem Post','Haaretz','Times of Israel','Fox News','New York Post','Washington Times','Newsmax'],'us_political_violence',1,'Protective response','Schutzreaktion',1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('usdom_violence_climate','Violence is becoming a recurring feature of political life','Gewalt wird zu einem wiederkehrenden Merkmal des politischen Lebens','Coverage treating the incidents as a pattern rather than isolated events: repeated attempts against a president, a member of Congress attacked at a town hall, judges reporting threats and requiring heightened security, polling showing large numbers disbelieve official accounts, and warnings about the climate that produces this. Vocabulary: threats, climate, rhetoric, polarisation, again, pattern, security for judges, conspiracy.','Berichterstattung, die die Vorfälle als Muster statt als Einzelfälle behandelt: wiederholte Anschläge auf einen Präsidenten, ein Angriff auf ein Kongressmitglied bei einer Bürgerversammlung, Richter, die Drohungen melden und verstärkten Schutz benötigen, Umfragen, wonach viele den offiziellen Darstellungen misstrauen, und Warnungen vor dem Klima, das dies hervorbringt.',ARRAY['AMERICAS-USA'],ARRAY['threats','threat','threatened','climate','rhetoric','polarisation','polarization','attempts','second attempt','pattern','judiciary','judges','conspiracy','staged','fake','hoax','believe','survey','poll','investigates','why so many','tone deaf','divided','warns','complaint','motive','extremism','radicalised','Drohungen','Klima','Rhetorik','Spaltung','warnt','Attentate','amenazas','atentados'],true,ARRAY['Reuters','Associated Press','AFP','BBC World','BBC','Al Jazeera','Deutsche Welle','France 24 (EN)','France 24','Euronews','Straits Times','Channel NewsAsia','NDTV','Times of India','Indian Express','Hindustan Times','Globe and Mail','News24','Sky News','WION','Anadolu Agency','Dawn','CBC','ABC News','SMH.com.au','Philippine Daily Inquirer','NHK World','KBS World','Al Arabiya','i24NEWS','Jerusalem Post','Haaretz','Times of Israel','El País','Le Monde','Le Figaro','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Corriere della Sera','La Repubblica','Tagesschau','Der Standard','Die Presse','Kurier','Handelsblatt','Neue Zürcher Zeitung','Swissinfo','iROZHLAS','ERR News','The Telegraph','CNN','New York Times','Washington Post','NPR','The Guardian','MSNBC','El País','Le Monde','Le Figaro','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Corriere della Sera','La Repubblica','Tagesschau','Der Standard','Die Presse','Kurier','Handelsblatt','Neue Zürcher Zeitung','Swissinfo','iROZHLAS','ERR News','The Telegraph'],'us_political_violence',2,'Climate of violence','Klima der Gewalt', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('usdom_violence_instability','A superpower unable to secure its own political life','Eine Supermacht, die ihr eigenes politisches Leben nicht sichern kann','Russian, Chinese and Iranian state coverage using shootings and plots around American political events as evidence of internal disorder, and to question the stability of a state that presents itself as a model of governance to others.','Russische, chinesische und iranische Staatsmedien nutzen Schüsse und Anschlagspläne rund um amerikanische politische Ereignisse als Beleg innerer Unordnung und stellen die Stabilität eines Staates infrage, der sich anderen als Vorbild guter Regierungsführung präsentiert.',ARRAY['AMERICAS-USA'],ARRAY['hypocrisy','double standard','decline','decay','crisis of democracy','so-called democracy','impunity','elite','Heuchelei','Doppelmoral','Niedergang','hipocresía','declive'],true,ARRAY['RT','TASS','TASS (EN)','Sputnik','CGTN','Global Times','China Daily','People''s Daily','Xinhua','Press TV','Tehran Times','IRNA'],'us_political_violence',3,'Internal disorder','Innere Unordnung', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('usdom_press_accountability','Broadcasters are being held to obligations that come with a licence','Rundfunkanstalten werden an Pflichten gemessen, die mit einer Lizenz einhergehen','Coverage framing regulatory action against networks as enforcement of existing public-interest and equal-time obligations rather than retaliation, and treating publicly funded broadcasting as a legitimate subject of political decision about who taxpayers should fund.','Berichterstattung, die regulatorisches Vorgehen gegen Sender als Durchsetzung bestehender Pflichten zu Gemeinwohl und Gleichbehandlung darstellt statt als Vergeltung, und öffentlich finanzierten Rundfunk als legitimen Gegenstand politischer Entscheidung behandelt.',ARRAY['AMERICAS-USA'],'{}',true,ARRAY['Fox News','New York Post','Washington Times','Newsmax'],'us_press_freedom',1,'Regulatory accountability','Regulatorische Rechenschaft',1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('usdom_press_suppression','State leverage is being used against critical coverage','Staatliche Hebel werden gegen kritische Berichterstattung eingesetzt','Coverage of licence reviews opened after a broadcast joke, funding for public media cut and restored by a court on First Amendment grounds, restricted Pentagon press access reimposed after a loss in court, defamation suits against news organisations, and press-freedom monitors warning about the pattern.','Berichterstattung über Lizenzprüfungen nach einem Witz im Programm, gekürzte und von einem Gericht unter Berufung auf den Ersten Verfassungszusatz wiederhergestellte Mittel für öffentliche Medien, nach einer Niederlage vor Gericht erneut eingeschränkten Zugang zum Pentagon, Verleumdungsklagen gegen Nachrichtenorganisationen und warnende Beobachter der Pressefreiheit.',ARRAY['AMERICAS-USA'],'{}',true,ARRAY['Reuters','Associated Press','AFP','BBC World','BBC','Al Jazeera','Deutsche Welle','France 24 (EN)','France 24','Euronews','Straits Times','Channel NewsAsia','NDTV','Times of India','Indian Express','Hindustan Times','Globe and Mail','News24','Sky News','WION','Anadolu Agency','Dawn','CBC','ABC News','SMH.com.au','Philippine Daily Inquirer','NHK World','KBS World','Al Arabiya','i24NEWS','Jerusalem Post','Haaretz','Times of Israel','El País','Le Monde','Le Figaro','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Corriere della Sera','La Repubblica','Tagesschau','Der Standard','Die Presse','Kurier','Handelsblatt','Neue Zürcher Zeitung','Swissinfo','iROZHLAS','ERR News','The Telegraph','CNN','New York Times','Washington Post','NPR','The Guardian','MSNBC','Reuters','Associated Press','AFP','BBC World','BBC','Al Jazeera','Deutsche Welle','France 24 (EN)','France 24','Euronews','Straits Times','Channel NewsAsia','NDTV','Times of India','Indian Express','Hindustan Times','Globe and Mail','News24','Sky News','WION','Anadolu Agency','Dawn','CBC','ABC News','SMH.com.au','Philippine Daily Inquirer','NHK World','KBS World','Al Arabiya','i24NEWS','Jerusalem Post','Haaretz','Times of Israel','El País','Le Monde','Le Figaro','Der Spiegel','Süddeutsche Zeitung','Frankfurter Allgemeine','Die Zeit','Corriere della Sera','La Repubblica','Tagesschau','Der Standard','Die Presse','Kurier','Handelsblatt','Neue Zürcher Zeitung','Swissinfo','iROZHLAS','ERR News','The Telegraph'],'us_press_freedom',2,'Pressure on the press','Druck auf die Presse', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('usdom_press_hypocrisy','Press-freedom advocacy abroad, licence pressure at home','Eintreten für Pressefreiheit im Ausland, Lizenzdruck im Inland','Russian, Chinese and Iranian state coverage contrasting American criticism of media restrictions elsewhere with regulatory pressure on its own broadcasters, used to reject the premise that the US speaks for press freedom internationally.','Russische, chinesische und iranische Staatsmedien stellen amerikanische Kritik an Medienbeschränkungen andernorts dem regulatorischen Druck auf eigene Sender gegenüber, um die Prämisse zurückzuweisen, die USA sprächen international für die Pressefreiheit.',ARRAY['AMERICAS-USA'],ARRAY['hypocrisy','double standard','decline','decay','crisis of democracy','so-called democracy','impunity','elite','Heuchelei','Doppelmoral','Niedergang','hipocresía','declive'],true,ARRAY['RT','TASS','TASS (EN)','Sputnik','CGTN','Global Times','China Daily','People''s Daily','Xinhua','Press TV','Tehran Times','IRNA'],'us_press_freedom',3,'Double standard on press freedom','Doppelmoral bei der Pressefreiheit', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('us_russia_new_treaty_needed','The expiry of New START is dangerous and a successor framework must be built','Das Auslaufen von New START ist gefährlich, ein Nachfolgerahmen muss geschaffen werden','Western mainstream and arms-control coverage treating the February 2026 lapse of the last US-Russia warhead limits as a genuine loss — the end of inspections and data exchange, the removal of predictability — and reporting proposals for a replacement pact as a necessary corrective rather than a concession. Vocabulary: expires, grave moment, unconstrained, predictability, verification, new pact, guardrails.','Westliche Leitmedien und Rüstungskontroll-Berichterstattung behandeln das Auslaufen der letzten US-russischen Sprengkopfobergrenzen im Februar 2026 als echten Verlust — das Ende von Inspektionen und Datenaustausch, den Wegfall von Berechenbarkeit — und berichten über Vorschläge für einen Nachfolgevertrag als notwendige Korrektur, nicht als Zugeständnis. Vokabular: läuft aus, Verifikation, Berechenbarkeit, Leitplanken.',ARRAY['AMERICAS-USA','EUROPE-RUSSIA'],ARRAY['arms race','looms','clock ticks','uncharted','grave moment','expires','expiry','expire','lapse','no more nuclear limits','no nuclear limits','without nuclear limits','unconstrained','unchecked','end of','ends decades','last remaining','last Russia-US','raises fears','fears of','warns','urges','negotiate new','new nuclear','close in on deal','extension','predictability','verification','guardrails','opening door','ausgelaufen','beendet','Obergrenzen','Abrüstungsvertrag','läuft aus','warnt','Wettrüsten','désarmement','proroga','scadenza'],true,ARRAY['Reuters','Bloomberg','Bloomberg.com','Financial Times','Wall Street Journal','New York Times','The New York Times','Washington Post','CNN','BBC World','The Guardian','Associated Press','NPR','Deutsche Welle','The Telegraph','Euronews','Corriere della Sera','La Repubblica','France 24 (EN)','France 24','Tagesschau','Frankfurter Allgemeine','Globe and Mail','ABC News','MSNBC','Die Zeit','Der Spiegel','Süddeutsche Zeitung','Handelsblatt','The Economist','Sky News','El País','Der Standard','Die Presse','Defense News','Atlantic Council','Council on Foreign Relations','CSIS','Brookings','Carnegie Endowment','Chatham House','Japan Times','Straits Times','Channel NewsAsia','Nikkei Asia','Jerusalem Post','Times of Israel','Bangkok Post','Kyodo News','NHK World','Al Jazeera','France 24','Novinite','Yonhap','KBS World'],'us_russia_arms_control',1,'A successor treaty is needed','Ein Nachfolgevertrag ist nötig',1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('us_russia_treaty_constrains_only_us','A new treaty would bind Washington while Moscow modernises unchecked','Ein neuer Vertrag würde Washington binden, während Moskau ungehindert modernisiert','Western hawkish, defence-policy and Ukrainian coverage arguing that arms control has become one-sided: Russia has fielded novel systems outside any treaty''s scope, verification had already collapsed in practice, and a successor pact negotiated from weakness would constrain US modernisation and missile defence while legitimising Moscow. Same publisher bloc as the successor-treaty stance, so framing separates them. Vocabulary: cheating, outside the treaty, one-sided, from weakness, no verification, unenforceable, modernising.','Westliche sicherheitspolitisch-harte und ukrainische Berichterstattung argumentiert, Rüstungskontrolle sei einseitig geworden: Russland habe neuartige Systeme außerhalb jedes Vertragsrahmens aufgestellt, die Verifikation sei praktisch bereits zusammengebrochen, und ein aus einer Position der Schwäche ausgehandelter Nachfolgevertrag würde die US-Modernisierung und Raketenabwehr einschränken und Moskau legitimieren. Gleicher Publisher-Block, daher trennt das Framing. Vokabular: einseitig, aus Schwäche, keine Verifikation, Modernisierung.',ARRAY['AMERICAS-USA','EUROPE-RUSSIA','EUROPE-UKRAINE'],ARRAY['cheat','violat','outside the treaty','one-sided','from weakness','no verification','unenforceable','modernis','moderniz','buildup','build-up','rejects','no need','skeptic','sceptic','doubt','einseitig','Schwäche','Modernisierung','Zweifel'],false,ARRAY['Reuters','Bloomberg','Bloomberg.com','Financial Times','Wall Street Journal','New York Times','The New York Times','Washington Post','CNN','BBC World','The Guardian','Associated Press','NPR','Deutsche Welle','The Telegraph','Euronews','Corriere della Sera','La Repubblica','France 24 (EN)','France 24','Tagesschau','Frankfurter Allgemeine','Globe and Mail','ABC News','Fox News','Die Zeit','Der Spiegel','Süddeutsche Zeitung','Handelsblatt','The Economist','Sky News','Die Presse','Defense News','Atlantic Council','Council on Foreign Relations','CSIS','Brookings','Carnegie Endowment','Chatham House','Kyiv Post','Kyiv Independent','Ukrinform'],'us_russia_arms_control',2,'Arms control has become one-sided','Rüstungskontrolle ist einseitig geworden', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('us_russia_us_buildup_drives_race','US missile defence and rejected proposals are what drive the new arms race','US-Raketenabwehr und zurückgewiesene Vorschläge treiben das neue Wettrüsten an','Russian state coverage attributing the collapse of the strategic framework to Washington: post-New START proposals were rejected, the Golden Dome missile-defence programme undermines mutual vulnerability, and Moscow presents itself as willing to observe limits if the US does the same. Novel Russian systems are framed as responses to that programme rather than as its cause. Vocabulary: rejected our proposals, Golden Dome, destabilising, will not exceed if, ready for dialogue, blames US.','Russische staatliche Berichterstattung schreibt den Zusammenbruch des strategischen Rahmens Washington zu: Vorschläge nach New START seien zurückgewiesen worden, das Raketenabwehrprogramm Golden Dome untergrabe die gegenseitige Verwundbarkeit, und Moskau stelle sich als bereit dar, Obergrenzen einzuhalten, wenn die USA dies auch täten. Neue russische Systeme gelten als Antwort auf dieses Programm. Vokabular: zurückgewiesen, destabilisierend, gesprächsbereit.',ARRAY['EUROPE-RUSSIA','AMERICAS-USA'],ARRAY['rejected','Golden Dome','destabilis','destabiliz','will not exceed','ready for','dialogue','blames','provocation','undermines','takes note','условие','отверг','готов','дестабилиз'],true,ARRAY['TASS (EN)','TASS','tass.ru','RT','RIA Novosti','Lenta.ru','Gazeta.ru','Kommersant','Izvestia','Sputnik','BelTA Russian','Rossiyskaya Gazeta','Interfax'],'us_russia_arms_control',3,'Washington drives the arms race','Washington treibt das Wettrüsten',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('us_russia_engagement_necessary','Keeping a working channel with Moscow is how wars are ended and accidents avoided','Ein funktionierender Gesprächskanal mit Moskau beendet Kriege und verhindert Zwischenfälle','Western mainstream coverage treating the restored contacts -- envoy trips, the resumed high-level military channel, foreign-minister phone calls -- as the ordinary machinery of great-power management: without it there is no route to a settlement, no deconfliction, and no arms-control conversation. This position is held widely but stated rarely: Western outlets overwhelmingly present these contacts as Ukraine-war developments, so the argument for engagement is usually implicit in war reporting rather than made as bilateral commentary. The card is small by construction, not for want of coverage. Vocabulary: channel, deconfliction, constructive, re-establish, working toward, only route.','Westliche Leitmedien behandeln die wiederhergestellten Kontakte -- Reisen von Sondergesandten, der wieder aufgenommene militärische Kanal auf hoher Ebene, Telefonate der Außenminister -- als das gewöhnliche Instrumentarium des Großmächtemanagements: Ohne ihn gibt es keinen Weg zu einer Regelung, keine Deeskalation und kein Gespräch über Rüstungskontrolle. Diese Position wird breit geteilt, aber selten ausgesprochen: Westliche Medien stellen diese Kontakte überwiegend als Entwicklungen des Ukrainekriegs dar, sodass das Argument für Gespräche meist implizit in der Kriegsberichterstattung steckt statt als bilateraler Kommentar formuliert zu werden. Die Karte ist strukturbedingt klein, nicht mangels Berichterstattung. Vokabular: Kanal, Deeskalation, konstruktiv, Wiederaufnahme.',ARRAY['AMERICAS-USA','EUROPE-RUSSIA'],ARRAY['re-establish','reestablish','resume','resumed','high-level','military contacts','military talks','channel','not frozen','bilateral ties','restore','constructive','working toward','deconflict','only route','pragmatic','breakthrough','thaw','ice breaks','engage','Kanal','Wiederaufnahme','konstruktiv','Annäherung'],true,ARRAY['Reuters','Bloomberg','Bloomberg.com','Financial Times','Wall Street Journal','New York Times','The New York Times','Washington Post','CNN','BBC World','The Guardian','Associated Press','NPR','Deutsche Welle','The Telegraph','Euronews','Corriere della Sera','La Repubblica','France 24 (EN)','France 24','Tagesschau','Frankfurter Allgemeine','Globe and Mail','ABC News','MSNBC','Fox News','Die Zeit','Der Spiegel','Süddeutsche Zeitung','Handelsblatt','The Economist','Sky News','El País','Der Standard','Die Presse','Kurier','EurActiv','Straits Times','Channel NewsAsia','Nikkei Asia','Japan Times','Jerusalem Post','Times of Israel','Globe and Mail','Al Jazeera','France 24','Kyodo News','NHK World','Bangkok Post','Novinite'],'us_russia_bilateral_channel',1,'Engagement is necessary','Gespräche sind notwendig',1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('us_russia_normalisation_premature','Normalising relations while the war continues legitimises the Kremlin and sidelines Europe','Eine Normalisierung während des andauernden Krieges legitimiert den Kreml und stellt Europa ins Abseits','Western mainstream, transatlantic-critical and Ukrainian coverage arguing that summitry and warm bilateral atmospherics -- congratulation calls, G20 invitations, talk of joint investment projects -- grant Moscow the status of an equal partner it has not earned, and that decisions about European security are being taken over Europe''s and Kyiv''s heads. As with the engagement stance, this objection is mostly voiced inside Ukraine-war coverage rather than as commentary on the bilateral relationship, which is why it registers here at a fraction of the volume the Kremlin''s own account of that relationship achieves. Same publisher bloc as the engagement stance, so framing separates them. Vocabulary: legitimise, over their heads, sidelined, without Europe, premature, rehabilitation, fatal mistake.','Westliche Leitmedien, transatlantisch-kritische und ukrainische Berichterstattung argumentieren, Gipfeltreffen und freundliche bilaterale Atmosphäre -- Gratulationsanrufe, G20-Einladungen, Gerede über gemeinsame Investitionsprojekte -- verliehen Moskau einen nicht verdienten Status als gleichwertiger Partner, und Entscheidungen über die europäische Sicherheit fielen über die Köpfe Europas und Kyjiws hinweg. Wie bei der Engagement-Position wird dieser Einwand überwiegend innerhalb der Ukraine-Kriegsberichterstattung erhoben und nicht als Kommentar zum bilateralen Verhältnis -- daher erscheint er hier nur mit einem Bruchteil des Volumens, das die Kreml-Darstellung dieses Verhältnisses erreicht. Gleicher Publisher-Block wie die Engagement-Position, daher trennt das Framing. Vokabular: legitimieren, ins Abseits, verfrüht, Rehabilitierung.',ARRAY['AMERICAS-USA','EUROPE-RUSSIA','EUROPE-UKRAINE','NON-STATE-EU'],ARRAY['legitimis','legitimiz','over their heads','sidelined','without Europe','excluded','premature','rehabilitat','fatal mistake','rewards','patience wears thin','wears thin','not invited','no invitation','rejects Europe','lost mediator','lost standing','doubt','concession','piles pressure','pressure on Kyiv','weak','stalled','stalling','legitimieren','Abseits','verfrüht','ohne Europa','Zugeständnis','Druck auf'],true,ARRAY['Reuters','Bloomberg','Bloomberg.com','Financial Times','Wall Street Journal','New York Times','The New York Times','Washington Post','CNN','BBC World','The Guardian','Associated Press','NPR','Deutsche Welle','The Telegraph','Euronews','Corriere della Sera','La Repubblica','France 24 (EN)','France 24','Tagesschau','Frankfurter Allgemeine','Globe and Mail','ABC News','MSNBC','Fox News','Die Zeit','Der Spiegel','Süddeutsche Zeitung','Handelsblatt','The Economist','Sky News','El País','Der Standard','Die Presse','Kurier','EurActiv','Atlantic Council','Council on Foreign Relations','CSIS','Brookings','Carnegie Endowment','Chatham House','Kyiv Post','Kyiv Independent','Ukrinform'],'us_russia_bilateral_channel',2,'Normalisation is premature','Normalisierung ist verfrüht', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('us_russia_washington_realism','Washington is returning to realism and accepting a multipolar order','Washington kehrt zum Realismus zurück und akzeptiert eine multipolare Ordnung','Russian state coverage presenting the restored channel as overdue recognition that Russia cannot be isolated: the previous freeze is over, contacts are being rebuilt on a basis of equality, and Washington must respect Russian interests for cooperation to be mutually beneficial. Because Russian state media treat the bilateral relationship as a standing subject rather than an adjunct of the war, this framing is asserted directly and continuously, giving it far more standalone volume than any Western counter-position achieves. Vocabulary: multipolar, equality, respect our interests, not frozen, mutually beneficial.','Russische staatliche Berichterstattung stellt den wiederhergestellten Kanal als überfällige Anerkennung dar, dass Russland nicht isoliert werden kann: Das frühere Einfrieren sei vorbei, Kontakte würden auf Grundlage der Gleichberechtigung wiederaufgebaut, und Washington müsse russische Interessen respektieren, damit die Zusammenarbeit beiderseits nützlich sei. Da russische Staatsmedien das bilaterale Verhältnis als dauerhaften Gegenstand behandeln und nicht als Anhängsel des Krieges, wird diese Rahmung unmittelbar und fortlaufend behauptet -- mit weit größerem eigenständigem Volumen als jede westliche Gegenposition erreicht. Vokabular: multipolar, Gleichberechtigung, Respekt, gegenseitiger Nutzen.',ARRAY['EUROPE-RUSSIA','AMERICAS-USA'],ARRAY['ready to work','ready for','not frozen','positively','constructive','positive','mutually beneficial','multipolar','equality','equal footing','respect','interests','future economic ties','economic ties','investors','participation','lend them an ear','congratulat','thanks','agreements in Alaska','Alaska','re-establish','reestablish','resume','restore','high-level','military contacts','conversation','signals','готов','взаимовыгодн','многополярн','равноправ','конструктивн','возобновл','контакт'],true,ARRAY['TASS (EN)','TASS','tass.ru','RT','RIA Novosti','Lenta.ru','Gazeta.ru','Kommersant','Izvestia','Sputnik','BelTA Russian','Rossiyskaya Gazeta','Interfax'],'us_russia_bilateral_channel',3,'Washington is becoming realistic','Washington wird realistisch',2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('us_russia_washington_bad_faith','Washington talks while acting in bad faith and refusing to treat Russia as an equal','Washington verhandelt, handelt dabei aber unaufrichtig und verweigert Russland den Status eines Gleichberechtigten','Russian state coverage in its adversarial register: the channel exists but Washington stalls, issues ultimatums, drifts from the mediator role it claimed, presses Europe to carry the cost of containment, and pursues Russian companies commercially while talking cooperation. US policy is presented as unchanged in substance regardless of administration. Vocabulary: ultimatums, stalling, disingenuous, double standards, at war with Russia, unchanged, drifting, piracy, pushes out.','Russische staatliche Berichterstattung im konfrontativen Register: Der Kanal besteht, doch Washington hinhaltet, stellt Ultimaten, entfernt sich von der beanspruchten Vermittlerrolle, drängt Europa, die Kosten der Eindämmung zu tragen, und verfolgt russische Unternehmen kommerziell, während es von Zusammenarbeit spricht. Die US-Politik gelte inhaltlich als unverändert, unabhängig von der Regierung. Vokabular: Ultimaten, Hinhalten, Doppelstandards, unverändert.',ARRAY['EUROPE-RUSSIA','AMERICAS-USA'],ARRAY['ultimatum','stalling','stalled','stagnant','disingenuous','hypocri','double standard','at war with','drifting','objective mediator','not fit','legal framework','piracy','provocation','blame','accuses','accus','criticiz','criticis','slams','condemn','unchanged','bear the cost','push','out of global business','energy grab','interference','ультиматум','лицемер','двойны','обвин','критику','неизменн','провокац'],true,ARRAY['TASS (EN)','TASS','tass.ru','RT','RIA Novosti','Lenta.ru','Gazeta.ru','Kommersant','Izvestia','Sputnik','BelTA Russian','Rossiyskaya Gazeta','Interfax'],'us_russia_bilateral_channel',4,'Washington acts in bad faith','Washington handelt unaufrichtig', -2,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('us_russia_relief_pragmatic','Sanctions relief is a pragmatic response to energy-market reality','Sanktionslockerung ist eine pragmatische Reaktion auf die Lage am Energiemarkt','Western mainstream and business coverage arguing that waivers on Russian crude were forced by supply conditions — the Iran war, stranded cargoes, refiners and importers such as India needing barrels — and that keeping oil flowing while retaining the legal architecture of sanctions is the responsible course. Vocabulary: market stability, supply, waiver, temporary, stranded at sea, short-term step.','Westliche Leit- und Wirtschaftsmedien argumentieren, Ausnahmegenehmigungen für russisches Rohöl seien durch die Versorgungslage erzwungen worden — der Iran-Krieg, festsitzende Ladungen, Raffinerien und Importeure wie Indien, die Barrel benötigen — und es sei verantwortungsvoll, das Öl fließen zu lassen und zugleich das rechtliche Sanktionsgerüst zu erhalten. Vokabular: Marktstabilität, Versorgung, Ausnahmegenehmigung, vorübergehend.',ARRAY['AMERICAS-USA','EUROPE-RUSSIA'],ARRAY['market stability','supply','energy prices','easing energy','eases energy','take a little pressure off','pressure off','back on market','weighs easing','temporary','short-term','stranded at sea','stranded','crunches supplies','vulnerable countries','ride out','avert','gambled','keeps','lifeline','Marktstabilität','vorübergehend','Versorgung','Ölpreis'],true,ARRAY['Reuters','Bloomberg','Bloomberg.com','Financial Times','Wall Street Journal','New York Times','The New York Times','Washington Post','CNN','BBC World','The Guardian','Associated Press','NPR','Deutsche Welle','The Telegraph','Euronews','Corriere della Sera','La Repubblica','France 24 (EN)','France 24','Tagesschau','Frankfurter Allgemeine','Globe and Mail','ABC News','MSNBC','Fox News','Die Zeit','Der Spiegel','Süddeutsche Zeitung','Handelsblatt','The Economist','Sky News','El País','Der Standard','Die Presse','Kurier','EurActiv','OilPrice','S&P Global','Straits Times','Channel NewsAsia','Nikkei Asia','Japan Times','Jerusalem Post','Times of Israel','Globe and Mail','Al Jazeera','France 24','Novinite','Kyodo News','NHK World','Bangkok Post'],'us_russia_sanctions_leverage',1,'Relief is pragmatic','Lockerung ist pragmatisch',1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('us_russia_relief_rewards_moscow','Easing sanctions hands Moscow a windfall and squanders the West''s main lever','Die Lockerung der Sanktionen verschafft Moskau unerwartete Einnahmen und verspielt den wichtigsten Hebel des Westens','Western mainstream, transatlantic-critical and Ukrainian coverage arguing that the waivers transfer billions to the Russian budget while the war continues, that they were granted without reciprocal concessions, and that they split the US from European and British partners still tightening enforcement. Same publisher bloc as the pragmatic stance, so framing separates them. Vocabulary: gift to Putin, coup for Putin, windfall, U-turn, splits with, clash over, rewards.','Westliche Leitmedien, transatlantisch-kritische und ukrainische Berichterstattung argumentieren, die Ausnahmen überwiesen Milliarden an den russischen Haushalt, während der Krieg weitergeht, sie seien ohne Gegenleistung gewährt worden und trennten die USA von europäischen und britischen Partnern, die die Durchsetzung weiter verschärfen. Gleicher Publisher-Block wie die pragmatische Position, daher trennt das Framing. Vokabular: Geschenk an Putin, Kehrtwende, Bruch mit.',ARRAY['AMERICAS-USA','EUROPE-RUSSIA','EUROPE-UKRAINE'],ARRAY['gift to Putin','coup for Putin','windfall','U-turn','U-Turn','rewards','defy Trump','sanctions bill','unblock','splits with','clash over','self-defeating','hand Moscow','give Moscow','emboldens','without concessions','no concessions','squander','critics','senators','despite','blockade','pay off','fails to','won''t withstand','lost standing','Geschenk','Kehrtwende','belohnt','Kritik'],true,ARRAY['Reuters','Bloomberg','Bloomberg.com','Financial Times','Wall Street Journal','New York Times','The New York Times','Washington Post','CNN','BBC World','The Guardian','Associated Press','NPR','Deutsche Welle','The Telegraph','Euronews','Corriere della Sera','La Repubblica','France 24 (EN)','France 24','Tagesschau','Frankfurter Allgemeine','Globe and Mail','ABC News','MSNBC','Fox News','Die Zeit','Der Spiegel','Süddeutsche Zeitung','Handelsblatt','The Economist','Sky News','El País','Der Standard','Die Presse','Kurier','EurActiv','Atlantic Council','Council on Foreign Relations','CSIS','Brookings','Carnegie Endowment','Chatham House','Kyiv Post','Kyiv Independent','Ukrinform'],'us_russia_sanctions_leverage',2,'Relief rewards Moscow','Lockerung belohnt Moskau', -1,true)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('us_russia_sanctions_illegitimate','Unilateral sanctions have failed and Washington has been forced to admit it','Einseitige Sanktionen sind gescheitert, und Washington musste dies eingestehen','Russian state coverage framing the waivers as proof that restrictions on Russian energy were always unworkable: the world market needs Russian barrels, buyers keep buying, and the US has quietly conceded the point while continuing to demand that Europe bear the cost of containment. Sanctions are cast as illegitimate extraterritorial coercion rather than lawful policy. Vocabulary: de-facto admitted, crucial for market, illegal, unilateral, pressure has failed, respect our interests.','Russische staatliche Berichterstattung stellt die Ausnahmen als Beweis dar, dass Beschränkungen für russische Energie nie funktionierten: Der Weltmarkt brauche russische Barrel, Käufer kauften weiter, und die USA hätten dies stillschweigend eingeräumt, während sie weiter verlangten, dass Europa die Kosten der Eindämmung trage. Sanktionen gelten als illegitimer extraterritorialer Zwang. Vokabular: faktisch eingeräumt, unverzichtbar, illegal, einseitig, gescheitert.',ARRAY['EUROPE-RUSSIA','AMERICAS-USA'],ARRAY['de-facto admitted','crucial for','market needs','illegal','illegitimate','unilateral','failed','respect','interests','forced to','climb down','extraterritorial','bear the cost','ослабление санкций','незаконн','односторонн','провал'],true,ARRAY['TASS (EN)','TASS','tass.ru','RT','RIA Novosti','Lenta.ru','Gazeta.ru','Kommersant','Izvestia','Sputnik','BelTA Russian','Rossiyskaya Gazeta','Interfax'],'us_russia_sanctions_leverage',3,'Sanctions were always unworkable','Sanktionen waren nie tragfähig',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('us_russia_buyer_autonomy','Sovereign buyers never accepted that US permission was required','Souveräne Käufer haben nie akzeptiert, dass eine US-Erlaubnis nötig wäre','Indian, Turkish and wider Global South coverage treating the waivers less as American generosity than as confirmation that the restrictions were unenforceable: purchases continued through every phase, energy security is a sovereign decision, and Washington relaxes or tightens the rules according to its own needs. Vocabulary: never depended on permission, when it suits them, energy security, sovereign choice, lifeline, will continue buying.','Indische, türkische und breitere Berichterstattung des Globalen Südens behandelt die Ausnahmegenehmigungen weniger als amerikanische Großzügigkeit denn als Bestätigung, dass die Beschränkungen nicht durchsetzbar waren: Die Käufe liefen in jeder Phase weiter, Energiesicherheit sei eine souveräne Entscheidung, und Washington lockere oder verschärfe die Regeln nach eigenem Bedarf. Vokabular: nie auf Erlaubnis angewiesen, Energiesicherheit, souveräne Entscheidung.',ARRAY['AMERICAS-USA','EUROPE-RUSSIA','ASIA-INDIA'],ARRAY['never depended','permission','suits them','mind his business','sovereign','energy security','will continue','continue buying','keep buying','regardless','lifeline','discount','national interest','our own','refiners','Reliance','crude imports','surge'],true,ARRAY['NDTV','Times of India','Hindustan Times','The Hindu','Indian Express','WION','Republic TV','Business Standard','Mint','Economic Times','Firstpost','Dawn','Anadolu Agency','TRT World','Daily Sabah','Al Arabiya','Al-Ahram','The News','Press TV'],'us_russia_sanctions_leverage',4,'Buying is a sovereign choice','Kaufen ist eine souveräne Entscheidung',1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('us_russia_theater_engagement_case','Managed engagement is the responsible way to handle a nuclear-armed adversary','Gesteuerter Dialog ist der verantwortungsvolle Umgang mit einem nuklear bewaffneten Gegner','The cross-cutting Western argument that the reopened channel, the energy waivers and the search for a successor arms-control framework are all instances of the same pragmatism: pressure alone did not end the war, isolation forecloses the settlement, and a nuclear peer has to be managed rather than merely punished.','Das übergreifende westliche Argument, dass der wiedereröffnete Gesprächskanal, die Energie-Ausnahmen und die Suche nach einem Nachfolgerahmen für die Rüstungskontrolle Ausdruck derselben Pragmatik sind: Druck allein hat den Krieg nicht beendet, Isolation verbaut die Regelung, und ein nuklearer Ebenbürtiger muss gesteuert und nicht nur bestraft werden.',ARRAY['AMERICAS-USA','EUROPE-RUSSIA'],ARRAY['channel','pragmatic','market stability','re-establish','new pact','predictability','settlement','Kanal','pragmatisch','Berechenbarkeit'],true,ARRAY['Reuters','Bloomberg','Bloomberg.com','Financial Times','Wall Street Journal','New York Times','The New York Times','Washington Post','CNN','BBC World','The Guardian','Associated Press','NPR','Deutsche Welle','The Telegraph','Euronews','Corriere della Sera','La Repubblica','France 24 (EN)','France 24','Tagesschau','Frankfurter Allgemeine','Globe and Mail','ABC News','MSNBC','Fox News','Die Zeit','Der Spiegel','Süddeutsche Zeitung','Handelsblatt','The Economist','Sky News','El País','Der Standard','Die Presse','Kurier','EurActiv','OilPrice','S&P Global','Straits Times','Channel NewsAsia','Nikkei Asia','Defense News','Atlantic Council','Council on Foreign Relations','CSIS','Brookings','Carnegie Endowment','Chatham House','Japan Times','Straits Times','Channel NewsAsia','Nikkei Asia','Jerusalem Post','Times of Israel','Bangkok Post','Kyodo News','NHK World','Al Jazeera','France 24','Novinite','Yonhap','KBS World','Globe and Mail'],'us_russia_theater',1,'Managed engagement','Gesteuerter Dialog',1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('us_russia_theater_kremlin_vindication','The West''s containment strategy has failed and Russia is being dealt with as an equal','Die Eindämmungsstrategie des Westens ist gescheitert, Russland wird als gleichwertig behandelt','The cross-cutting Russian state framing that each strand of the relationship confirms the same conclusion: sanctions could not be sustained, isolation collapsed, and Washington is negotiating on a basis of equality it long denied. Responsibility for remaining friction — stalled talks, the lapsed treaty — is placed on US inconsistency.','Der übergreifende russische Staatsrahmen, wonach jeder Strang der Beziehung dieselbe Schlussfolgerung bestätigt: Sanktionen waren nicht durchzuhalten, die Isolation brach zusammen, und Washington verhandelt auf einer Grundlage der Gleichberechtigung, die es lange verweigert hat. Die Verantwortung für verbleibende Reibung wird der US-Inkonsequenz zugeschrieben.',ARRAY['EUROPE-RUSSIA','AMERICAS-USA'],ARRAY['equality','multipolar','failed','respect','interests','de-facto admitted','rejected','многополярн','равноправ','провал'],true,ARRAY['TASS (EN)','TASS','tass.ru','RT','RIA Novosti','Lenta.ru','Gazeta.ru','Kommersant','Izvestia','Sputnik','BelTA Russian','Rossiyskaya Gazeta','Interfax'],'us_russia_theater',2,'Containment has failed','Eindämmung ist gescheitert',2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('us_russia_theater_western_alarm','Accommodation is being granted without reciprocity, over the heads of Europe and Kyiv','Entgegenkommen wird ohne Gegenleistung gewährt — über die Köpfe Europas und Kyjiws hinweg','The cross-cutting Western-critical and Ukrainian argument that sanctions relief, summit atmospherics and a weakened arms-control position form one pattern of unreciprocated concession: Moscow gains revenue, status and strategic room while the war continues, and the allies who bear the security consequences are not at the table.','Das übergreifende westlich-kritische und ukrainische Argument, dass Sanktionslockerung, Gipfelatmosphäre und eine geschwächte rüstungskontrollpolitische Position ein einziges Muster einseitiger Zugeständnisse bilden: Moskau gewinnt Einnahmen, Status und strategischen Spielraum, während der Krieg weitergeht — und die Verbündeten, die die Sicherheitsfolgen tragen, sitzen nicht mit am Tisch.',ARRAY['AMERICAS-USA','EUROPE-RUSSIA','EUROPE-UKRAINE','NON-STATE-EU'],ARRAY['gift to Putin','windfall','sidelined','over their heads','without Europe','premature','one-sided','rewards','U-turn','legitimis','Geschenk','Abseits','einseitig','verfrüht'],true,ARRAY['Reuters','Bloomberg','Bloomberg.com','Financial Times','Wall Street Journal','New York Times','The New York Times','Washington Post','CNN','BBC World','The Guardian','Associated Press','NPR','Deutsche Welle','The Telegraph','Euronews','Corriere della Sera','La Repubblica','France 24 (EN)','France 24','Tagesschau','Frankfurter Allgemeine','Globe and Mail','ABC News','MSNBC','Fox News','Die Zeit','Der Spiegel','Süddeutsche Zeitung','Handelsblatt','The Economist','Sky News','El País','Der Standard','Die Presse','Kurier','EurActiv','Defense News','Atlantic Council','Council on Foreign Relations','CSIS','Brookings','Carnegie Endowment','Chatham House','Kyiv Post','Kyiv Independent','Ukrinform'],'us_russia_theater',3,'Concessions without reciprocity','Zugeständnisse ohne Gegenleistung', -1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('us_russia_theater_buyer_autonomy','Third countries treat the rivalry as something to navigate, not to join','Drittstaaten betrachten die Rivalität als etwas, das zu navigieren, nicht mitzutragen ist','The cross-cutting Global South framing that the US-Russia relationship is a set of conditions to be managed rather than a side to be chosen: energy purchases continue through every phase of pressure and relief, the rules are seen to move with Washington''s domestic needs, and sovereign interest rather than alignment governs the response.','Der übergreifende Rahmen des Globalen Südens, wonach das Verhältnis USA-Russland Rahmenbedingungen setzt, die zu bewältigen sind, statt eine Seite, für die man sich entscheidet: Energiekäufe laufen durch alle Phasen von Druck und Lockerung weiter, die Regeln folgen erkennbar innenpolitischen Bedürfnissen Washingtons, und souveränes Interesse statt Bündnistreue bestimmt die Reaktion.',ARRAY['AMERICAS-USA','EUROPE-RUSSIA','ASIA-INDIA'],ARRAY['never depended','permission','suits them','sovereign','energy security','continue buying','regardless','lifeline','national interest'],true,ARRAY['NDTV','Times of India','Hindustan Times','The Hindu','Indian Express','WION','Republic TV','Business Standard','Mint','Economic Times','Firstpost','Dawn','Anadolu Agency','TRT World','Daily Sabah','Al Arabiya','Al-Ahram','The News','Press TV'],'us_russia_theater',4,'Navigating, not choosing sides','Navigieren statt Seitenwahl',1,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();
INSERT INTO narratives_v2 (id,name_en,name_de,claim_en,claim_de,actor_centroids,framing_keywords,is_active,publishers,fn_id,display_order,stance_label_en,stance_label_de,stance,framing_required) VALUES ('us_russia_theater_kremlin_grievance','Washington cannot be trusted to keep its side of any bargain','Auf Washington ist bei keiner Vereinbarung Verlass','The cross-cutting Russian state framing that runs against its own optimistic register: whatever is agreed, the US stalls, attaches ultimatums, keeps squeezing Russian companies and shifts the burden of confrontation onto Europe. Engagement is worth pursuing, but American commitments are treated as provisional.','Der übergreifende russische Staatsrahmen, der seinem eigenen optimistischen Register widerspricht: Was auch vereinbart werde, die USA hinhielten, knüpften Ultimaten daran, setzten russische Unternehmen weiter unter Druck und verlagerten die Last der Konfrontation auf Europa. Gespräche lohnten sich, doch amerikanische Zusagen gälten als vorläufig.',ARRAY['EUROPE-RUSSIA','AMERICAS-USA'],ARRAY['ultimatum','stalling','stagnant','double standard','at war with','drifting','unchanged','bear the cost','accus','ультиматум','лицемер','обвин'],true,ARRAY['TASS (EN)','TASS','tass.ru','RT','RIA Novosti','Lenta.ru','Gazeta.ru','Kommersant','Izvestia','Sputnik','BelTA Russian','Rossiyskaya Gazeta','Interfax'],'us_russia_theater',5,'American commitments are provisional','Amerikanische Zusagen sind vorläufig', -2,false)
  ON CONFLICT (id) DO UPDATE SET name_en = EXCLUDED.name_en, name_de = EXCLUDED.name_de, claim_en = EXCLUDED.claim_en, claim_de = EXCLUDED.claim_de, actor_centroids = EXCLUDED.actor_centroids, framing_keywords = EXCLUDED.framing_keywords, is_active = EXCLUDED.is_active, publishers = EXCLUDED.publishers, fn_id = EXCLUDED.fn_id, display_order = EXCLUDED.display_order, stance_label_en = EXCLUDED.stance_label_en, stance_label_de = EXCLUDED.stance_label_de, stance = EXCLUDED.stance, framing_required = EXCLUDED.framing_required, updated_at = NOW();

